import { useState, useRef, useEffect, useCallback } from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { motion, AnimatePresence } from 'framer-motion';
import ReactMarkdown from 'react-markdown';
import { 
  Bot, 
  Sparkles,
  Trash2,
  Zap,
  TrendingUp,
  Users,
  AlertCircle,
  ArrowUp,
  TestTube,
  ShieldCheck
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { AdminStatsPanel, QuickStats } from './AdminStatsPanel';

interface Message {
  role: 'user' | 'assistant';
  content: string;
  actions?: Array<{ type: string; params: string }>;
  timestamp?: Date;
}

import { SUPABASE_URL } from '@/config';

// Typing indicator dots
const TypingIndicator = () => (
  <div className="flex items-center gap-1.5 px-4 py-3">
    {[0, 1, 2].map((i) => (
      <motion.div
        key={i}
        className="w-2 h-2 rounded-full bg-muted-foreground/60"
        animate={{
          y: [0, -6, 0],
          opacity: [0.4, 1, 0.4],
        }}
        transition={{
          duration: 0.8,
          repeat: Infinity,
          delay: i * 0.15,
          ease: "easeInOut",
        }}
      />
    ))}
  </div>
);

// Message component with markdown support
const ChatMessage = ({ 
  message, 
  onExecuteAction 
}: { 
  message: Message; 
  onExecuteAction: (action: { type: string; params: string }) => void;
}) => {
  const isUser = message.role === 'user';

  return (
    <div className={cn("flex", isUser ? "justify-end" : "justify-start")}>
      <div
        className={cn(
          "max-w-[85%] rounded-2xl px-4 py-3",
          isUser 
            ? "bg-foreground text-background" 
            : "bg-muted border border-border"
        )}
      >
        {isUser ? (
          <p className="text-sm leading-relaxed whitespace-pre-wrap">
            {message.content}
          </p>
        ) : (
          <div className="text-sm">
            <p className="text-sm leading-relaxed whitespace-pre-wrap">
              {message.content.replace(/\[ACTION:[^\]]*\]/g, '').trim()}
            </p>
          </div>
        )}

        {message.timestamp && (
          <p className={cn(
            "text-[10px] mt-1.5",
            isUser ? "text-background/60" : "text-muted-foreground"
          )}>
            {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
          </p>
        )}

        {message.actions && message.actions.length > 0 && (
          <div className="flex flex-wrap gap-1.5 mt-3 pt-3 border-t border-border/50">
            {message.actions.map((action, j) => (
              <Badge 
                key={j}
                variant="secondary" 
                className="cursor-pointer hover:bg-primary/10 hover:text-primary transition-colors"
                onClick={() => onExecuteAction(action)}
              >
                <Sparkles className="w-3 h-3 mr-1.5" />
                <span className="text-xs">{action.type.replace(/_/g, ' ')}</span>
              </Badge>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export function AdminAIAssistant() {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'assistant',
      content: "Hey! I'm your admin operations assistant. I can see system health, test results, rate limits, and more. Ask me anything about platform operations or click a stat to dive deeper.",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [stats, setStats] = useState<QuickStats | null>(null);
  const [isLoadingStats, setIsLoadingStats] = useState(true);
  const scrollRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Fetch stats on mount and periodically
  const fetchStats = useCallback(async () => {
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;

      // Quick ping to get stats from a simple message
      const response = await fetch(
        `${SUPABASE_URL}/functions/v1/admin-ai-assistant`,
        {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${session.access_token}`,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({ message: 'quick stats check' })
        }
      );

      if (response.ok) {
        const data = await response.json();
        if (data.quickStats) {
          setStats(data.quickStats);
        }
      }
    } catch (error) {
      console.error('Failed to fetch stats:', error);
    } finally {
      setIsLoadingStats(false);
    }
  }, []);

  useEffect(() => {
    fetchStats();
    // Refresh stats every 30 seconds
    const interval = setInterval(fetchStats, 30000);
    return () => clearInterval(interval);
  }, [fetchStats]);

  // Auto-scroll to bottom
  useEffect(() => {
    const scrollToBottom = () => {
      if (scrollRef.current) {
        const viewport = scrollRef.current.querySelector('[data-radix-scroll-area-viewport]');
        if (viewport) {
          viewport.scrollTop = viewport.scrollHeight;
        }
      }
    };
    scrollToBottom();
    const raf = requestAnimationFrame(scrollToBottom);
    const timeout = setTimeout(scrollToBottom, 150);
    return () => {
      cancelAnimationFrame(raf);
      clearTimeout(timeout);
    };
  }, [messages, isLoading]);

  const sendMessage = async (messageText?: string) => {
    const text = messageText || input.trim();
    if (!text || isLoading) return;

    setInput('');
    if (textareaRef.current) {
      textareaRef.current.style.height = '44px';
    }

    setMessages(prev => [...prev, { 
      role: 'user', 
      content: text,
      timestamp: new Date()
    }]);
    setIsLoading(true);

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        toast.error('Not authenticated');
        setIsLoading(false);
        return;
      }

      const response = await fetch(
        `${SUPABASE_URL}/functions/v1/admin-ai-assistant`,
        {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${session.access_token}`,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({ message: text })
        }
      );

      if (!response.ok) {
        throw new Error('Failed to get response');
      }

      const data = await response.json();

      // Update stats if returned
      if (data.quickStats) {
        setStats(data.quickStats);
      }

      setMessages(prev => [...prev, {
        role: 'assistant',
        content: data.content,
        actions: data.actions,
        timestamp: new Date()
      }]);
    } catch (error) {
      console.error('Admin AI error:', error);
      setMessages(prev => [...prev, {
        role: 'assistant',
        content: "Sorry, couldn't process that. Try again?",
        timestamp: new Date()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const executeAction = async (action: { type: string; params: string }) => {
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        toast.error('Not authenticated');
        return;
      }

      switch (action.type) {
        case 'unblock_user':
          const { error: unblockError } = await supabase.rpc('admin_unblock_user', { 
            p_user_id: action.params 
          });
          if (unblockError) throw unblockError;
          toast.success('User unblocked successfully');
          break;

        case 'run_tests':
          await fetch(`${SUPABASE_URL}/functions/v1/ai-comprehensive-tester`, {
            method: 'POST',
            headers: {
              'Authorization': `Bearer ${session.access_token}`,
              'Content-Type': 'application/json'
            },
            body: JSON.stringify({ suite: action.params })
          });
          toast.success(`Running ${action.params} tests...`);
          break;

        case 'refresh_stats':
          await fetchStats();
          toast.success('Stats refreshed');
          break;

        case 'view_section':
          window.dispatchEvent(new CustomEvent('admin-navigate', { 
            detail: action.params 
          }));
          break;

        default:
          toast.info(`Action: ${action.type}`);
      }

      // Refresh stats after action
      fetchStats();
    } catch (error) {
      console.error('Action failed:', error);
      toast.error(`Action failed: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }
  };

  const clearChat = () => {
    setMessages([{
      role: 'assistant',
      content: "Hey! I'm your admin operations assistant. I can see system health, test results, rate limits, and more. Ask me anything about platform operations or click a stat to dive deeper.",
      timestamp: new Date()
    }]);
  };

  const handleTextareaChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInput(e.target.value);
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = Math.max(44, Math.min(textareaRef.current.scrollHeight, 160)) + 'px';
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  // Dynamic quick suggestions based on stats
  const getQuickSuggestions = () => {
    const suggestions = [
      { icon: TrendingUp, text: "Show AI cost breakdown" },
      { icon: TestTube, text: "Show test results" },
    ];

    if (stats?.blockedUsers && stats.blockedUsers > 0) {
      suggestions.push({ 
        icon: Users, 
        text: `Unblock ${stats.blockedUsers} rate-limited users` 
      });
    }

    if (stats?.openTickets && stats.openTickets > 0) {
      suggestions.push({ 
        icon: AlertCircle, 
        text: `${stats.openTickets} open tickets - show details` 
      });
    }

    if (stats?.llmFallbackRate && stats.llmFallbackRate > 5) {
      suggestions.push({ 
        icon: Zap, 
        text: "Why is fallback rate high?" 
      });
    }

    suggestions.push({ icon: ShieldCheck, text: "Check security alerts" });

    return suggestions.slice(0, 6);
  };

  const quickSuggestions = getQuickSuggestions();

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-muted flex items-center justify-center">
            <Bot className="w-5 h-5 text-foreground" />
          </div>
          <div>
            <h2 className="text-lg font-semibold flex items-center gap-2">
              AYN Admin Assistant
              <Badge variant="secondary" className="text-[10px] font-normal">
                AYN
              </Badge>
            </h2>
            <p className="text-sm text-muted-foreground">
              System operations & insights
            </p>
          </div>
        </div>

        <Button 
          variant="ghost" 
          size="sm"
          onClick={clearChat}
          className="text-muted-foreground hover:text-foreground"
        >
          <Trash2 className="w-4 h-4 mr-2" />
          Clear
        </Button>
      </div>

      {/* Chat Card */}
      <Card className="border border-border bg-card overflow-hidden">
        {/* Stats Panel */}
        <AdminStatsPanel 
          stats={stats} 
          isLoading={isLoadingStats}
          onStatClick={sendMessage}
          onRefresh={fetchStats}
        />

        {/* Messages */}
        <CardContent className="p-0">
          <ScrollArea className="h-[350px]" ref={scrollRef}>
            <div className="p-4 space-y-4">
              {messages.map((msg, i) => (
                <ChatMessage 
                  key={i} 
                  message={msg} 
                  onExecuteAction={executeAction}
                />
              ))}

              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-muted border border-border rounded-2xl">
                    <TypingIndicator />
                  </div>
                </div>
              )}
            </div>
          </ScrollArea>

          {/* Quick Suggestions */}
          {messages.length <= 1 && !isLoading && (
            <div className="px-4 pb-4">
              <p className="text-xs text-muted-foreground mb-2">Quick actions:</p>
              <div className="flex flex-wrap gap-2">
                {quickSuggestions.map((suggestion, i) => (
                  <button
                    key={i}
                    onClick={() => sendMessage(suggestion.text)}
                    className="flex items-center gap-2 px-3 py-2 rounded-lg bg-muted border border-border hover:bg-muted/80 transition-colors text-sm"
                  >
                    <suggestion.icon className="w-3.5 h-3.5 text-muted-foreground" />
                    <span>{suggestion.text}</span>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Input Area */}
          <div className="p-3 border-t border-border">
            <div className="relative bg-muted/50 border border-border rounded-xl overflow-hidden">
              <div className="flex items-end gap-2 p-2">
                <Textarea
                  ref={textareaRef}
                  placeholder="Ask about system health, tests, rate limits..."
                  value={input}
                  onChange={handleTextareaChange}
                  onKeyDown={handleKeyPress}
                  disabled={isLoading}
                  className={cn(
                    "flex-1 resize-none min-h-[44px] max-h-[160px]",
                    "text-sm bg-transparent",
                    "border-0 focus-visible:ring-0 focus-visible:ring-offset-0",
                    "px-2 py-2"
                  )}
                />

                <AnimatePresence>
                  {input.trim() && !isLoading && (
                    <motion.button
                      initial={{ scale: 0, opacity: 0 }}
                      animate={{ scale: 1, opacity: 1 }}
                      exit={{ scale: 0, opacity: 0 }}
                      onClick={() => sendMessage()}
                      className="shrink-0 w-9 h-9 rounded-lg bg-foreground text-background flex items-center justify-center hover:opacity-90 transition-opacity"
                    >
                      <ArrowUp className="w-4 h-4" strokeWidth={2.5} />
                    </motion.button>
                  )}
                </AnimatePresence>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { motion } from 'framer-motion';
import { 
  Search, 
  Mail, 
  Calendar,
  ChevronRight,
  RefreshCw,
  Download,
  Inbox,
  Star,
  Trash2,
  CheckCircle
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

interface ContactMessage {
  id: string;
  name: string;
  email: string;
  message: string;
  status: string;
  created_at: string;
  updated_at: string;
}

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.05
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, y: 10 },
  visible: { 
    opacity: 1, 
    y: 0,
    transition: { duration: 0.2 }
  }
};

const ITEMS_PER_PAGE = 15;

const ContactMessagesView: React.FC = () => {
  const [messages, setMessages] = useState<ContactMessage[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => {
    fetchMessages();

    const channel = supabase
      .channel('contacts-realtime')
      .on('postgres_changes', { event: 'DELETE', schema: 'public', table: 'contact_messages' }, (payload) => {
        setMessages(prev => prev.filter(m => m.id !== (payload.old as any)?.id));
      })
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'contact_messages' }, (payload) => {
        const updated = payload.new as ContactMessage;
        setMessages(prev => prev.map(m => m.id === updated.id ? { ...m, ...updated } : m));
      })
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'contact_messages' }, (payload) => {
        setMessages(prev => [payload.new as ContactMessage, ...prev]);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  const fetchMessages = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('contact_messages')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      setMessages(data || []);
    } catch (error) {
      if (import.meta.env.DEV) {
        console.error('Error fetching contact messages:', error);
      }
      toast.error("Couldn't load messages. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleStatusChange = async (id: string, newStatus: string) => {
    try {
      const { error } = await supabase
        .from('contact_messages')
        .update({ status: newStatus, updated_at: new Date().toISOString() })
        .eq('id', id);

      if (error) throw error;
      toast.success('Status updated');
      fetchMessages();
    } catch (error) {
      toast.error("Couldn't update status. Please try again.");
    }
  };

  const handleDelete = async (id: string) => {
    try {
      const { error } = await supabase
        .from('contact_messages')
        .delete()
        .eq('id', id);

      if (error) throw error;
      toast.success('Message deleted');
      fetchMessages();
    } catch (error) {
      toast.error("Couldn't delete message. Please try again.");
    }
  };

  const filteredMessages = useMemo(() => {
    return messages.filter(msg => {
      const matchesSearch = 
        msg.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        msg.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
        msg.message.toLowerCase().includes(searchQuery.toLowerCase());

      const matchesStatus = statusFilter === 'all' || msg.status === statusFilter;

      return matchesSearch && matchesStatus;
    });
  }, [messages, searchQuery, statusFilter]);

  const paginatedMessages = useMemo(() => {
    const start = (currentPage - 1) * ITEMS_PER_PAGE;
    return filteredMessages.slice(start, start + ITEMS_PER_PAGE);
  }, [filteredMessages, currentPage]);

  const totalPages = Math.ceil(filteredMessages.length / ITEMS_PER_PAGE);

  const stats = useMemo(() => ({
    total: messages.length,
    new: messages.filter(m => m.status === 'new').length,
    read: messages.filter(m => m.status === 'read').length,
    enterprise: messages.filter(m => m.message.includes('[ENTERPRISE INQUIRY]')).length,
  }), [messages]);

  const exportToCSV = () => {
    const headers = ['Name', 'Email', 'Message', 'Status', 'Created At'];
    const csvData = filteredMessages.map(msg => [
      msg.name,
      msg.email,
      msg.message.replace(/"/g, '""'),
      msg.status,
      new Date(msg.created_at).toLocaleString()
    ]);

    const csvContent = [headers, ...csvData]
      .map(row => row.map(cell => `"${cell}"`).join(','))
      .join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `contact_messages_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    toast.success('Messages exported successfully');
  };

  const isEnterprise = (msg: ContactMessage) => msg.message.includes('[ENTERPRISE INQUIRY]');
  const isNew = (createdAt: string) => {
    const created = new Date(createdAt);
    const now = new Date();
    const diffHours = (now.getTime() - created.getTime()) / (1000 * 60 * 60);
    return diffHours < 24;
  };

  return (
    <div className="space-y-6">
      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Total', value: stats.total, color: 'text-foreground' },
          { label: 'New', value: stats.new, color: 'text-blue-500' },
          { label: 'Read', value: stats.read, color: 'text-green-500' },
          { label: 'Enterprise', value: stats.enterprise, color: 'text-yellow-500' },
        ].map((stat) => (
          <div
            key={stat.label}
            className="bg-card/80 backdrop-blur-sm border border-border/50 rounded-xl p-4"
          >
            <p className="text-sm text-muted-foreground">{stat.label}</p>
            <p className={`text-3xl font-bold mt-1 ${stat.color}`}>{stat.value}</p>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div className="flex flex-wrap items-center gap-3">
        <div className="relative flex-1 min-w-[200px]">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Search by name, email, or message..."
            className="pl-9 bg-background/50"
          />
        </div>

        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-[130px] bg-background/50">
            <SelectValue placeholder="Status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Status</SelectItem>
            <SelectItem value="new">New</SelectItem>
            <SelectItem value="read">Read</SelectItem>
          </SelectContent>
        </Select>

        <Button variant="outline" size="sm" onClick={exportToCSV} className="gap-2">
          <Download className="h-4 w-4" />
          Export CSV
        </Button>
        <Button variant="outline" size="icon" onClick={fetchMessages} disabled={isLoading}>
          <RefreshCw className={`h-4 w-4 ${isLoading ? 'animate-spin' : ''}`} />
        </Button>
      </div>

      {/* Messages List */}
      <ScrollArea className="h-[500px] rounded-xl border border-border/50 bg-background/30">
        {isLoading ? (
          <div className="flex items-center justify-center py-16">
            <RefreshCw className="h-8 w-8 animate-spin text-muted-foreground" />
          </div>
        ) : paginatedMessages.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16 text-muted-foreground">
            <div className="p-4 rounded-full bg-muted/50 mb-4">
              <Inbox className="h-12 w-12 opacity-50" />
            </div>
            <p className="text-lg font-medium">No messages found</p>
            <p className="text-sm">Try adjusting your filters or search query</p>
          </div>
        ) : (
          <motion.div
            variants={containerVariants}
            initial="hidden"
            animate="visible"
            className="p-2 space-y-2"
          >
            {paginatedMessages.map((msg) => (
              <motion.div
                key={msg.id}
                variants={itemVariants}
                className="group bg-card/80 backdrop-blur-sm border border-border/50 rounded-xl p-4 hover:border-primary/30 hover:shadow-md transition-all duration-200"
              >
                <div className="flex items-start justify-between gap-4">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-2">
                      {isEnterprise(msg) && (
                        <Badge className="bg-yellow-500/10 text-yellow-500 border-yellow-500/20">
                          <Star className="h-3 w-3 mr-1" />
                          Enterprise
                        </Badge>
                      )}
                      {isNew(msg.created_at) && (
                        <span className="relative flex h-2 w-2">
                          <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75" />
                          <span className="relative inline-flex rounded-full h-2 w-2 bg-blue-500" />
                        </span>
                      )}
                      <h4 className="font-medium truncate">{msg.name}</h4>
                    </div>
                    <div className="flex items-center gap-3 text-sm text-muted-foreground mb-2">
                      <span className="flex items-center gap-1.5">
                        <Mail className="h-3.5 w-3.5" />
                        {msg.email}
                      </span>
                      <span className="flex items-center gap-1.5">
                        <Calendar className="h-3.5 w-3.5" />
                        {new Date(msg.created_at).toLocaleDateString()}
                      </span>
                    </div>
                    <p className="text-sm text-muted-foreground line-clamp-2">
                      {msg.message.replace('[ENTERPRISE INQUIRY]\n\n', '')}
                    </p>
                  </div>

                  <div className="flex items-center gap-2">
                    <Badge variant="outline" className={`text-xs ${msg.status === 'new' ? 'bg-blue-500/10 text-blue-500' : 'bg-green-500/10 text-green-500'}`}>
                      {msg.status}
                    </Badge>

                    {msg.status === 'new' && (
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8"
                        onClick={() => handleStatusChange(msg.id, 'read')}
                        title="Mark as read"
                      >
                        <CheckCircle className="h-4 w-4" />
                      </Button>
                    )}

                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-8 w-8 text-destructive hover:text-destructive"
                      onClick={() => handleDelete(msg.id)}
                      title="Delete"
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              </motion.div>
            ))}
          </motion.div>
        )}
      </ScrollArea>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between pt-2">
          <p className="text-sm text-muted-foreground">
            Showing {((currentPage - 1) * ITEMS_PER_PAGE) + 1} - {Math.min(currentPage * ITEMS_PER_PAGE, filteredMessages.length)} of {filteredMessages.length}
          </p>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
              disabled={currentPage === 1}
            >
              Previous
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
              disabled={currentPage === totalPages}
            >
              Next
            </Button>
          </div>
        </div>
      )}
    </div>
  );
};

