interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  agent?: string;
  agent_name?: string;
  agent_emoji?: string;
  tool_results?: ToolResult[];
  timestamp: Date;
  fromHistory?: boolean;
}

interface ToolResult {
  type: 'agent_result' | 'directive_saved' | 'discussion' | 'error' | 'memory_updated';
  agent?: string;
  agent_name?: string;
  agent_emoji?: string;
  command?: string;
  result?: any;
  success?: boolean;
  message?: string;
  directive?: any;
  responses?: { name: string; reply: string; emoji: string; employeeId: string }[];
