// ─── Props ───
interface ChartUnifiedChatProps {
  messages?: ChatMessage[];
  onMessagesChange?: (messages: ChatMessage[]) => void;
  latestResult?: ChartAnalysisResult | null;
  onLatestResultChange?: (result: ChartAnalysisResult | null) => void;
  coach: CoachAPI;
  onToggleSidebar?: () => void;
}

// ─── Main Component ───
export default function ChartUnifiedChat({
  messages: externalMessages,
  onMessagesChange,
  latestResult: externalLatestResult,
  onLatestResultChange,
  coach,
  onToggleSidebar,
}: ChartUnifiedChatProps) {
  const [localMessages, setLocalMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [attachedFile, setAttachedFile] = useState<File | null>(null);
  const [attachedPreview, setAttachedPreview] = useState<string | null>(null);
  const [isDragOver, setIsDragOver] = useState(false);
  const [localLatestResult, setLocalLatestResult] = useState<ChartAnalysisResult | null>(null);

  // Use external state if provided (lifted to parent for persistence), else local
  const messages = externalMessages ?? localMessages;
  const setMessages = useCallback((updater: ChatMessage[] | ((prev: ChatMessage[]) => ChatMessage[])) => {
    const next = typeof updater === 'function' ? updater(externalMessages ?? localMessages) : updater;
    if (onMessagesChange) onMessagesChange(next);
    else setLocalMessages(next);
  }, [externalMessages, localMessages, onMessagesChange]);

  const latestResult = externalLatestResult !== undefined ? externalLatestResult : localLatestResult;
  const setLatestResult = useCallback((result: ChartAnalysisResult | null) => {
    if (onLatestResultChange) onLatestResultChange(result);
    else setLocalLatestResult(result);
  }, [onLatestResultChange]);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const dragCounter = useRef(0);

  const analyzer = useChartAnalyzer();

  const isAnalyzing = ['uploading', 'analyzing', 'fetching-news', 'predicting'].includes(analyzer.step);
  const isBusy = isAnalyzing || coach.isLoading;

  // ─── Scroll to bottom ───
  const scrollToBottom = useCallback(() => {
    requestAnimationFrame(() => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }));
  }, []);

  useEffect(() => { scrollToBottom(); }, [messages.length, scrollToBottom]);

  // ─── Watch analyzer step changes ───
  useEffect(() => {
    if (isAnalyzing) {
      setMessages(prev => {
        const withoutLoading = prev.filter(m => m.type !== 'ayn-loading');
        return [...withoutLoading, { type: 'ayn-loading', step: analyzer.step }];
      });
    }
  }, [analyzer.step, isAnalyzing, setMessages]);

  // ─── Watch for analysis result ───
  useEffect(() => {
    if (analyzer.result && analyzer.step === 'done') {
      setLatestResult(analyzer.result);
      const text = formatAnalysisAsText(analyzer.result);
      setMessages(prev => {
        const withoutLoading = prev.filter(m => m.type !== 'ayn-loading');
        return [...withoutLoading, { type: 'ayn-text', content: text }];
      });

      // Frontend backup: record paper trade if actionable signal
      const r = analyzer.result;
      const sig = r.prediction;
      const action = sig.signal;
      const conf = sig.confidence;
      const ts = sig.tradingSignal;
      if ((action === 'BUY' || action === 'SELL' || action === 'BULLISH' || action === 'BEARISH') && conf >= 60 && ts) {
        const entryPrice = ts.entry?.price;
        const stopLoss = ts.stopLoss?.price;
        if (entryPrice && stopLoss && entryPrice > 0 && stopLoss > 0) {
          supabase.functions.invoke('ayn-open-trade', {
            body: {
              ticker: r.ticker,
              timeframe: r.timeframe,
              signal: action === 'BULLISH' ? 'BUY' : action === 'BEARISH' ? 'SELL' : action,
              entryPrice,
              stopLoss,
              takeProfit1: ts.takeProfits?.[0]?.price || null,
              takeProfit2: ts.takeProfits?.[1]?.price || null,
              confidence: conf,
              setupType: sig.patternBreakdown?.[0]?.name || null,
              reasoning: sig.reasoning || '',
              chartImageUrl: r.imageUrl || null,
            },
          }).then(res => {
            if (res.data?.opened) {
              toast.success('Trade recorded in paper account');
            }
          }).catch(() => {});
        }
      }
    }
  }, [analyzer.result, analyzer.step, setLatestResult, setMessages]);

  // ─── Watch for analysis error ───
  useEffect(() => {
    if (analyzer.error && analyzer.step === 'error') {
      setMessages(prev => {
        const withoutLoading = prev.filter(m => m.type !== 'ayn-loading');
        return [...withoutLoading, { type: 'ayn-error', content: analyzer.error! }];
      });
    }
  }, [analyzer.error, analyzer.step, setMessages]);

  // ─── Sync coach messages ───
  const prevCoachLenRef = useRef(coach.messages.length);
  const prevSessionIdRef = useRef<string | null>(coach.activeSessionId);

  // When session switches, replace all messages with the new session's messages
  useEffect(() => {
    if (coach.activeSessionId !== prevSessionIdRef.current) {
      prevSessionIdRef.current = coach.activeSessionId;
      if (coach.messages.length > 0) {
        const converted: ChatMessage[] = coach.messages.map(m =>
          m.role === 'user'
            ? { type: 'user-text' as const, content: m.content }
            : { type: 'ayn-text' as const, content: m.content }
        );
        setMessages(converted);
      } else {
        setMessages([]);
      }
      prevCoachLenRef.current = coach.messages.length;
    }
  }, [coach.activeSessionId, coach.messages, setMessages]);

  useEffect(() => {
    // Only start a new chat session if there are no existing messages (first ever load)
    if (messages.length === 0) {
      coach.newChat();
    }
    prevCoachLenRef.current = coach.messages.length;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (coach.messages.length > prevCoachLenRef.current) {
      const newMsgs = coach.messages.slice(prevCoachLenRef.current);
      const chatMsgs: ChatMessage[] = newMsgs.map(m =>
        m.role === 'user' ? { type: 'user-text' as const, content: m.content } : { type: 'ayn-text' as const, content: m.content }
      );
      const assistantOnly = chatMsgs.filter(m => m.type === 'ayn-text');
      if (assistantOnly.length > 0) {
        setMessages(prev => [...prev, ...assistantOnly]);
      }
    }
    prevCoachLenRef.current = coach.messages.length;
  }, [coach.messages.length, coach.messages, setMessages]);

  // ─── File handling ───
  const attachFile = useCallback((file: File) => {
    if (!file.type.startsWith('image/')) return;
    setAttachedFile(file);
    const url = URL.createObjectURL(file);
    setAttachedPreview(url);
  }, []);

  const clearAttachment = useCallback(() => {
    if (attachedPreview) URL.revokeObjectURL(attachedPreview);
    setAttachedFile(null);
    setAttachedPreview(null);
  }, [attachedPreview]);

  // ─── Drag & Drop ───
  const handleDragEnter = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    dragCounter.current++;
    setIsDragOver(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    dragCounter.current--;
    if (dragCounter.current === 0) setIsDragOver(false);
  }, []);

  const handleDragOver = useCallback((e: React.DragEvent) => { e.preventDefault(); }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    dragCounter.current = 0;
    setIsDragOver(false);
    const file = e.dataTransfer.files[0];
    if (file) attachFile(file);
  }, [attachFile]);

  // ─── Send ───
  const handleSend = useCallback(() => {
    const text = input.trim();
    if (!text && !attachedFile) return;
    if (isBusy) return;

    if (attachedFile) {
      // Convert to base64 for persistent image URL
      const reader = new FileReader();
      const file = attachedFile;
      const msgText = text || undefined;
      reader.onload = () => {
        const base64Url = reader.result as string;
        setMessages(prev => [...prev, { type: 'user-image', imageUrl: base64Url, content: msgText }]);
        analyzer.reset();
        analyzer.analyzeChart(file);
      };
      reader.readAsDataURL(file);
      clearAttachment();
      setInput('');
    } else {
      // Text-only chat flow
      setMessages(prev => [...prev, { type: 'user-text', content: text }]);
      coach.sendMessage(text);
      setInput('');
    }
  }, [input, attachedFile, attachedPreview, isBusy, analyzer, coach, clearAttachment, setMessages]);

  // ─── Textarea auto-resize ───
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = Math.min(textareaRef.current.scrollHeight, 120) + 'px';
    }
  }, [input]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // ─── Quick chip ───
  const handleChip = useCallback((text: string) => {
    setMessages(prev => [...prev, { type: 'user-text', content: text }]);
    coach.sendMessage(text);
  }, [coach, setMessages]);


  const hasMessages = messages.length > 0;

  return (
    <div
      className="flex flex-col h-[calc(100vh-100px)] relative"
      onDragEnter={handleDragEnter}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      {/* Drag overlay */}
      <AnimatePresence>
        {isDragOver && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="absolute inset-0 z-50 bg-background/80 backdrop-blur-sm flex items-center justify-center rounded-2xl border-2 border-dashed border-amber-500"
          >
            <div className="text-center">
              <Upload className="h-10 w-10 text-amber-500 mx-auto mb-2" />
              <p className="text-sm font-semibold">Drop your chart here</p>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Top bar */}
      <div className="flex items-center gap-2 px-1 py-2 shrink-0">
        <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-amber-500 to-orange-600 flex items-center justify-center">
          <BarChart3 className="h-4 w-4 text-white" />
        </div>
        <span className="text-sm font-semibold">AYN Chart Analyzer</span>
      </div>

      {/* Messages area */}
      <div ref={scrollContainerRef} className="flex-1 overflow-y-auto px-1">
        {!hasMessages ? (
          /* Empty state */
          <div className="flex flex-col items-center justify-center h-full text-center px-4">
            <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-amber-500/20 to-orange-500/20 flex items-center justify-center mb-4">
              <BarChart3 className="h-8 w-8 text-amber-500" />
            </div>
            <h3 className="text-lg font-semibold mb-1">Drop a chart or type a question</h3>
            <p className="text-sm text-muted-foreground mb-6 max-w-sm">
              Upload a trading chart for AI analysis, or ask anything about trading
            </p>
            <div className="flex flex-wrap justify-center gap-2">
              {QUICK_CHIPS.map(chip => (
                <button
                  key={chip}
                  onClick={() => handleChip(chip)}
                  className="text-xs px-3 py-1.5 rounded-full border border-amber-500/20 text-amber-600 dark:text-amber-400 hover:bg-amber-500/10 transition-colors"
                >
                  {chip}
                </button>
              ))}
            </div>
          </div>
        ) : (
          <div className="space-y-4 py-4">
            {messages.map((msg, i) => {
              switch (msg.type) {
                case 'user-text':
                  return <UserTextBubble key={i} content={msg.content} />;
                case 'user-image':
                  return <UserImageBubble key={i} imageUrl={msg.imageUrl} content={msg.content} />;
                case 'ayn-loading':
                  return <LoadingBubble key={`loading-${i}`} currentStep={msg.step} />;
                case 'ayn-text':
                  return <AynTextBubble key={i} content={msg.content} />;
                case 'ayn-error':
                  return (
                    <div key={i} className="flex justify-start">
                      <div className="max-w-[80%] rounded-2xl px-4 py-2.5 bg-destructive/10 text-destructive text-sm">
                        {msg.content}
                      </div>
                    </div>
                  );
                default:
                  return null;
              }
            })}
            {coach.isLoading && (
              <div className="flex justify-start">
                <div className="rounded-2xl px-4 py-2.5 bg-muted">
                  <div className="flex items-center gap-2 text-sm text-muted-foreground">
                    <Sparkles className="w-4 h-4 animate-pulse text-amber-500" />
                    <span>AYN is thinking...</span>
                  </div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>

      {/* Input bar — AYN style */}
      <div className="shrink-0 px-1 pb-2 pt-2">
        <div className={cn(
          "relative rounded-2xl overflow-hidden",
          "bg-background/95 backdrop-blur-xl",
          "border border-border/50",
          "shadow-lg",
          "transition-all duration-200",
          "focus-within:border-amber-500/40"
        )}>
          {/* Row 1: Textarea + animated Send button */}
          <div className="flex items-end gap-2 px-4 pt-3 pb-2">
            <div className="flex-1 min-w-0">
              <Textarea
                ref={textareaRef}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Ask about trading or upload a chart..."
                disabled={isBusy}
                unstyled
                className="resize-none min-h-[44px] max-h-[120px] w-full text-sm bg-transparent placeholder:text-muted-foreground/50 leading-relaxed overflow-y-auto"
                rows={1}
              />
            </div>

            {/* Send / Loading button */}
            <AnimatePresence mode="wait">
              {isBusy ? (
                <motion.div
                  key="loading"
                  initial={{ scale: 0, opacity: 0 }}
                  animate={{ scale: 1, opacity: 1 }}
                  exit={{ scale: 0, opacity: 0 }}
                  className="shrink-0 mb-1 w-9 h-9 rounded-xl bg-muted flex items-center justify-center"
                >
                  <Loader2 className="w-4 h-4 animate-spin text-amber-500" />
                </motion.div>
              ) : (input.trim() || attachedFile) ? (
                <motion.button
                  key="send"
                  initial={{ scale: 0, opacity: 0 }}
                  animate={{ scale: 1, opacity: 1 }}
                  exit={{ scale: 0, opacity: 0 }}
                  transition={{ duration: 0.15, ease: 'easeOut' }}
                  onClick={handleSend}
                  className="shrink-0 mb-1 w-9 h-9 rounded-xl bg-amber-500 text-white flex items-center justify-center hover:bg-amber-600 hover:scale-105 active:scale-95 shadow-md transition-all"
                >
                  <ArrowUp className="w-4 h-4" strokeWidth={2.5} />
                </motion.button>
              ) : null}
            </AnimatePresence>
          </div>

          {/* Attached image chip */}
          <AnimatePresence>
            {attachedPreview && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                className="px-4 pb-2"
              >
                <div className="relative inline-block">
                  <img src={attachedPreview} alt="Attached chart" className="h-16 rounded-lg border border-border object-contain" />
                  <button
                    onClick={clearAttachment}
                    className="absolute -top-1.5 -right-1.5 w-5 h-5 rounded-full bg-foreground text-background flex items-center justify-center hover:scale-110 transition-transform"
                  >
                    <X className="h-3 w-3" />
                  </button>
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Row 2: Toolbar — 3-column grid (matches AYN ChatInput) */}
          <div className="grid grid-cols-3 items-center px-2 py-1.5 border-t border-border/30 bg-muted/10">
            {/* Left: + New + Upload */}
            <div className="flex items-center gap-0.5">
              <button
                onClick={() => { coach.newChat(); setMessages([]); }}
                className="inline-flex items-center gap-1 px-2.5 py-1 rounded-full border border-border text-xs text-muted-foreground hover:bg-muted/60 hover:text-foreground transition-all"
              >
                <Plus className="w-3.5 h-3.5" />
                New
              </button>
              <button
                onClick={() => fileInputRef.current?.click()}
                disabled={isBusy}
                className="inline-flex items-center justify-center w-8 h-8 rounded-full border border-border text-muted-foreground hover:bg-muted/60 hover:text-foreground transition-all disabled:opacity-40"
                title="Upload chart"
              >
                <Upload className="w-4 h-4" />
              </button>
            </div>

            {/* Center: Chat history toggle */}
            <div className="flex justify-center">
              {coach.sessions.length > 0 && (
                <button
                  onClick={onToggleSidebar}
                  className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full border border-border bg-card/80 text-xs text-muted-foreground hover:bg-muted/50 hover:text-foreground active:scale-95 transition-all"
                >
                  <Clock className="h-3.5 w-3.5" />
                  <span className="hidden sm:inline">History</span>
                  <span className="text-[10px] bg-muted px-1.5 py-0.5 rounded-full">{coach.sessions.length}</span>
                </button>
              )}
            </div>

            {/* Right: AYN label */}
            <div className="flex items-center justify-end gap-1.5 text-muted-foreground px-1">
              <Brain className="w-4 h-4 text-foreground" />
              <span className="text-xs font-medium hidden sm:inline">AYN</span>
            </div>
          </div>
        </div>

        <input
          ref={fileInputRef}
          type="file"
          accept="image/*"
          className="hidden"
          onChange={(e) => {
            const file = e.target.files?.[0];
            if (file) attachFile(file);
            e.target.value = '';
          }}
        />
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, Zap, ArrowRight, Gift, Clock } from 'lucide-react';
import { Progress } from '@/components/ui/progress';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { differenceInDays, differenceInHours } from 'date-fns';
import { supabase } from '@/integrations/supabase/client';

interface CreditUpgradeCardProps {
  // All props are now optional — component fetches its own data
  remaining?: number;
  totalLimit?: number;
  allowed?: boolean;
  resetsAt?: string | null;
  tier?: string;
  isFree?: boolean;
  isUnlimited?: boolean;
  userId?: string;
  onOpenFeedback?: () => void;
  rewardAmount?: number;
}

interface CreditState {
  remaining: number;
  totalLimit: number;
  allowed: boolean;
  resetsAt: string | null;
  tier: string;
  isFree: boolean;
  isUnlimited: boolean;
  loaded: boolean;
}

export const CreditUpgradeCard = ({
  userId,
  onOpenFeedback,
  rewardAmount = 5,
  // These are fallback props — component will override with live data
  remaining: propRemaining,
  totalLimit: propTotalLimit,
  allowed: propAllowed,
  resetsAt: propResetsAt,
  tier: propTier,
  isFree: propIsFree,
  isUnlimited: propIsUnlimited,
}: CreditUpgradeCardProps) => {
  const navigate = useNavigate();
  const [hasSubmittedFeedback, setHasSubmittedFeedback] = useState<boolean | null>(null);
  const [displayCount, setDisplayCount] = useState(0);

  // Live credit state fetched directly from Supabase
  const [credits, setCredits] = useState<CreditState>({
    remaining: propRemaining ?? 0,
    totalLimit: propTotalLimit ?? 5,
    allowed: propAllowed ?? true,
    resetsAt: propResetsAt ?? null,
    tier: propTier ?? 'free',
    isFree: propIsFree ?? true,
    isUnlimited: propIsUnlimited ?? false,
    loaded: false,
  });

  // Fetch live credit data directly — never trust props alone
  useEffect(() => {
    if (!userId) return;

    const fetchCredits = async () => {
      try {
        const { data: limitsData, error } = await supabase
          .from('user_ai_limits')
          .select('*')
          .eq('user_id', userId)
          .maybeSingle();

        const { data: subData } = await supabase
          .from('user_subscriptions')
          .select('subscription_tier')
          .eq('user_id', userId)
          .maybeSingle();

        if (error || !limitsData) return;

        const tier = subData?.subscription_tier || 'free';
        const isFree = tier === 'free';
        const isUnlimited = limitsData.is_unlimited === true;

        if (isUnlimited) {
          setCredits(prev => ({ ...prev, isUnlimited: true, loaded: true }));
          return;
        }

        let remaining: number;
        let totalLimit: number;
        let resetsAt: string | null;
        let allowed: boolean;

        if (isFree) {
          // Free users: daily limit, check if daily reset has expired
          const dailyResetAt = limitsData.daily_reset_at ? new Date(limitsData.daily_reset_at) : null;
          const isExpired = !dailyResetAt || dailyResetAt <= new Date();

          const used = isExpired ? 0 : (limitsData.current_daily_messages || 0);
          const limit = limitsData.daily_messages || 5;
          remaining = Math.max(0, limit - used);
          totalLimit = limit;
          resetsAt = isExpired
            ? new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString()
            : limitsData.daily_reset_at;
          allowed = remaining > 0;
        } else {
          // Paid users: monthly limit
          const monthlyResetAt = limitsData.monthly_reset_at ? new Date(limitsData.monthly_reset_at) : null;
          const isExpired = !monthlyResetAt || monthlyResetAt <= new Date();

          const used = isExpired ? 0 : (limitsData.current_monthly_messages || 0);
          const limit = (limitsData.monthly_messages || 1000) + (limitsData.bonus_credits || 0);
          remaining = Math.max(0, limit - used);
          totalLimit = limit;
          resetsAt = limitsData.monthly_reset_at;
          allowed = remaining > 0;
        }

        setCredits({
          remaining,
          totalLimit,
          allowed,
          resetsAt,
          tier,
          isFree,
          isUnlimited: false,
          loaded: true,
        });
      } catch {
        // Silent failure — keep defaults
        setCredits(prev => ({ ...prev, loaded: true }));
      }
    };

    fetchCredits();

    // Re-fetch every 60 seconds to stay current
    const interval = setInterval(fetchCredits, 60000);
    return () => clearInterval(interval);
  }, [userId]);

  // Check if user has already submitted feedback
  useEffect(() => {
    if (!userId) return;
    const check = async () => {
      try {
        const { data } = await supabase
          .from('beta_feedback')
          .select('id')
          .eq('user_id', userId)
          .limit(1);
        setHasSubmittedFeedback(data ? data.length > 0 : false);
      } catch (error) { console.error("Error checking beta feedback:", error); }
    };
    check();
  }, [userId]);

  // Animate count changes
  useEffect(() => {
    const target = credits.remaining;
    if (target === displayCount) return;
    const start = displayCount;
    const duration = 300;
    const startTime = performance.now();
    const animate = (currentTime: number) => {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplayCount(Math.round(start + (target - start) * eased));
      if (progress < 1) requestAnimationFrame(animate);
    };
    requestAnimationFrame(animate);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [credits.remaining, displayCount]);

  // Format reset time
  const formattedResetTime = useMemo(() => {
    if (!credits.resetsAt) return null;
    const reset = new Date(credits.resetsAt);
    const days = differenceInDays(reset, new Date());
    if (days > 0) return `${days}d`;
    const hours = differenceInHours(reset, new Date());
    return hours > 0 ? `${hours}h` : 'Soon';
  }, [credits.resetsAt]);

  const { remaining, totalLimit, allowed, isFree, isUnlimited, tier } = credits;
  const percentage = totalLimit > 0 ? Math.min(((totalLimit - remaining) / totalLimit) * 100, 100) : 0;
  const isLow = remaining < totalLimit * 0.2 && remaining > 0;
  const showEarnButton = userId && onOpenFeedback && hasSubmittedFeedback === false;

  // Unlimited users — show a clean status card
  if (isUnlimited) {
    return (
      <motion.div
        initial={{ opacity: 0, y: 6 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.2 }}
        className={cn(
          "relative rounded-xl overflow-hidden",
          "bg-card/60 backdrop-blur-md",
          "border border-border/50",
          "p-3"
        )}
      >
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="p-1.5 rounded-lg bg-primary/10">
              <Sparkles className="w-4 h-4 text-primary" />
            </div>
            <span className="font-medium text-sm text-foreground">Unlimited Plan</span>
          </div>
          <span className="text-xs font-semibold text-primary">∞</span>
        </div>
        <p className="text-[10px] text-muted-foreground mt-1.5">No message limits</p>
      </motion.div>
    );
  }

  // Don't render while loading to avoid flash of wrong data
  if (!credits.loaded && !userId) return null;

  // Limit reached
  if (!allowed) {
    return (
      <motion.div
        initial={{ opacity: 0, y: 6 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.2 }}
        className={cn(
          "relative rounded-xl overflow-hidden",
          "bg-destructive/10 backdrop-blur-md",
          "border border-destructive/30",
          "p-3"
        )}
      >
        <div className="flex items-center gap-2 mb-2">
          <div className="p-1.5 rounded-lg bg-destructive/20">
            <Zap className="w-4 h-4 text-destructive" />
          </div>
          <span className="font-medium text-sm text-foreground">Limit Reached</span>
        </div>

        <p className="text-xs text-muted-foreground leading-relaxed mb-2">
          {isFree
            ? "You've used all 5 messages for today. Come back tomorrow."
            : "You've reached your monthly limit. Top up or wait for renewal."}
        </p>

        {formattedResetTime && (
          <div className="flex items-center gap-1.5 text-xs text-muted-foreground mb-2">
            <Clock className="w-3 h-3" />
            <span>Resets in {formattedResetTime}</span>
          </div>
        )}

        {isFree ? (
          <motion.button
            onClick={() => navigate('/pricing')}
            className={cn(
              "w-full flex items-center justify-center gap-1.5",
              "text-xs font-medium text-primary",
              "hover:text-primary/80 transition-colors group"
            )}
          >
            <span>Upgrade for more messages</span>
            <ArrowRight className="w-3 h-3 group-hover:translate-x-0.5 transition-transform" />
          </motion.button>
        ) : (
          <Button
            onClick={() => navigate('/pricing')}
            size="sm"
            variant="outline"
            className="w-full h-8 text-xs"
          >
            Top Up or Upgrade
          </Button>
        )}
      </motion.div>
    );
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 6 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.2 }}
      className={cn(
        "relative rounded-xl overflow-hidden",
        "bg-card/60 backdrop-blur-md",
        "border border-border/50",
        "p-3"
      )}
    >
      {/* Header Row */}
      <div className="flex items-center justify-between mb-2">
        <div className="flex items-center gap-2">
          <div className={cn(
            "p-1.5 rounded-lg",
            isLow ? "bg-destructive/20" : "bg-muted/50"
          )}>
            {isLow
              ? <Zap className="w-4 h-4 text-destructive" />
              : <Sparkles className="w-4 h-4 text-foreground/70" />}
          </div>
          <span className="font-medium text-sm text-foreground">
            {isFree ? 'Daily Messages' : 'Monthly Messages'}
          </span>
        </div>
        <div className="flex items-baseline gap-1">
          <motion.span
            key={displayCount}
            initial={{ scale: 1.1, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="text-lg font-bold tabular-nums text-foreground"
          >
            {String(displayCount)}
          </motion.span>
          <span className="text-xs text-muted-foreground">left</span>
        </div>
      </div>

      {/* Progress Bar */}
      <div className="flex items-center gap-2">
        <div className="flex-1">
          <Progress
            value={100 - percentage}
            className={cn(
              "h-1.5",
              isLow && "[&>div]:bg-destructive"
            )}
          />
        </div>
        {formattedResetTime && (
          <span className="text-xs text-muted-foreground whitespace-nowrap">
            Resets {formattedResetTime}
          </span>
        )}
      </div>

      {/* Context line */}
      <p className="text-[10px] text-muted-foreground mt-1.5">
        {remaining} of {totalLimit} {isFree ? 'messages remaining today' : 'messages remaining this month'}
      </p>

      {/* Earn Credits Button */}
      <AnimatePresence>
        {showEarnButton && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.2 }}
          >
            <Button
              onClick={onOpenFeedback}
              size="sm"
              className={cn(
                "w-full mt-2.5 h-9 rounded-lg gap-2",
                "bg-gradient-to-r from-purple-500 via-fuchsia-500 to-pink-500",
                "hover:from-purple-600 hover:via-fuchsia-600 hover:to-pink-600",
                "text-white font-medium",
                "shadow-sm hover:shadow-md shadow-purple-500/20",
                "transition-all duration-150"
              )}
            >
              <Gift className="w-4 h-4" />
              <span>Earn +{rewardAmount} Credits</span>
              <Sparkles className="w-3.5 h-3.5 text-yellow-200" />
            </Button>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Upgrade Link for Free Tier */}
      {isFree && !showEarnButton && (
        <motion.button
          onClick={() => navigate('/pricing')}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.1 }}
          className={cn(
            "mt-2 w-full flex items-center justify-center gap-1.5",
            "text-xs font-medium text-primary",
            "hover:text-primary/80 transition-colors",
            "group"
          )}
        >
          <span>Upgrade for more messages</span>
          <ArrowRight className="w-3 h-3 group-hover:translate-x-0.5 transition-transform" />
        </motion.button>
      )}
    </motion.div>
  );
};

