  timestamp: Date;
}

interface AnalysisInsight {
  icon: 'check' | 'trend' | 'alert';
  text: string;
  type: 'positive' | 'neutral' | 'warning';
}

interface AICalculatorAssistantProps {
  calculatorType: CalculatorType;
  inputs: Record<string, any>;
  outputs: Record<string, any> | null;
  onApplySuggestion: (field: string, value: any) => void;
  onApplyAllSuggestions: (values: Record<string, any>) => void;
}

const QUICK_ACTIONS: Record<CalculatorType, { label: string; prompt: string; icon: 'sparkles' | 'zap' | 'trend' }[]> = {
  beam: [
    { label: 'Optimize depth', prompt: 'What is the optimal depth for this beam based on span/depth ratios?', icon: 'sparkles' },
    { label: 'Check deflection', prompt: 'Will this beam meet deflection limits under service loads?', icon: 'trend' },
    { label: 'Reduce steel', prompt: 'How can I reduce the steel requirement while maintaining safety?', icon: 'zap' },
  ],
  column: [
    { label: 'Check slenderness', prompt: 'Is this column slender? Should I consider second-order effects?', icon: 'trend' },
    { label: 'Optimize section', prompt: 'What is the minimum section size for this load?', icon: 'sparkles' },
    { label: 'Tie spacing', prompt: 'What tie spacing is required per ACI 318?', icon: 'zap' },
  ],
  foundation: [
    { label: 'Check bearing', prompt: 'Is the bearing pressure within allowable limits?', icon: 'trend' },
    { label: 'Optimize size', prompt: 'What is the minimum foundation size for this load?', icon: 'sparkles' },
    { label: 'Punching shear', prompt: 'Is punching shear a concern? What reinforcement is needed?', icon: 'zap' },
  ],
  slab: [
    { label: 'Minimum thickness', prompt: 'What is the minimum slab thickness to control deflection?', icon: 'sparkles' },
    { label: 'Rebar layout', prompt: 'What is the optimal reinforcement layout for this slab?', icon: 'zap' },
    { label: 'Crack control', prompt: 'How do I ensure crack widths are within limits?', icon: 'trend' },
  ],
  retaining_wall: [
    { label: 'Stability check', prompt: 'Is the wall stable against overturning and sliding?', icon: 'trend' },
    { label: 'Drainage', prompt: 'What drainage provisions are recommended?', icon: 'zap' },
    { label: 'Key design', prompt: 'Do I need a key? What size should it be?', icon: 'sparkles' },
  ],
  grading: [
    { label: 'Cut/fill balance', prompt: 'How can I balance cut and fill volumes?', icon: 'sparkles' },
    { label: 'Drainage design', prompt: 'What slope is needed for proper drainage?', icon: 'trend' },
    { label: 'Cost estimate', prompt: 'What is the estimated earthwork cost?', icon: 'zap' },
  ],
  // parking: (hidden for now)
};

export const AICalculatorAssistant: React.FC<AICalculatorAssistantProps> = ({
  calculatorType,
  inputs,
  outputs,
  onApplySuggestion,
  onApplyAllSuggestions,
}) => {
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [warnings, setWarnings] = useState<Warning[]>([]);
  const [insights, setInsights] = useState<AnalysisInsight[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [isSending, setIsSending] = useState(false);
  const [streamingContent, setStreamingContent] = useState('');
  const [analysisStatus, setAnalysisStatus] = useState<'idle' | 'analyzing' | 'ready'>('idle');
  const chatEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);
  const lastAnalyzedInputs = useRef<string>('');

  // Smart auto-scroll state
  const [shouldAutoScroll, setShouldAutoScroll] = useState(true);
  const prevMessageCountRef = useRef(0);

  // Smart auto-scroll: only when NEW messages are added and user is near bottom
  useEffect(() => {
    const newMessageAdded = chatMessages.length > prevMessageCountRef.current;
    const isStreaming = streamingContent.length > 0;

    if ((newMessageAdded || isStreaming) && shouldAutoScroll) {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
    prevMessageCountRef.current = chatMessages.length;
  }, [chatMessages.length, streamingContent, shouldAutoScroll]);

  // Auto-resize textarea
  useEffect(() => {
    if (inputRef.current) {
      inputRef.current.style.height = 'auto';
      inputRef.current.style.height = Math.min(inputRef.current.scrollHeight, 100) + 'px';
    }
  }, [chatInput]);



  const analyzeInputs = useCallback(async () => {
    const newWarnings: Warning[] = [];
    const newSuggestions: Suggestion[] = [];
    const newInsights: AnalysisInsight[] = [];

    // Parking-specific analysis (hidden for now)

    // Beam-specific analysis
    if (calculatorType === 'beam' && inputs.span && inputs.width) {
      const span = parseFloat(inputs.span);
      const width = parseFloat(inputs.width);

      if (span > 0 && width > 0) {
        const recommendedDepth = (span * 1000) / 16;

        newInsights.push({
          icon: 'check',
          text: `Span: ${span}m — Recommended depth ≥ ${Math.round(recommendedDepth)}mm`,
          type: 'positive'
        });

        if (!inputs.depth || parseFloat(inputs.depth) < recommendedDepth * 0.8) {
          newSuggestions.push({
            field: 'depth',
            label: 'Beam Depth',
            currentValue: inputs.depth || 'Not set',
            suggestedValue: Math.ceil(recommendedDepth / 25) * 25,
            reason: `For span/depth ratio ≤ 16 (simply supported), depth should be ≥ ${Math.round(recommendedDepth)}mm`,
            priority: 'high',
          });
        }

        if (width < 200) {
          newWarnings.push({
            type: 'warning',
            message: 'Beam width < 200mm may cause construction difficulties',
            field: 'width',
          });
        }
      }
    }

    // Column-specific analysis
    if (calculatorType === 'column' && inputs.height && inputs.width) {
      const height = parseFloat(inputs.height) * 1000;
      const width = parseFloat(inputs.width);
      const slenderness = height / (width * 0.3);

      newInsights.push({
        icon: slenderness > 22 ? 'alert' : 'check',
        text: `Slenderness ratio: ${slenderness.toFixed(1)} ${slenderness > 22 ? '(needs P-Δ analysis)' : '(OK)'}`,
        type: slenderness > 22 ? 'warning' : 'positive'
      });

      if (slenderness > 22) {
        newWarnings.push({
          type: 'warning',
          message: `Slenderness ratio ≈ ${slenderness.toFixed(1)} > 22. Second-order effects should be considered.`,
        });
      }
    }

    // Foundation-specific analysis
    if (calculatorType === 'foundation' && inputs.columnLoad && inputs.bearingCapacity) {
      const load = parseFloat(inputs.columnLoad);
      const bearing = parseFloat(inputs.bearingCapacity);
      const minArea = (load * 1.5) / bearing;
      const minSize = Math.sqrt(minArea);

      newInsights.push({
        icon: 'check',
        text: `Required area: ${minArea.toFixed(2)} m² — Min size: ${minSize.toFixed(2)}m × ${minSize.toFixed(2)}m`,
        type: 'positive'
      });

      if (!inputs.length || parseFloat(inputs.length) < minSize) {
        newSuggestions.push({
          field: 'length',
          label: 'Foundation Length',
          currentValue: inputs.length || 'Not set',
          suggestedValue: Math.ceil(minSize * 10) / 10,
          reason: `Minimum size for bearing capacity: ${minSize.toFixed(2)}m × ${minSize.toFixed(2)}m`,
          priority: 'high',
        });
      }
    }

    setSuggestions(newSuggestions);
    setWarnings(newWarnings);
    setInsights(newInsights);
  }, [calculatorType, inputs]);

  // Analyze inputs when they change (debounced)
  useEffect(() => {
    const inputsString = JSON.stringify(inputs);
    if (inputsString === lastAnalyzedInputs.current) return;

    setAnalysisStatus('analyzing');
    const timer = setTimeout(() => {
      analyzeInputs();
      lastAnalyzedInputs.current = inputsString;
      setAnalysisStatus('ready');
    }, 1000);

    return () => clearTimeout(timer);
  }, [inputs, analyzeInputs]);

  const requestAIOptimization = async () => {
    setIsAnalyzing(true);
    try {
      const { data, error } = await supabase.functions.invoke('engineering-ai-chat', {
        body: {
          calculatorType,
          currentInputs: inputs,
          currentOutputs: outputs,
          messages: [
            {
              role: 'user',
              content: `Analyze my current inputs and provide specific optimized values. Return a JSON object with suggested field values and reasons. Current inputs: ${JSON.stringify(inputs)}`,
            },
          ],
        },
      });

      if (error) throw error;
      if (data?.suggestions) {
        setSuggestions(data.suggestions);
      }
    } catch (err) {
      console.error('AI optimization error:', err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const sendChatMessage = async (message: string) => {
    if (!message.trim() || isSending) return;

    const userMessage: ChatMessage = {
      role: 'user',
      content: message,
      timestamp: new Date(),
    };
    setChatMessages(prev => [...prev, userMessage]);
    setChatInput('');
    setIsSending(true);
    setStreamingContent('');

    try {
      const response = await fetch(
        `${SUPABASE_URL}/functions/v1/engineering-ai-chat`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
          },
          body: JSON.stringify({
            calculatorType,
            currentInputs: inputs,
            currentOutputs: outputs,
            messages: [
              ...chatMessages.map(m => ({ role: m.role, content: m.content })),
              { role: 'user', content: message },
            ],
            stream: true,
          }),
        }
      );

      if (!response.ok) throw new Error('Stream failed');

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();
      let fullContent = '';
      let buffer = '';

      while (reader) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });

        let newlineIndex: number;
        while ((newlineIndex = buffer.indexOf('\n')) !== -1) {
          const line = buffer.slice(0, newlineIndex).trim();
          buffer = buffer.slice(newlineIndex + 1);

          if (!line.startsWith('data: ') || line === 'data: [DONE]') continue;

          try {
            const parsed = JSON.parse(line.slice(6));
            const content = parsed.choices?.[0]?.delta?.content;
            if (content) {
              fullContent += content;
              setStreamingContent(fullContent);
            }
          } catch {
            // Partial JSON, continue
          }
        }
      }

      setChatMessages(prev => [
        ...prev,
        { role: 'assistant', content: fullContent, timestamp: new Date() },
      ]);
      setStreamingContent('');
    } catch (err) {
      console.error('Chat error:', err);
      setChatMessages(prev => [
        ...prev,
        { role: 'assistant', content: 'Sorry, I encountered an error. Please try again.', timestamp: new Date() },
      ]);
    } finally {
      setIsSending(false);
    }
  };

  const handleQuickAction = (prompt: string) => {
    sendChatMessage(prompt);
    if (!isChatOpen) setIsChatOpen(true);
  };

  const applyAllSuggestions = () => {
    const values: Record<string, any> = {};
    suggestions.forEach(s => {
      values[s.field] = s.suggestedValue;
    });
    onApplyAllSuggestions(values);
    setSuggestions([]);
  };

  const quickActions = QUICK_ACTIONS[calculatorType] || [];

  return (
    <div className="space-y-4">
      {/* AI Analysis Card - Always visible inline insights */}
      <motion.div 
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        className="relative overflow-hidden rounded-xl border border-primary/20 bg-gradient-to-br from-primary/5 via-background to-accent/5"
      >
        {/* Subtle animated background */}
        <div className="absolute inset-0 opacity-30">
          <div className="absolute top-0 right-0 w-32 h-32 bg-primary/10 rounded-full blur-3xl" />
          <div className="absolute bottom-0 left-0 w-24 h-24 bg-accent/10 rounded-full blur-2xl" />
        </div>

        <div className="relative p-4">
          {/* Header */}
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-3">
              <motion.div 
                className="relative w-10 h-10 rounded-xl bg-gradient-to-br from-primary/20 to-accent/20 flex items-center justify-center"
                animate={analysisStatus === 'analyzing' ? { scale: [1, 1.05, 1] } : {}}
                transition={{ repeat: Infinity, duration: 2 }}
              >
                <Brain className="w-5 h-5 text-primary" />
                {analysisStatus === 'analyzing' && (
                  <motion.div 
                    className="absolute inset-0 rounded-xl border-2 border-primary/40"
                    animate={{ scale: [1, 1.2, 1], opacity: [1, 0, 1] }}
                    transition={{ repeat: Infinity, duration: 1.5 }}
                  />
                )}
              </motion.div>
              <div>
                <h3 className="font-semibold text-sm">AI Engineering Analysis</h3>
                <p className="text-xs text-muted-foreground">
                  {analysisStatus === 'analyzing' ? 'Analyzing inputs...' : 'Real-time design insights'}
                </p>
              </div>
            </div>
            <Button
              variant="outline"
              size="sm"
              onClick={requestAIOptimization}
              disabled={isAnalyzing}
              className="gap-2 bg-background/50 backdrop-blur-sm border-primary/30 hover:border-primary/50 hover:bg-primary/10"
            >
              {isAnalyzing ? (
                <Loader2 className="w-3.5 h-3.5 animate-spin" />
              ) : (
                <Wand2 className="w-3.5 h-3.5" />
              )}
              <span className="hidden sm:inline">AI Optimize</span>
            </Button>
          </div>

          {/* Real-time Insights */}
          <AnimatePresence mode="wait">
            {insights.length > 0 && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                className="mb-3"
              >
                <div className="flex flex-wrap gap-2">
                  {insights.map((insight, i) => (
                    <motion.div
                      key={i}
                      initial={{ scale: 0.9, opacity: 0 }}
                      animate={{ scale: 1, opacity: 1 }}
                      transition={{ delay: i * 0.1 }}
                      className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium ${
                        insight.type === 'positive' 
                          ? 'bg-green-500/10 text-green-600 dark:text-green-400' 
                          : insight.type === 'warning'
                          ? 'bg-amber-500/10 text-amber-600 dark:text-amber-400'
                          : 'bg-primary/10 text-primary'
                      }`}
                    >
                      {insight.icon === 'check' && <CheckCircle2 className="w-3.5 h-3.5" />}
                      {insight.icon === 'trend' && <TrendingUp className="w-3.5 h-3.5" />}
                      {insight.icon === 'alert' && <AlertTriangle className="w-3.5 h-3.5" />}
                      {insight.text}
                    </motion.div>
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Warnings */}
          <AnimatePresence>
            {warnings.length > 0 && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                className="mb-3 p-3 rounded-lg bg-destructive/10 border border-destructive/20"
              >
                {warnings.map((warning, i) => (
                  <motion.div 
                    key={i} 
                    initial={{ x: -10, opacity: 0 }}
                    animate={{ x: 0, opacity: 1 }}
                    transition={{ delay: i * 0.05 }}
                    className="flex items-start gap-2 text-sm"
                  >
                    <AlertTriangle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
                    <span className="text-destructive">{warning.message}</span>
                  </motion.div>
                ))}
              </motion.div>
            )}
          </AnimatePresence>

          {/* Suggestions with Apply */}
          <AnimatePresence>
            {suggestions.length > 0 && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                className="space-y-2"
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Lightbulb className="w-4 h-4 text-yellow-500" />
                    <span className="text-sm font-medium">Suggestions</span>
                    <Badge variant="secondary" className="text-xs bg-yellow-500/10 text-yellow-600 dark:text-yellow-400">
                      {suggestions.length}
                    </Badge>
                  </div>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={applyAllSuggestions}
                    className="text-xs gap-1.5 text-primary hover:bg-primary/10"
                  >
                    <Zap className="w-3.5 h-3.5" />
                    Apply All
                  </Button>
                </div>

                {suggestions.map((suggestion, i) => (
                  <motion.div
                    key={i}
                    initial={{ x: -10, opacity: 0 }}
                    animate={{ x: 0, opacity: 1 }}
                    transition={{ delay: i * 0.1 }}
                    className="flex items-center justify-between p-3 bg-background/80 backdrop-blur-sm rounded-lg border border-border/50 hover:border-primary/30 transition-colors"
                  >
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-sm font-medium">{suggestion.label}</span>
                        <Badge
                          variant="outline"
                          className={`text-xs ${
                            suggestion.priority === 'high' 
                              ? 'border-destructive/50 text-destructive' 
                              : suggestion.priority === 'medium'
                              ? 'border-amber-500/50 text-amber-600 dark:text-amber-400'
                              : 'border-muted'
                          }`}
                        >
                          {suggestion.priority}
                        </Badge>
                      </div>
                      <p className="text-xs text-muted-foreground line-clamp-2">
                        {suggestion.reason}
                      </p>
                      <div className="flex items-center gap-2 mt-1.5 text-xs">
                        <span className="text-muted-foreground font-mono">{suggestion.currentValue}</span>
                        <ArrowRight className="w-3 h-3 text-muted-foreground" />
                        <span className="text-primary font-mono font-medium">{suggestion.suggestedValue}</span>
                      </div>
                    </div>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => onApplySuggestion(suggestion.field, suggestion.suggestedValue)}
                      className="shrink-0 ml-3 h-8 w-8 p-0 hover:bg-primary/10 hover:text-primary"
                    >
                      <CheckCircle2 className="w-4 h-4" />
                    </Button>
                  </motion.div>
                ))}
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </motion.div>

      {/* Quick Actions */}
      <div className="flex flex-wrap gap-2">
        {quickActions.map((action, i) => (
          <motion.button
            key={i}
            whileHover={{ scale: 1.03 }}
            whileTap={{ scale: 0.97 }}
            onClick={() => handleQuickAction(action.prompt)}
            className="flex items-center gap-1.5 px-3 py-2 rounded-full text-xs font-medium bg-gradient-to-r from-primary/10 to-accent/10 hover:from-primary/20 hover:to-accent/20 border border-primary/20 hover:border-primary/40 transition-all duration-200"
          >
            {action.icon === 'sparkles' && <Sparkles className="w-3 h-3 text-primary" />}
            {action.icon === 'zap' && <Zap className="w-3 h-3 text-accent" />}
            {action.icon === 'trend' && <TrendingUp className="w-3 h-3 text-green-500" />}
            {action.label}
          </motion.button>
        ))}
      </div>

      {/* Chat Section */}
      <div className="rounded-xl border border-border overflow-hidden bg-card">
        <Collapsible open={isChatOpen} onOpenChange={setIsChatOpen}>
          <CollapsibleTrigger asChild>
            <button className="w-full px-4 py-3 flex items-center justify-between text-sm hover:bg-accent/30 transition-colors group">
              <div className="flex items-center gap-2">
                <MessageSquare className="w-4 h-4 text-primary" />
                <span className="font-medium">Chat with AI Engineer</span>
                {chatMessages.length > 0 && (
                  <Badge variant="secondary" className="text-xs">
                    {chatMessages.length}
                  </Badge>
                )}
              </div>
              <motion.div
                animate={{ rotate: isChatOpen ? 180 : 0 }}
                transition={{ duration: 0.2 }}
              >
                <ChevronDown className="w-4 h-4 text-muted-foreground group-hover:text-foreground" />
              </motion.div>
            </button>
          </CollapsibleTrigger>

          <CollapsibleContent>
            <div className="border-t border-border">
              {/* Chat Messages */}
              <ScrollArea className="h-64 px-4 py-3">
                {chatMessages.length === 0 && !streamingContent && (
                  <div className="flex flex-col items-center justify-center h-full text-center text-muted-foreground py-8">
                    <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center mb-3">
                      <Brain className="w-6 h-6 text-primary/60" />
                    </div>
                    <p className="text-sm font-medium mb-1">Ask anything about your design</p>
                    <p className="text-xs">Code compliance, optimization, best practices...</p>
                  </div>
                )}

                <div className="space-y-3">
                  {chatMessages.map((msg, i) => (
                    <motion.div
                      key={i}
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                    >
                      <div
                        className={`max-w-[85%] p-3 rounded-2xl text-sm ${
                          msg.role === 'user'
                            ? 'bg-primary text-primary-foreground rounded-br-md'
                            : 'bg-muted rounded-bl-md'
                        }`}
                      >
                        {msg.content}
                      </div>
                    </motion.div>
                  ))}

                  {streamingContent && (
                    <motion.div
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      className="flex justify-start"
                    >
                      <div className="max-w-[85%] p-3 rounded-2xl rounded-bl-md text-sm bg-muted">
                        {streamingContent}
                        <motion.span 
                          className="inline-block w-1.5 h-4 ml-1 bg-primary rounded-sm"
                          animate={{ opacity: [1, 0, 1] }}
                          transition={{ repeat: Infinity, duration: 0.8 }}
                        />
                      </div>
                    </motion.div>
                  )}
                </div>
                <div ref={chatEndRef} />
              </ScrollArea>

              {/* Chat Input */}
              <div className="p-3 border-t border-border bg-muted/30">
                <form
                  onSubmit={(e) => {
                    e.preventDefault();
                    sendChatMessage(chatInput);
                  }}
                  className="flex gap-2 items-end"
                >
                  <div className="flex-1 relative">
                    <textarea
                      ref={inputRef}
                      value={chatInput}
                      onChange={(e) => setChatInput(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' && !e.shiftKey) {
                          e.preventDefault();
                          sendChatMessage(chatInput);
                        }
                      }}
                      placeholder="Ask about your design..."
                      disabled={isSending}
                      rows={1}
                      className="w-full resize-none bg-background border border-border rounded-xl px-4 py-2.5 text-sm placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 focus:border-primary disabled:opacity-50 transition-all"
                    />
                  </div>
                  <motion.button 
                    type="submit" 
                    disabled={isSending || !chatInput.trim()}
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                    className="h-10 w-10 rounded-xl bg-primary text-primary-foreground flex items-center justify-center disabled:opacity-50 disabled:pointer-events-none hover:bg-primary/90 transition-colors"
                  >
                    {isSending ? (
                      <Loader2 className="w-4 h-4 animate-spin" />
                    ) : (
                      <Send className="w-4 h-4" />
                    )}
                  </motion.button>
                </form>
              </div>
            </div>
          </CollapsibleContent>
        </Collapsible>
      </div>
    </div>
  );
};

import { useState, useEffect, useImperativeHandle, forwardRef } from 'react';
import { motion } from 'framer-motion';
import { Calculator, Info, Loader2, AlertTriangle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { 
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { toast } from 'sonner';
import { cn } from '@/lib/utils';
import { useEngineeringHistory } from '@/hooks/useEngineeringHistory';
import { calculateBeam } from '@/lib/engineeringCalculations';
import { useLanguage } from '@/contexts/LanguageContext';
import { useEngineeringSessionOptional } from '@/contexts/EngineeringSessionContext';
import { beamValidationRules, validateInput, validateAllInputs } from '@/lib/inputValidation';
import { getCodeInfoText } from '@/lib/designValidation';
import { FormError } from '@/components/ui/form-error';

interface BeamCalculatorProps {
  onCalculate: (result: {
    type: 'beam';
    inputs: Record<string, number | string>;
    outputs: Record<string, number | string | object>;
    timestamp: Date;
  }) => void;
  isCalculating: boolean;
  setIsCalculating: (value: boolean) => void;
  userId?: string;
  onReset?: () => void;
  onInputChange?: (inputs: Record<string, any>) => void;
}

export interface BeamCalculatorRef {
  reset: () => void;
}

const defaultFormData = {
  span: '6.0',
  deadLoad: '15.0',
  liveLoad: '10.0',
  beamWidth: '300',
  concreteGrade: 'C30',
  steelGrade: 'Fy420',
  supportType: 'simply_supported',
  exposureClass: 'XC1',
};

const concreteGrades = [
  { value: 'C25', fck: 25, label: 'C25 (25 MPa)' },
  { value: 'C30', fck: 30, label: 'C30 (30 MPa)' },
  { value: 'C35', fck: 35, label: 'C35 (35 MPa)' },
  { value: 'C40', fck: 40, label: 'C40 (40 MPa)' },
];

const steelGrades = [
  { value: 'Fy420', fy: 420, label: 'Fy420 (420 MPa)' },
  { value: 'Fy500', fy: 500, label: 'Fy500 (500 MPa)' },
];

const supportTypes = [
  { value: 'simply_supported', label: 'Simply Supported', momentFactor: 8 },
  { value: 'continuous', label: 'Continuous (Interior)', momentFactor: 10 },
  { value: 'cantilever', label: 'Cantilever', momentFactor: 2 },
];

export const BeamCalculator = forwardRef<BeamCalculatorRef, BeamCalculatorProps>(
  ({ onCalculate, isCalculating, setIsCalculating, userId, onReset, onInputChange }, ref) => {
  const { t } = useLanguage();
  const { saveCalculation } = useEngineeringHistory(userId);
  const session = useEngineeringSessionOptional();
  const buildingCode = session?.buildingCode || 'ACI';

  const [formData, setFormData] = useState(defaultFormData);
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Expose reset method via ref
  useImperativeHandle(ref, () => ({
    reset: () => {
      setFormData(defaultFormData);
      setErrors({});
      onReset?.();
    },
  }));

  // Sync inputs to parent on mount and when formData changes
  useEffect(() => {
    const inputs = {
      span: parseFloat(formData.span) || 0,
      deadLoad: parseFloat(formData.deadLoad) || 0,
      liveLoad: parseFloat(formData.liveLoad) || 0,
      beamWidth: parseFloat(formData.beamWidth) || 0,
      concreteGrade: formData.concreteGrade,
      steelGrade: formData.steelGrade,
      supportType: formData.supportType,
      exposureClass: formData.exposureClass,
      buildingCode,
    };
    onInputChange?.(inputs);
  }, [formData, buildingCode, onInputChange]);

  // Get dynamic code info
  const codeInfo = getCodeInfoText(buildingCode);

  const handleInputChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));

    // Real-time validation
    const rule = beamValidationRules[field];
    if (rule && value !== '') {
      const result = validateInput(value, rule);
      setErrors(prev => {
        if (result.isValid) {
          const { [field]: _, ...rest } = prev;
          return rest;
        }
        return { ...prev, [field]: result.error || '' };
      });
    }
  };

  const handleCalculate = async () => {
    // Validate all inputs
    const allErrors = validateAllInputs(formData, beamValidationRules);
    if (Object.keys(allErrors).length > 0) {
      setErrors(allErrors);
      toast.error('Please fix validation errors before calculating');
      return;
    }

    const span = parseFloat(formData.span);
    const deadLoad = parseFloat(formData.deadLoad);
    const liveLoad = parseFloat(formData.liveLoad);
    const beamWidth = parseFloat(formData.beamWidth);

    if (isNaN(span) || span <= 0) {
      toast.error(t('error.invalidInputDesc'));
      return;
    }

    setIsCalculating(true);

    try {
      // Client-side calculation with building code
      const data = calculateBeam({
        span,
        deadLoad,
        liveLoad,
        beamWidth,
        concreteGrade: formData.concreteGrade,
        steelGrade: formData.steelGrade,
        supportType: formData.supportType,
        buildingCode,
      });

      const inputs = {
        span,
        deadLoad,
        liveLoad,
        beamWidth,
        concreteGrade: formData.concreteGrade,
        steelGrade: formData.steelGrade,
        supportType: formData.supportType,
        exposureClass: formData.exposureClass,
        buildingCode,
      };

      // Save to history (non-blocking)
      saveCalculation('beam', inputs, data);

      onCalculate({
        type: 'beam',
        inputs,
        outputs: data as unknown as Record<string, number | string | object>,
        timestamp: new Date(),
      });

      toast.success(t('common.success'));
    } catch (err) {
      if (import.meta.env.DEV) {
        console.error('Calculation error:', err);
      }
      toast.error(t('error.calculationFailedDesc'));
    } finally {
      setIsCalculating(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="bg-card rounded-2xl border border-border p-6 shadow-lg"
      >
        <div className="flex items-center gap-3 mb-6">
          <div className="p-3 rounded-xl bg-gradient-to-br from-blue-500 to-cyan-500 text-white">
            <Calculator className="w-6 h-6" />
          </div>
          <div>
            <h2 className="text-xl font-bold">Beam Design Calculator</h2>
            <p className="text-sm text-muted-foreground">Reinforced Concrete Beam Design</p>
          </div>
        </div>

        <div className="space-y-6">
          {/* Geometry Section */}
          <div className="space-y-4">
            <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">
              Geometry
            </h3>
            <div className="grid md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="span">Span Length (m)</Label>
                <Input
                  id="span"
                  type="number"
                  placeholder="e.g., 6.0"
                  value={formData.span}
                  onChange={(e) => handleInputChange('span', e.target.value)}
                  step="0.1"
                  min="0.5"
                  max="30"
                  className={errors.span ? 'border-destructive' : ''}
                />
                <FormError message={errors.span} />
              </div>
              <div className="space-y-2">
                <Label htmlFor="beamWidth">Beam Width (mm)</Label>
                <Input
                  id="beamWidth"
                  type="number"
                  placeholder="e.g., 300"
                  value={formData.beamWidth}
                  onChange={(e) => handleInputChange('beamWidth', e.target.value)}
                  step="25"
                  min="150"
                  max="2000"
                  className={errors.beamWidth ? 'border-destructive' : ''}
                />
                <FormError message={errors.beamWidth} />
              </div>
            </div>
          </div>

          {/* Loads Section */}
          <div className="space-y-4">
            <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">
              Applied Loads
            </h3>
            <div className="grid md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="deadLoad">Dead Load (kN/m)</Label>
                <Input
                  id="deadLoad"
                  type="number"
                  placeholder="e.g., 15.0"
                  value={formData.deadLoad}
                  onChange={(e) => handleInputChange('deadLoad', e.target.value)}
                  step="0.5"
                  min="0"
                  max="500"
                  className={errors.deadLoad ? 'border-destructive' : ''}
                />
                <FormError message={errors.deadLoad} />
              </div>
              <div className="space-y-2">
                <Label htmlFor="liveLoad">Live Load (kN/m)</Label>
                <Input
                  id="liveLoad"
                  type="number"
                  placeholder="e.g., 10.0"
                  value={formData.liveLoad}
                  onChange={(e) => handleInputChange('liveLoad', e.target.value)}
                  step="0.5"
                  min="0"
                  max="500"
                  className={errors.liveLoad ? 'border-destructive' : ''}
                />
                <FormError message={errors.liveLoad} />
              </div>
            </div>
          </div>

          {/* Materials Section */}
          <div className="space-y-4">
            <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">
              Materials
            </h3>
            <div className="grid md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Concrete Grade</Label>
                <Select value={formData.concreteGrade} onValueChange={(v) => handleInputChange('concreteGrade', v)}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {concreteGrades.map((grade) => (
                      <SelectItem key={grade.value} value={grade.value}>
                        {grade.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Steel Grade</Label>
                <Select value={formData.steelGrade} onValueChange={(v) => handleInputChange('steelGrade', v)}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {steelGrades.map((grade) => (
                      <SelectItem key={grade.value} value={grade.value}>
                        {grade.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
          </div>

          {/* Support Conditions */}
          <div className="space-y-4">
            <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">
              Support Conditions
            </h3>
            <div className="space-y-2">
              <Label>Support Type</Label>
              <Select value={formData.supportType} onValueChange={(v) => handleInputChange('supportType', v)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {supportTypes.map((type) => (
                    <SelectItem key={type.value} value={type.value}>
                      {type.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          {/* Info Box - Dynamic based on building code */}
          <div className={cn(
            "flex items-start gap-3 p-4 rounded-xl",
            buildingCode === 'CSA' 
              ? "bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-800"
              : "bg-blue-50 dark:bg-blue-950/30 border border-blue-200 dark:border-blue-800"
          )}>
            <Info className={cn(
              "w-5 h-5 shrink-0 mt-0.5",
              buildingCode === 'CSA' ? "text-red-500" : "text-blue-500"
            )} />
            <div className={cn(
              "text-sm",
              buildingCode === 'CSA' ? "text-red-700 dark:text-red-300" : "text-blue-700 dark:text-blue-300"
            )}>
              <p className="font-medium mb-1">Calculation Method: {codeInfo.name}</p>
              <p className={buildingCode === 'CSA' ? "text-red-600 dark:text-red-400" : "text-blue-600 dark:text-blue-400"}>
                Load factors: {codeInfo.factors} • Resistance: {codeInfo.phi}
              </p>
              {buildingCode === 'CSA' && (
                <p className="text-xs mt-1 flex items-center gap-1">
                  <AlertTriangle className="w-3 h-3" />
                  {codeInfo.note}
                </p>
              )}
            </div>
          </div>

          {/* Calculate Button */}
          <Button
            onClick={handleCalculate}
            disabled={isCalculating || Object.keys(errors).length > 0}
            className="w-full h-12 text-lg font-semibold bg-gradient-to-r from-blue-500 to-cyan-500 hover:from-blue-600 hover:to-cyan-600"
          >
            {isCalculating ? (
              <>
                <Loader2 className="w-5 h-5 mr-2 animate-spin" />
                Calculating...
              </>
            ) : (
              <>
                <Calculator className="w-5 h-5 mr-2" />
                Calculate Beam Design
              </>
            )}
          </Button>
        </div>
      </motion.div>
    </div>
  );
});

BeamCalculator.displayName = 'BeamCalculator';

import React, { useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Calculator, Building2, Box, Mountain, Trash2, Clock, ArrowRight, Layers, Blocks, Car } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import { useEngineeringHistory, CalculationHistoryItem } from '@/hooks/useEngineeringHistory';
import { format } from 'date-fns';
import { cn } from '@/lib/utils';

interface CalculationHistoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string | undefined;
  onLoadCalculation?: (calculation: CalculationHistoryItem) => void;
}

const typeConfig: Record<string, { icon: React.ElementType; color: string; label: string }> = {
  beam: { icon: Calculator, color: 'from-blue-500 to-cyan-500', label: 'Beam Design' },
  foundation: { icon: Building2, color: 'from-amber-500 to-orange-500', label: 'Foundation Design' },
  column: { icon: Box, color: 'from-purple-500 to-pink-500', label: 'Column Design' },
  slab: { icon: Layers, color: 'from-green-500 to-emerald-500', label: 'Slab Design' },
  retaining_wall: { icon: Blocks, color: 'from-stone-500 to-slate-500', label: 'Retaining Wall' },
  parking: { icon: Car, color: 'from-violet-500 to-indigo-500', label: 'Parking Layout' },
  grading: { icon: Mountain, color: 'from-emerald-500 to-teal-500', label: 'Grading Design' },
};

export const CalculationHistoryModal: React.FC<CalculationHistoryModalProps> = ({
  isOpen,
  onClose,
  userId,
  onLoadCalculation,
}) => {
  const { calculationHistory, isLoading, fetchHistory, deleteCalculation } = useEngineeringHistory(userId);

  useEffect(() => {
    if (isOpen && userId) {
      fetchHistory();
    }
  }, [isOpen, userId, fetchHistory]);

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    await deleteCalculation(id);
  };

  const getTypeInfo = (type: string) => {
    return typeConfig[type] || { icon: Calculator, color: 'from-gray-500 to-gray-600', label: type };
  };

  const formatInputs = (inputs: Record<string, any>, type: string) => {
    switch (type) {
      case 'beam':
        return `${inputs.span || 0}m span, ${(inputs.deadLoad || 0) + (inputs.liveLoad || 0)} kN/m`;
      case 'foundation':
        return `${inputs.columnLoad || 0} kN load, ${inputs.soilType || 'standard'} soil`;
      case 'column':
        return `${inputs.axialLoad || 0} kN, ${inputs.columnWidth || 0}x${inputs.columnDepth || 0}mm`;
      case 'slab':
        return `${inputs.longSpan || 0}x${inputs.shortSpan || 0}m, ${(inputs.deadLoad || 0) + (inputs.liveLoad || 0)} kN/m²`;
      case 'retaining_wall':
        return `${inputs.wallHeight || 0}m height, ${inputs.soilType || 'standard'} soil`;
      case 'parking':
        return `${inputs.siteLength || 0}x${inputs.siteWidth || 0}m site, ${inputs.floors || 1} floor(s)`;
      case 'grading':
        return `${inputs.pointCount || inputs.surveyPoints?.length || '?'} survey points`;
      default:
        return 'Custom design';
    }
  };

  const formatOutputs = (outputs: Record<string, any>, type: string) => {
    switch (type) {
      case 'beam':
        return `${outputs.beamWidth || 0}x${outputs.totalDepth || 0}mm`;
      case 'foundation':
        return `${outputs.length || 0}x${outputs.width || 0}m, ${outputs.depth || 0}mm`;
      case 'column':
        return `${outputs.requiredSteelArea?.toFixed(0) || '?'}mm² steel`;
      case 'slab':
        return `${outputs.slabThickness || outputs.thickness || '?'}mm thick`;
      case 'retaining_wall':
        return `Base: ${outputs.baseWidth || '?'}mm`;
      case 'parking':
        return `${outputs.totalSpaces || outputs.layout?.totalSpaces || '?'} spaces`;
      case 'grading':
        return `Cut: ${outputs.totalCutVolume?.toLocaleString() || '?'}m³`;
      default:
        return '';
    }
  };

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4"
        onClick={onClose}
      >
        <motion.div
          initial={{ scale: 0.95, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          exit={{ scale: 0.95, opacity: 0 }}
          onClick={(e) => e.stopPropagation()}
          className="bg-card border border-border rounded-2xl shadow-2xl w-full max-w-2xl max-h-[80vh] overflow-hidden"
        >
          {/* Header */}
          <div className="flex items-center justify-between p-4 border-b border-border">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-xl bg-gradient-to-br from-primary/20 to-primary/10">
                <Clock className="w-5 h-5 text-primary" />
              </div>
              <div>
                <h2 className="text-lg font-bold">Calculation History</h2>
                <p className="text-sm text-muted-foreground">
                  {calculationHistory.length} saved calculations
                </p>
              </div>
            </div>
            <Button variant="ghost" size="icon" onClick={onClose}>
              <X className="w-5 h-5" />
            </Button>
          </div>

          {/* Content */}
          <ScrollArea className="h-[60vh]">
            <div className="p-4 space-y-3">
              {isLoading ? (
                <div className="flex items-center justify-center py-12">
                  <div className="animate-spin rounded-full h-8 w-8 border-2 border-primary border-t-transparent" />
                </div>
              ) : calculationHistory.length === 0 ? (
                <div className="text-center py-12">
                  <Calculator className="w-12 h-12 mx-auto text-muted-foreground/50 mb-4" />
                  <p className="text-muted-foreground">No calculations saved yet</p>
                  <p className="text-sm text-muted-foreground/70 mt-1">
                    Your beam, foundation, and column calculations will appear here
                  </p>
                </div>
              ) : (
                calculationHistory.map((calc) => {
                  const typeInfo = getTypeInfo(calc.calculation_type);
                  const Icon = typeInfo.icon;

                  return (
                    <motion.div
                      key={calc.id}
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      className={cn(
                        "group relative p-4 rounded-xl border border-border bg-card/50",
                        "hover:bg-card hover:border-primary/30 transition-all cursor-pointer"
                      )}
                      onClick={() => onLoadCalculation?.(calc)}
                    >
                      <div className="flex items-start gap-3">
                        <div className={cn(
                          "w-10 h-10 rounded-lg flex items-center justify-center shrink-0",
                          `bg-gradient-to-br ${typeInfo.color}`
                        )}>
                          <Icon className="w-5 h-5 text-white" />
                        </div>

                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 mb-1">
                            <span className="font-medium">{typeInfo.label}</span>
                            <span className="text-xs text-muted-foreground">
                              {format(new Date(calc.created_at), 'MMM d, yyyy · HH:mm')}
                            </span>
                          </div>
                          <p className="text-sm text-muted-foreground">
                            {formatInputs(calc.inputs, calc.calculation_type)}
                          </p>
                          <p className="text-sm font-medium text-primary mt-1">
                            {formatOutputs(calc.outputs, calc.calculation_type)}
                          </p>
                        </div>

                        <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-8 w-8 text-destructive hover:text-destructive"
                            onClick={(e) => handleDelete(e, calc.id)}
                          >
                            <Trash2 className="w-4 h-4" />
                          </Button>
                          <ArrowRight className="w-4 h-4 text-muted-foreground" />
                        </div>
                      </div>
                    </motion.div>
                  );
                })
              )}
            </div>
          </ScrollArea>
        </motion.div>
      </motion.div>
    </AnimatePresence>
  );
};

import React, { useState, forwardRef, useImperativeHandle, useEffect, lazy, Suspense } from 'react';
import { motion } from 'framer-motion';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Calculator, Loader2, Info, AlertTriangle } from 'lucide-react';
import { toast } from 'sonner';

const ColumnVisualization3D = lazy(() => import('./ColumnVisualization3D'));
import { useEngineeringHistory } from '@/hooks/useEngineeringHistory';
import { calculateColumn } from '@/lib/engineeringCalculations';
import { useLanguage } from '@/contexts/LanguageContext';
import { columnValidationRules, validateField, hasErrors } from '@/lib/inputValidation';
import { useEngineeringSessionOptional } from '@/contexts/EngineeringSessionContext';
import { cn } from '@/lib/utils';
import type { BuildingCodeId } from '@/lib/buildingCodes/types';

interface ColumnCalculatorProps {
  onCalculate: (result: any) => void;
  isCalculating: boolean;
  setIsCalculating: (value: boolean) => void;
  userId?: string;
  onInputChange?: (inputs: Record<string, any>) => void;
  resetKey?: number;
}

const getDefaultInputs = () => ({
  axialLoad: 1500,
  momentX: 80,
  momentY: 60,
  columnWidth: 400,
  columnDepth: 400,
  columnHeight: 3500,
  concreteGrade: 'C30',
  steelGrade: '420',
  coverThickness: 40,
  columnType: 'tied',
  slendernessCheck: true
});

// Helper component for form errors
const FormError = ({ message }: { message?: string }) => {
  if (!message) return null;
  return <p className="text-destructive text-xs mt-1">{message}</p>;
};

// Get code-specific info
const getCodeInfo = (buildingCode: BuildingCodeId) => {
  if (buildingCode === 'CSA') {
    return {
      name: 'CSA A23.3-24 / NBCC 2020',
      factors: '1.25D + 1.5L',
      phi: 'φc = 0.65',
      isCSA: true,
    };
  }
  return {
    name: 'ACI 318-25 / ASCE 7-22',
    factors: '1.2D + 1.6L',
    phi: 'φ = 0.65 (compression)',
    isCSA: false,
  };
};

export interface ColumnCalculatorRef {
  reset: () => void;
}

const ColumnCalculator = forwardRef<ColumnCalculatorRef, ColumnCalculatorProps>(({ 
  onCalculate, 
  isCalculating, 
  setIsCalculating, 
  userId,
  onInputChange,
  resetKey
}, ref) => {
  const { t } = useLanguage();
  const { saveCalculation } = useEngineeringHistory(userId);
  const session = useEngineeringSessionOptional();
  const buildingCode: BuildingCodeId = (session?.buildingCode as BuildingCodeId) || 'ACI';
  const codeInfo = getCodeInfo(buildingCode);

  const [inputs, setInputs] = useState(getDefaultInputs());
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Reset form when resetKey changes
  useEffect(() => {
    if (resetKey !== undefined) {
      setInputs(getDefaultInputs());
      setErrors({});
    }
  }, [resetKey]);

  // Expose reset method via ref
  useImperativeHandle(ref, () => ({
    reset: () => {
      setInputs(getDefaultInputs());
      setErrors({});
    }
  }));

  const handleInputChange = (field: string, value: string | number | boolean) => {
    const newInputs = { ...inputs, [field]: value };
    setInputs(newInputs);
    onInputChange?.(newInputs);

    // Validate numeric fields
    if (typeof value === 'number') {
      const rule = columnValidationRules[field];
      if (rule) {
        const error = validateField(value, rule);
        setErrors(prev => {
          if (error) {
            return { ...prev, [field]: error };
          }
          const { [field]: _, ...rest } = prev;
          return rest;
        });
      }
    }
  };

  const validateAllInputs = (): boolean => {
    const newErrors: Record<string, string> = {};

    Object.entries(columnValidationRules).forEach(([field, rule]) => {
      const value = inputs[field as keyof typeof inputs];
      if (typeof value === 'number') {
        const error = validateField(value, rule);
        if (error) newErrors[field] = error;
      }
    });

    setErrors(newErrors);
    return !hasErrors(newErrors);
  };

  const handleCalculate = async () => {
    if (!validateAllInputs()) {
      toast.error(t('error.invalidInputDesc'));
      return;
    }

    setIsCalculating(true);
    try {
      // Client-side calculation with building code
      const data = calculateColumn({
        axialLoad: inputs.axialLoad,
        momentX: inputs.momentX,
        momentY: inputs.momentY,
        columnWidth: inputs.columnWidth,
        columnDepth: inputs.columnDepth,
        columnHeight: inputs.columnHeight,
        concreteGrade: inputs.concreteGrade,
        steelGrade: inputs.steelGrade,
        coverThickness: inputs.coverThickness,
        columnType: inputs.columnType,
      }, buildingCode);

      // Save to history (non-blocking)
      saveCalculation('column', { ...inputs, buildingCode }, data);

      onCalculate({
        type: 'column',
        inputs: { ...inputs, buildingCode },
        outputs: data,
        timestamp: new Date()
      });

      toast.success(t('common.success'));
    } catch (error) {
      if (import.meta.env.DEV) {
        console.error('Calculation error:', error);
      }
      toast.error(t('error.calculationFailedDesc'));
    } finally {
      setIsCalculating(false);
    }
  };

  return (
    <motion.div
