import React, { useMemo, useState } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Text, PerspectiveCamera } from '@react-three/drei';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Eye, Layers, Mountain } from 'lucide-react';
import * as THREE from 'three';

interface Point {
  id: string;
  x: number;
  y: number;
  z: number;
  fgl?: number;
  cutFill?: number;
}

interface TerrainVisualization3DProps {
  points: Point[];
  showFGL: boolean;
}

type ViewMode = 'ngl' | 'fgl' | 'cutfill';

const TerrainMesh: React.FC<{ points: Point[]; viewMode: ViewMode; bounds: any }> = ({ 
  points, 
  viewMode,
  bounds 
}) => {
  const meshData = useMemo(() => {
    if (points.length < 3) return null;

    // Normalize coordinates
    const normalizedPoints = points.map(p => ({
      ...p,
      nx: (p.x - bounds.minX) / bounds.rangeX - 0.5,
      ny: (p.y - bounds.minY) / bounds.rangeY - 0.5,
      nz: ((viewMode === 'fgl' && p.fgl !== undefined ? p.fgl : p.z) - bounds.minZ) / bounds.rangeZ,
    }));

    // Create geometry from points
    const geometry = new THREE.BufferGeometry();
    const vertices: number[] = [];
    const colors: number[] = [];

    // Simple point cloud with color gradient
    normalizedPoints.forEach(p => {
      vertices.push(p.nx * 10, p.nz * 3, p.ny * 10);

      // Color based on view mode
      let color: THREE.Color;
      if (viewMode === 'cutfill' && p.cutFill !== undefined) {
        if (p.cutFill > 0) {
          // Cut - red gradient
          const intensity = Math.min(1, p.cutFill / 3);
          color = new THREE.Color().setHSL(0, 0.8, 0.5 + intensity * 0.3);
        } else {
          // Fill - yellow gradient
          const intensity = Math.min(1, Math.abs(p.cutFill) / 3);
          color = new THREE.Color().setHSL(0.15, 0.9, 0.5 + intensity * 0.3);
        }
      } else {
        // Elevation gradient (green to brown)
        const t = p.nz;
        color = new THREE.Color().setHSL(0.15 - t * 0.1, 0.6, 0.4 + t * 0.2);
      }

      colors.push(color.r, color.g, color.b);
    });

    geometry.setAttribute('position', new THREE.Float32BufferAttribute(vertices, 3));
    geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));

    return geometry;
  }, [points, viewMode, bounds]);

  if (!meshData) return null;

  return (
    <points geometry={meshData}>
      <pointsMaterial size={0.15} vertexColors />
    </points>
  );
};

const GridFloor: React.FC = () => (
  <gridHelper args={[20, 20, '#444', '#333']} rotation={[0, 0, 0]} position={[0, -0.5, 0]} />
);

const AxisLabels: React.FC = () => (
  <>
    <Text position={[6, 0, 0]} fontSize={0.4} color="#888">E →</Text>
    <Text position={[0, 0, 6]} fontSize={0.4} color="#888">N →</Text>
    <Text position={[0, 2, 0]} fontSize={0.4} color="#888">↑ Elev</Text>
  </>
);

export const TerrainVisualization3D: React.FC<TerrainVisualization3DProps> = ({ 
  points,
  showFGL 
}) => {
  const [viewMode, setViewMode] = useState<ViewMode>('ngl');

  const bounds = useMemo(() => {
    if (points.length === 0) return { minX: 0, maxX: 1, minY: 0, maxY: 1, minZ: 0, maxZ: 1, rangeX: 1, rangeY: 1, rangeZ: 1 };

    const xs = points.map(p => p.x);
    const ys = points.map(p => p.y);
    const zs = points.map(p => p.z);
    const fgls = points.filter(p => p.fgl !== undefined).map(p => p.fgl!);

    const allZs = [...zs, ...fgls];

    const minX = Math.min(...xs);
    const maxX = Math.max(...xs);
    const minY = Math.min(...ys);
    const maxY = Math.max(...ys);
    const minZ = Math.min(...allZs);
    const maxZ = Math.max(...allZs);

    return {
      minX, maxX, minY, maxY, minZ, maxZ,
      rangeX: maxX - minX || 1,
      rangeY: maxY - minY || 1,
      rangeZ: maxZ - minZ || 1,
    };
  }, [points]);

  const hasFGLData = points.some(p => p.fgl !== undefined);

  return (
    <Card className="p-4">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-lg font-semibold flex items-center gap-2">
          <Mountain className="w-5 h-5 text-primary" />
          3D Terrain View
        </h3>

        <div className="flex gap-2">
          <Button
            variant={viewMode === 'ngl' ? 'default' : 'outline'}
            size="sm"
            onClick={() => setViewMode('ngl')}
          >
            <Layers className="w-4 h-4 mr-1" />
            NGL
          </Button>
          {hasFGLData && (
            <>
              <Button
                variant={viewMode === 'fgl' ? 'default' : 'outline'}
                size="sm"
                onClick={() => setViewMode('fgl')}
              >
                <Layers className="w-4 h-4 mr-1" />
                FGL
              </Button>
              <Button
                variant={viewMode === 'cutfill' ? 'default' : 'outline'}
                size="sm"
                onClick={() => setViewMode('cutfill')}
              >
                <Eye className="w-4 h-4 mr-1" />
                Cut/Fill
              </Button>
            </>
          )}
        </div>
      </div>

      <div className="h-[400px] bg-gradient-to-b from-slate-900 to-slate-800 rounded-lg overflow-hidden">
        {points.length > 0 ? (
          <Canvas>
            <PerspectiveCamera makeDefault position={[8, 6, 8]} />
            <OrbitControls enableDamping dampingFactor={0.1} />
            <ambientLight intensity={0.5} />
            <directionalLight position={[10, 10, 5]} intensity={1} />
            <TerrainMesh points={points} viewMode={viewMode} bounds={bounds} />
            <GridFloor />
            <AxisLabels />
          </Canvas>
        ) : (
          <div className="h-full flex items-center justify-center text-muted-foreground">
            Upload survey data to view 3D terrain
          </div>
        )}
      </div>

      {viewMode === 'cutfill' && hasFGLData && (
        <div className="mt-3 flex items-center justify-center gap-6 text-sm">
          <div className="flex items-center gap-2">
            <div className="w-4 h-4 rounded bg-red-500" />
            <span>Cut Area</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-4 h-4 rounded bg-yellow-500" />
            <span>Fill Area</span>
          </div>
        </div>
      )}
    </Card>
  );
};

import { useState, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

export interface ComplianceProject {
  id?: string;
  user_id: string;
  project_name: string;
  location_country: string;
  location_state_province: string;
  location_city: string;
  location_zip_postal: string;
  code_system: string;
  climate_zone_id?: string;
  building_type: string;
  num_storeys: number;
  has_basement: boolean;
  has_garage: boolean;
  garage_attached: boolean;
  has_fuel_burning_appliance: boolean;
}

export function useComplianceProject(userId: string) {
  const [project, setProject] = useState<ComplianceProject>({
    user_id: userId,
    project_name: '',
    location_country: 'US',
    location_state_province: '',
    location_city: '',
    location_zip_postal: '',
    code_system: 'IRC_2024',
    building_type: 'single_family',
    num_storeys: 1,
    has_basement: false,
    has_garage: false,
    garage_attached: false,
    has_fuel_burning_appliance: false,
  });

  const [saving, setSaving] = useState(false);

  const updateProject = useCallback((updates: Partial<ComplianceProject>) => {
    setProject(prev => {
      const next = { ...prev, ...updates };
      // Auto-select code system based on country
      if (updates.location_country === 'US') next.code_system = 'IRC_2024';
      if (updates.location_country === 'CA') next.code_system = 'NBC_2025';
      return next;
    });
  }, []);

  const saveProject = useCallback(async () => {
    setSaving(true);
    try {
      const { data, error } = await supabase
        .from('compliance_projects')
        .insert(project as any)
        .select()
        .single();

      if (error) throw error;
      setProject(prev => ({ ...prev, id: (data as any).id }));
      toast.success('Project saved');
      return (data as any).id as string;
    } catch (err) {
      toast.error('Failed to save project');
      return null;
    } finally {
      setSaving(false);
    }
  }, [project]);

  return { project, updateProject, saveProject, saving };
}

import { useState, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import type { ComplianceInput } from '../utils/complianceEngine';
import { toast } from 'sonner';

export interface ExtractedInput extends ComplianceInput {
  confidence: number;
}

interface AnalysisResult {
  inputs: ExtractedInput[];
  notes: string;
  storeys_detected: number;
}

type AnalysisPhase = 'idle' | 'uploading' | 'analyzing' | 'extracting' | 'done' | 'error';

const ACCEPTED_TYPES = ['application/pdf', 'image/png', 'image/jpeg', 'image/jpg'];
const MAX_SIZE = 10 * 1024 * 1024; // 10MB

export function useFloorPlanAnalysis() {
  const [phase, setPhase] = useState<AnalysisPhase>('idle');
  const [extractedInputs, setExtractedInputs] = useState<ExtractedInput[]>([]);
  const [notes, setNotes] = useState('');
  const [storeysDetected, setStoreysDetected] = useState(1);
  const [error, setError] = useState<string | null>(null);
  const [fileName, setFileName] = useState('');

  const validateFile = useCallback((file: File): string | null => {
    if (!ACCEPTED_TYPES.includes(file.type)) {
      return 'Please upload a PDF, PNG, or JPG file.';
    }
    if (file.size > MAX_SIZE) {
      return 'File size must be under 10MB.';
    }
    return null;
  }, []);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const result = reader.result as string;
        // Strip data URL prefix to get raw base64
        const base64 = result.split(',')[1];
        resolve(base64);
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const analyzeFile = useCallback(async (file: File, unitSystem: string, codeSystem: string) => {
    const validationError = validateFile(file);
    if (validationError) {
      toast.error(validationError);
      return;
    }

    setError(null);
    setFileName(file.name);
    setPhase('uploading');

    try {
      setPhase('uploading');
      const base64 = await fileToBase64(file);

      setPhase('analyzing');
      const { data, error: fnError } = await supabase.functions.invoke('analyze-floor-plan', {
        body: {
          file_base64: base64,
          file_type: file.type,
          unit_system: unitSystem,
          code_system: codeSystem,
        },
      });

      if (fnError) throw new Error(fnError.message || 'Analysis failed');
      if (data?.error) throw new Error(data.error);

      setPhase('extracting');
      const result = data as AnalysisResult;
      setExtractedInputs(result.inputs || []);
      setNotes(result.notes || '');
      setStoreysDetected(result.storeys_detected || 1);
      setPhase('done');

      toast.success(`Extracted ${result.inputs?.length || 0} items from your floor plan`);
    } catch (e: any) {
      console.error('Floor plan analysis error:', e);
      setError(e.message || 'Failed to analyze floor plan');
      setPhase('error');
      toast.error(e.message || 'Failed to analyze floor plan');
    }
  }, [validateFile]);

  const updateInput = useCallback((index: number, updates: Partial<ExtractedInput>) => {
    setExtractedInputs(prev => prev.map((item, i) => i === index ? { ...item, ...updates } : item));
  }, []);

  const removeInput = useCallback((index: number) => {
    setExtractedInputs(prev => prev.filter((_, i) => i !== index));
  }, []);

  const addInput = useCallback((input: ExtractedInput) => {
    setExtractedInputs(prev => [...prev, input]);
  }, []);

  const reset = useCallback(() => {
    setPhase('idle');
    setExtractedInputs([]);
    setNotes('');
    setStoreysDetected(1);
    setError(null);
    setFileName('');
  }, []);

  // Convert ExtractedInput[] to ComplianceInput[] (strip confidence)
  const getComplianceInputs = useCallback((): ComplianceInput[] => {
    return extractedInputs.map(({ confidence, ...rest }) => rest);
  }, [extractedInputs]);

  return {
    phase,
    extractedInputs,
    notes,
    storeysDetected,
    error,
    fileName,
    analyzeFile,
    updateInput,
    removeInput,
    addInput,
    reset,
    getComplianceInputs,
    validateFile,
  };
}

