export const DesignUploadStep: React.FC<Props> = ({
  phase, extractedInputs, notes, error, fileName,
  onFileSelected, onUpdateInput, onRemoveInput, onAddInput,
  onConfirm, onReUpload, onSwitchToManual, unitSystem,
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragOver, setIsDragOver] = useState(false);

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
    const file = e.dataTransfer.files[0];
    if (file) onFileSelected(file);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) onFileSelected(file);
  };

  // Upload zone
  if (phase === 'idle' || phase === 'error') {
    return (
      <div className="space-y-4">
        <div
          className={cn(
            "border-2 border-dashed rounded-xl p-12 transition-all duration-300 cursor-pointer",
            isDragOver
              ? "border-primary bg-primary/5 scale-[1.02]"
              : "border-muted-foreground/25 hover:border-primary/50 hover:bg-muted/50"
          )}
          onDragEnter={(e) => { e.preventDefault(); setIsDragOver(true); }}
          onDragLeave={(e) => { e.preventDefault(); setIsDragOver(false); }}
          onDragOver={(e) => e.preventDefault()}
          onDrop={handleDrop}
          onClick={() => fileInputRef.current?.click()}
        >
          <div className="flex flex-col items-center text-center space-y-4">
            <div className={cn(
              "w-16 h-16 rounded-full flex items-center justify-center transition-colors",
              isDragOver ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground"
            )}>
              <Upload className="w-8 h-8" />
            </div>
            <div>
              <h3 className="text-lg font-semibold">Upload Your Floor Plan</h3>
              <p className="text-sm text-muted-foreground max-w-md mt-1">
                Drop your floor plan here — AYN will read it and extract all measurements automatically
              </p>
            </div>
            <div className="text-xs text-muted-foreground">
              <p>PDF, PNG, JPG • Max 10MB</p>
            </div>
            <Button variant="outline" onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}>
              <FileText className="w-4 h-4 mr-2" /> Browse Files
            </Button>
          </div>
        </div>

        <input ref={fileInputRef} type="file" className="hidden" accept=".pdf,.png,.jpg,.jpeg" onChange={handleFileChange} />

        {error && (
          <div className="flex items-center gap-2 text-destructive text-sm p-3 bg-destructive/10 rounded-lg">
            <AlertTriangle className="w-4 h-4 shrink-0" />
            {error}
          </div>
        )}

        <button
          onClick={onSwitchToManual}
          className="text-xs text-muted-foreground hover:text-primary underline block mx-auto transition-colors"
        >
          Don't have drawings? Enter measurements manually →
        </button>
      </div>
    );
  }

  // Analyzing state
  if (phase === 'uploading' || phase === 'analyzing' || phase === 'extracting') {
    const progressValue = phase === 'uploading' ? 20 : phase === 'analyzing' ? 60 : 90;
    const label = phase === 'uploading' ? 'Uploading...' : phase === 'analyzing' ? 'AYN is reading your floor plan...' : 'Extracting data...';

    return (
      <div className="flex flex-col items-center py-16 space-y-6">
        <motion.div
          animate={{ rotate: 360 }}
          transition={{ duration: 2, repeat: Infinity, ease: "linear" }}
        >
          <Loader2 className="w-12 h-12 text-primary" />
        </motion.div>
        <p className="text-lg font-medium">{label}</p>
        <p className="text-sm text-muted-foreground">{fileName}</p>
        <Progress value={progressValue} className="w-64" indicatorClassName="bg-gradient-to-r from-teal-500 to-cyan-500" />
        <div className="flex gap-6 text-xs text-muted-foreground">
          {['Uploading', 'Analyzing', 'Extracting'].map((s, i) => {
            const active = i === (phase === 'uploading' ? 0 : phase === 'analyzing' ? 1 : 2);
            const done = i < (phase === 'uploading' ? 0 : phase === 'analyzing' ? 1 : 2);
            return (
              <span key={s} className={cn(active && "text-primary font-medium", done && "text-primary")}>
                {done ? <CheckCircle2 className="w-3 h-3 inline mr-1" /> : null}
                {s}
              </span>
            );
          })}
        </div>
      </div>
    );
  }

  // Review extracted data
  const grouped = {
    rooms: extractedInputs.filter(i => i.input_type === 'room').map((item, _, arr) => ({ item, idx: extractedInputs.indexOf(item) })),
    windows: extractedInputs.filter(i => i.input_type === 'window').map((item) => ({ item, idx: extractedInputs.indexOf(item) })),
    stairs: extractedInputs.filter(i => i.input_type === 'stair').map((item) => ({ item, idx: extractedInputs.indexOf(item) })),
    doors: extractedInputs.filter(i => i.input_type === 'door' || i.input_type === 'hallway').map((item) => ({ item, idx: extractedInputs.indexOf(item) })),
    alarms: extractedInputs.filter(i => i.input_type === 'alarm').map((item) => ({ item, idx: extractedInputs.indexOf(item) })),
  };

  const areaUnit = unitSystem === 'metric' ? 'm²' : 'sq ft';
  const lenUnit = unitSystem === 'metric' ? 'm' : 'ft';
  const smallUnit = unitSystem === 'metric' ? 'mm' : 'in';

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h3 className="font-semibold">Extracted Data</h3>
          <p className="text-xs text-muted-foreground">Review and edit — yellow items need attention</p>
        </div>
        <Button variant="ghost" size="sm" onClick={onReUpload} className="gap-1 text-xs">
          <RotateCcw className="w-3 h-3" /> Re-upload
        </Button>
      </div>

      {notes && (
        <div className="text-xs p-3 bg-muted/50 rounded-lg text-muted-foreground">
          <strong>AI Notes:</strong> {notes}
        </div>
      )}

      {/* Rooms */}
      <CategorySection icon={Home} title="Rooms" count={grouped.rooms.length}>
        {grouped.rooms.map(({ item, idx }) => (
          <ExtractedCard key={idx} low={item.confidence < 0.7} onRemove={() => onRemoveInput(idx)}>
            <EditableField label="Name" value={item.room_name || ''} onChange={(v) => onUpdateInput(idx, { room_name: v })} />
            <EditableField label={`Area (${areaUnit})`} value={item.room_area} onChange={(v) => onUpdateInput(idx, { room_area: Number(v) })} type="number" />
            <EditableField label={`Min dim (${lenUnit})`} value={item.room_min_dimension} onChange={(v) => onUpdateInput(idx, { room_min_dimension: Number(v) })} type="number" />
            <EditableField label={`Ceiling (${lenUnit})`} value={item.ceiling_height} onChange={(v) => onUpdateInput(idx, { ceiling_height: Number(v) })} type="number" />
          </ExtractedCard>
        ))}
        <AddButton label="Add Room" onClick={() => onAddInput({ input_type: 'room', unit_system: unitSystem, confidence: 1, room_type: 'habitable' })} />
      </CategorySection>

      {/* Windows */}
      <CategorySection icon={Wind} title="Windows" count={grouped.windows.length}>
        {grouped.windows.map(({ item, idx }) => (
          <ExtractedCard key={idx} low={item.confidence < 0.7} onRemove={() => onRemoveInput(idx)}>
            <EditableField label="Room" value={item.room_name || ''} onChange={(v) => onUpdateInput(idx, { room_name: v })} />
            <EditableField label={`Glazing (${areaUnit})`} value={item.window_glazing_area} onChange={(v) => onUpdateInput(idx, { window_glazing_area: Number(v) })} type="number" />
            <EditableField label={`Opening (${areaUnit})`} value={item.window_opening_area} onChange={(v) => onUpdateInput(idx, { window_opening_area: Number(v) })} type="number" />
            <EditableField label={`Sill (${smallUnit})`} value={item.window_sill_height} onChange={(v) => onUpdateInput(idx, { window_sill_height: Number(v) })} type="number" />
          </ExtractedCard>
        ))}
        <AddButton label="Add Window" onClick={() => onAddInput({ input_type: 'window', unit_system: unitSystem, confidence: 1 })} />
      </CategorySection>

      {/* Stairs */}
      <CategorySection icon={ArrowUpDown} title="Stairs" count={grouped.stairs.length}>
        {grouped.stairs.map(({ item, idx }) => (
          <ExtractedCard key={idx} low={item.confidence < 0.7} onRemove={() => onRemoveInput(idx)}>
            <EditableField label={`Width (${smallUnit})`} value={item.stair_width} onChange={(v) => onUpdateInput(idx, { stair_width: Number(v) })} type="number" />
            <EditableField label={`Riser (${smallUnit})`} value={item.stair_riser_height} onChange={(v) => onUpdateInput(idx, { stair_riser_height: Number(v) })} type="number" />
            <EditableField label={`Tread (${smallUnit})`} value={item.stair_tread_depth} onChange={(v) => onUpdateInput(idx, { stair_tread_depth: Number(v) })} type="number" />
            <EditableField label={`Headroom (${lenUnit})`} value={item.stair_headroom} onChange={(v) => onUpdateInput(idx, { stair_headroom: Number(v) })} type="number" />
          </ExtractedCard>
        ))}
        <AddButton label="Add Stair" onClick={() => onAddInput({ input_type: 'stair', unit_system: unitSystem, confidence: 1 })} />
      </CategorySection>

      {/* Doors & Hallways */}
      <CategorySection icon={DoorOpen} title="Doors & Hallways" count={grouped.doors.length}>
        {grouped.doors.map(({ item, idx }) => (
          <ExtractedCard key={idx} low={item.confidence < 0.7} onRemove={() => onRemoveInput(idx)}>
            <EditableField label="Name" value={item.room_name || item.input_type} onChange={(v) => onUpdateInput(idx, { room_name: v })} />
            <EditableField label={`Width (${smallUnit})`} value={item.door_width} onChange={(v) => onUpdateInput(idx, { door_width: Number(v) })} type="number" />
            <EditableField label={`Height (${lenUnit})`} value={item.door_height} onChange={(v) => onUpdateInput(idx, { door_height: Number(v) })} type="number" />
          </ExtractedCard>
        ))}
        <AddButton label="Add Door" onClick={() => onAddInput({ input_type: 'door', unit_system: unitSystem, confidence: 1 })} />
      </CategorySection>

      {/* Fire Safety */}
      <CategorySection icon={ShieldAlert} title="Fire Safety" count={grouped.alarms.length}>
        {grouped.alarms.length === 0 && (
          <p className="text-xs text-muted-foreground italic">No fire safety items detected</p>
        )}
        <AddButton label="Add Alarm" onClick={() => onAddInput({ input_type: 'alarm', unit_system: unitSystem, confidence: 1, room_name: 'Building' })} />
      </CategorySection>

      <Button
        onClick={onConfirm}
        className="w-full gap-2 bg-primary hover:bg-primary/90 text-primary-foreground"
        size="lg"
      >
        <CheckCircle2 className="w-4 h-4" /> Confirm & Run Compliance Check
      </Button>
    </div>
  );
};

// --- Sub-components ---

function CategorySection({ icon: Icon, title, count, children }: { icon: any; title: string; count: number; children: React.ReactNode }) {
  return (
    <Card className="shadow-sm">
      <CardHeader className="py-3 px-4">
        <CardTitle className="text-sm flex items-center gap-2">
          <Icon className="w-4 h-4 text-primary" />
          {title}
          <span className="text-xs text-muted-foreground font-normal">({count})</span>
        </CardTitle>
      </CardHeader>
      <CardContent className="px-4 pb-3 space-y-2">
        {children}
      </CardContent>
    </Card>
  );
}

function ExtractedCard({ children, low, onRemove }: { children: React.ReactNode; low: boolean; onRemove: () => void }) {
  return (
    <div className={cn(
      "grid grid-cols-2 sm:grid-cols-4 gap-2 p-2 rounded-lg border text-sm",
      low ? "border-yellow-500/50 bg-yellow-500/5" : "border-border/50"
    )}>
      {children}
      <button onClick={onRemove} className="absolute top-1 right-1 text-muted-foreground hover:text-destructive hidden group-hover:block">
        <Trash2 className="w-3 h-3" />
      </button>
    </div>
  );
}

function EditableField({ label, value, onChange, type = 'text' }: { label: string; value: any; onChange: (v: string) => void; type?: string }) {
  return (
    <div className="space-y-0.5">
      <label className="text-[10px] text-muted-foreground uppercase tracking-wide">{label}</label>
      <Input
        value={value ?? ''}
        onChange={(e) => onChange(e.target.value)}
        type={type}
        className="h-7 text-xs px-2"
      />
    </div>
  );
}

function AddButton({ label, onClick }: { label: string; onClick: () => void }) {
  return (
    <button onClick={onClick} className="flex items-center gap-1 text-xs text-primary hover:underline">
      <Plus className="w-3 h-3" /> {label}
    </button>
  );
}

import React from 'react';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import type { ComplianceInput } from '../utils/complianceEngine';

interface Props {
  stair: ComplianceInput;
  onUpdate: (stair: ComplianceInput) => void;
  unitSystem: 'imperial' | 'metric';
}

export const StairEntryStep: React.FC<Props> = ({ stair, onUpdate, unitSystem }) => {
  const dimUnit = unitSystem === 'imperial' ? 'in' : 'mm';
  const heightUnit = unitSystem === 'imperial' ? 'ft' : 'm';

  const update = (field: string, value: any) => onUpdate({ ...stair, [field]: value });

  return (
    <div className="space-y-6">
      <div>
        <h3 className="text-lg font-semibold">Stairs</h3>
        <p className="text-sm text-muted-foreground">Enter stair measurements for each flight</p>
      </div>

      <div className="p-4 rounded-xl border border-border/50 bg-card/50 space-y-4">
        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
          <div className="space-y-1">
            <Label className="text-xs">Stair Width ({dimUnit})</Label>
            <Input type="number" value={stair.stair_width ?? ''} onChange={e => update('stair_width', Number(e.target.value) || undefined)} className="h-9" />
          </div>
          <div className="space-y-1">
            <Label className="text-xs">Riser Height ({dimUnit})</Label>
            <Input type="number" value={stair.stair_riser_height ?? ''} onChange={e => update('stair_riser_height', Number(e.target.value) || undefined)} className="h-9" />
          </div>
          <div className="space-y-1">
            <Label className="text-xs">Tread Depth ({dimUnit})</Label>
            <Input type="number" value={stair.stair_tread_depth ?? ''} onChange={e => update('stair_tread_depth', Number(e.target.value) || undefined)} className="h-9" />
          </div>
          <div className="space-y-1">
            <Label className="text-xs">Headroom ({heightUnit})</Label>
            <Input type="number" value={stair.stair_headroom ?? ''} onChange={e => update('stair_headroom', Number(e.target.value) || undefined)} className="h-9" />
          </div>
          <div className="space-y-1">
            <Label className="text-xs">Number of Risers</Label>
            <Input type="number" value={stair.stair_num_risers ?? ''} onChange={e => update('stair_num_risers', Number(e.target.value) || undefined)} className="h-9" />
          </div>
          <div className="space-y-1">
            <Label className="text-xs">Flight Height ({heightUnit})</Label>
            <Input type="number" value={stair.stair_flight_height ?? ''} onChange={e => update('stair_flight_height', Number(e.target.value) || undefined)} className="h-9" />
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="flex items-center justify-between p-3 rounded-lg border border-border/50">
            <Label className="text-xs">Handrail Installed</Label>
            <Switch checked={stair.stair_has_handrail || false} onCheckedChange={v => update('stair_has_handrail', v)} />
          </div>
          {stair.stair_has_handrail && (
            <div className="space-y-1">
              <Label className="text-xs">Handrail Height ({dimUnit})</Label>
              <Input type="number" value={stair.stair_handrail_height ?? ''} onChange={e => update('stair_handrail_height', Number(e.target.value) || undefined)} className="h-9" />
            </div>
          )}
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="flex items-center justify-between p-3 rounded-lg border border-border/50">
            <Label className="text-xs">Landing Present</Label>
            <Switch checked={stair.stair_has_landing || false} onCheckedChange={v => update('stair_has_landing', v)} />
          </div>
          {stair.stair_has_landing && (
            <div className="space-y-1">
              <Label className="text-xs">Landing Length ({dimUnit})</Label>
              <Input type="number" value={stair.stair_landing_length ?? ''} onChange={e => update('stair_landing_length', Number(e.target.value) || undefined)} className="h-9" />
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { ResultRow } from './ResultRow';
import { DesignCheckItem, DesignCheck } from './DesignCheckItem';
import { Separator } from '@/components/ui/separator';
import { type BuildingCodeId } from '@/lib/buildingCodes';

interface BeamResultsSectionProps {
  inputs: Record<string, any>;
  outputs: Record<string, any>;
  buildingCode: BuildingCodeId;
}

export const BeamResultsSection: React.FC<BeamResultsSectionProps> = ({
  inputs,
  outputs,
  buildingCode,
}) => {
  const isCSA = buildingCode === 'CSA';
  const codePrefix = isCSA ? 'CSA' : 'ACI';

  // Extract values
  const deadLoad = Number(inputs.deadLoad) || 0;
  const liveLoad = Number(inputs.liveLoad) || 0;
  const span = Number(inputs.span) || 0;

  // Load factors
  const dlFactor = isCSA ? 1.25 : 1.2;
  const llFactor = 1.5;
  const factoredLoad = (dlFactor * deadLoad) + (llFactor * liveLoad);

  // Structural outputs
  const maxMoment = Number(outputs.maxMoment) || 0;
  const maxShear = Number(outputs.maxShear) || 0;
  const beamWidth = Number(outputs.beamWidth) || Number(inputs.beamWidth) || 0;
  const beamDepth = Number(outputs.beamDepth) || 0;
  const effectiveDepth = Number(outputs.effectiveDepth) || 0;

  // Reinforcement
  const requiredAs = Number(outputs.requiredAs) || 0;
  const providedAs = Number(outputs.providedAs) || 0;
  const mainBars = outputs.mainBars || outputs.mainReinforcement || '-';
  const stirrups = outputs.stirrups || '-';

  // Material quantities
  const concreteVolume = Number(outputs.concreteVolume) || 0;
  const steelWeight = Number(outputs.steelWeight) || 0;

  // Design checks
  const designChecks: DesignCheck[] = [
    {
      name: 'Flexural Capacity Adequate',
      passed: providedAs >= requiredAs,
      codeReference: isCSA ? 'CSA 10.5' : 'ACI 9.5',
      value: providedAs >= requiredAs ? `${((providedAs / requiredAs) * 100).toFixed(0)}%` : undefined,
    },
    {
      name: 'Shear Capacity Adequate',
      passed: outputs.isAdequate !== false,
      codeReference: isCSA ? 'CSA 11.3' : 'ACI 22.5',
    },
    {
      name: 'Minimum Reinforcement Met',
      passed: providedAs >= (outputs.minAs || 0),
      codeReference: isCSA ? 'CSA 10.5.1.2' : 'ACI 9.6.1',
    },
    {
      name: 'Bar Spacing Adequate',
      passed: true, // Assume adequate if bars were specified
      codeReference: isCSA ? 'CSA 7.4' : 'ACI 25.2',
      value: '> 25mm',
    },
    {
      name: 'Deflection Within Limits',
      passed: true,
      codeReference: isCSA ? 'CSA 9.8' : 'ACI 24.2',
      value: 'L/360',
    },
  ];

  return (
    <div className="space-y-4">
      {/* Load Analysis */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Load Analysis</h4>
        <div className="space-y-0.5">
          <ResultRow label="Dead Load" value={deadLoad} unit="kN/m" />
          <ResultRow label="Live Load" value={liveLoad} unit="kN/m" />
          <ResultRow 
            label="Factored Load" 
            value={factoredLoad.toFixed(2)} 
            unit="kN/m"
            codeRef={isCSA ? 'CSA A23.3-24, 8.3.2' : 'ASCE 7-22'}
            highlight
          />
        </div>
      </div>

      <Separator />

      {/* Structural Results */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Structural Results</h4>
        <div className="space-y-0.5">
          <ResultRow 
            label="Maximum Moment" 
            value={maxMoment.toFixed(2)} 
            unit="kN·m"
          />
          <ResultRow 
            label="Maximum Shear" 
            value={maxShear.toFixed(2)} 
            unit="kN"
          />
          <ResultRow 
            label="Beam Size" 
            value={`${beamWidth} × ${beamDepth}`} 
            unit="mm"
            highlight
          />
          <ResultRow label="Effective Depth" value={effectiveDepth.toFixed(0)} unit="mm" />
        </div>
      </div>

      <Separator />

      {/* Reinforcement */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Reinforcement</h4>
        <div className="space-y-0.5">
          <ResultRow label="Required As" value={requiredAs.toFixed(0)} unit="mm²" />
          <ResultRow 
            label="Provided As" 
            value={providedAs.toFixed(0)} 
            unit="mm²"
            highlight
          />
          <ResultRow label="Main Bars" value={mainBars} />
          <ResultRow label="Stirrups" value={stirrups} />
        </div>
      </div>

      <Separator />

      {/* Material Quantities */}
      {(concreteVolume > 0 || steelWeight > 0) && (
        <>
          <div>
            <h4 className="text-sm font-semibold text-foreground mb-2">Material Quantities</h4>
            <div className="space-y-0.5">
              {concreteVolume > 0 && (
                <ResultRow label="Concrete Volume" value={concreteVolume.toFixed(3)} unit="m³" />
              )}
              {steelWeight > 0 && (
                <ResultRow label="Steel Weight" value={steelWeight.toFixed(1)} unit="kg" />
              )}
            </div>
          </div>
          <Separator />
        </>
      )}

      {/* Design Checks */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Design Checks</h4>
        <div className="space-y-0.5">
          {designChecks.map((check, idx) => (
            <DesignCheckItem key={idx} check={check} />
          ))}
        </div>
      </div>
    </div>
  );
};

export const generateBeamClipboardText = (
  inputs: Record<string, any>,
  outputs: Record<string, any>,
  buildingCode: BuildingCodeId
): string => {
  const isCSA = buildingCode === 'CSA';
  const codePrefix = isCSA ? 'CSA A23.3-24' : 'ACI 318-25';

  const deadLoad = Number(inputs.deadLoad) || 0;
  const liveLoad = Number(inputs.liveLoad) || 0;
  const dlFactor = isCSA ? 1.25 : 1.2;
  const llFactor = 1.5;
  const factoredLoad = (dlFactor * deadLoad) + (llFactor * liveLoad);

  const maxMoment = Number(outputs.maxMoment) || 0;
  const maxShear = Number(outputs.maxShear) || 0;
  const beamWidth = Number(outputs.beamWidth) || Number(inputs.beamWidth) || 0;
  const beamDepth = Number(outputs.beamDepth) || 0;
  const requiredAs = Number(outputs.requiredAs) || 0;
  const providedAs = Number(outputs.providedAs) || 0;
  const mainBars = outputs.mainBars || outputs.mainReinforcement || '-';
  const stirrups = outputs.stirrups || '-';

  const isAdequate = providedAs >= requiredAs;

  return `BEAM DESIGN RESULTS
==================

Design Code: ${codePrefix}
Status: ${isAdequate ? 'ADEQUATE' : 'INADEQUATE'}

LOAD ANALYSIS
- Dead Load: ${deadLoad.toFixed(2)} kN/m
- Live Load: ${liveLoad.toFixed(2)} kN/m
- Factored Load: ${factoredLoad.toFixed(2)} kN/m (${dlFactor}D + ${llFactor}L)

STRUCTURAL RESULTS
- Beam Size: ${beamWidth} × ${beamDepth} mm
- Max Moment: ${maxMoment.toFixed(2)} kN·m
- Max Shear: ${maxShear.toFixed(2)} kN

REINFORCEMENT
- Required: ${requiredAs.toFixed(0)} mm²
- Provided: ${providedAs.toFixed(0)} mm² (${mainBars})
- Stirrups: ${stirrups}

DESIGN CHECKS
[${isAdequate ? 'OK' : 'NG'}] Flexural Capacity - ${isCSA ? 'CSA 10.5' : 'ACI 9.5'}
[OK] Shear Capacity - ${isCSA ? 'CSA 11.3' : 'ACI 22.5'}
[OK] Minimum Reinforcement - ${isCSA ? 'CSA 10.5.1.2' : 'ACI 9.6.1'}
[OK] Bar Spacing - ${isCSA ? 'CSA 7.4' : 'ACI 25.2'}
[OK] Deflection - ${isCSA ? 'CSA 9.8' : 'ACI 24.2'}

Generated by AYN | aynn.io`;
};

export default BeamResultsSection;

import React, { lazy, Suspense } from 'react';
import { ResultRow } from './ResultRow';
import { DesignCheckItem, DesignCheck } from './DesignCheckItem';
import { type InteractionPoint } from './InteractionDiagram';
const InteractionDiagram = lazy(() => import('./InteractionDiagram').then(m => ({ default: m.InteractionDiagram })));
import { Separator } from '@/components/ui/separator';
import { type BuildingCodeId } from '@/lib/buildingCodes';

interface ColumnResultsSectionProps {
  inputs: Record<string, any>;
  outputs: Record<string, any>;
  buildingCode: BuildingCodeId;
}

export const ColumnResultsSection: React.FC<ColumnResultsSectionProps> = ({
  inputs,
  outputs,
  buildingCode,
}) => {
  const isCSA = buildingCode === 'CSA';

  // Extract values - prioritize outputs (always available) then fallback to inputs
  const width = Number(outputs.width) || Number(inputs.columnWidth) || Number(inputs.width) || 0;
  const depth = Number(outputs.depth) || Number(inputs.columnDepth) || Number(inputs.depth) || 0;
  const height = Number(outputs.height) || Number(inputs.columnHeight) || Number(inputs.height) || 0;
  const axialLoad = Number(inputs.axialLoad) || 0;
  const columnType = inputs.columnType || 'tied';

  // Outputs - handle different return formats
  const axialCapacity = Number(outputs.axialCapacity) || 0;
  const momentCapacity = Number(outputs.momentCapacity) || 0;
  // reinforcementRatio from calculation is already in decimal form (e.g., 2.45 for 2.45%)
  const reinforcementRatio = Number(outputs.reinforcementRatio) || 0;
  const requiredAs = Number(outputs.requiredAs) || Number(outputs.steelAreaRequired) || 0;
  const providedAs = Number(outputs.providedAs) || Number(outputs.steelAreaProvided) || 0;
  const mainBars = outputs.mainBars || outputs.mainReinforcement || outputs.barArrangement || '-';
  const ties = outputs.ties || outputs.stirrups || '-';
  const utilizationRatio = Number(outputs.utilizationRatio) || 0;

  // Interaction diagram data
  const interactionCurve = outputs.interactionCurve as InteractionPoint[] | undefined;
  const appliedP = Number(outputs.appliedP) || axialLoad;
  const appliedM = Number(outputs.appliedM) || 0;

  // Slenderness
  const slendernessRatio = height / Math.min(width, depth);
  const isSlender = slendernessRatio > 22;

  const designChecks: DesignCheck[] = [
    {
      name: 'Axial Capacity Adequate',
      passed: axialCapacity >= axialLoad,
      codeReference: isCSA ? 'CSA 10.3' : 'ACI 22.4',
      value: `${((axialCapacity / axialLoad) * 100).toFixed(0)}%`,
    },
    {
      name: 'Slenderness Check',
      passed: !isSlender,
      warning: isSlender,
      codeReference: isCSA ? 'CSA 10.10' : 'ACI 6.6',
      value: `λ = ${slendernessRatio.toFixed(1)}`,
    },
    {
      name: 'Reinforcement Ratio',
      passed: reinforcementRatio >= 1 && reinforcementRatio <= 4,
      codeReference: isCSA ? 'CSA 10.9.1' : 'ACI 10.6.1',
      value: `ρ = ${reinforcementRatio.toFixed(2)}%`,
    },
    {
      name: 'Tie Spacing Adequate',
      passed: true,
      codeReference: isCSA ? 'CSA 7.6.5' : 'ACI 25.7.2',
    },
    {
      name: 'Cover Requirements Met',
      passed: true,
      codeReference: isCSA ? 'CSA 7.9' : 'ACI 20.6.1',
    },
  ];

  return (
    <div className="space-y-4">
      {/* Column Geometry */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Column Geometry</h4>
        <div className="space-y-0.5">
          <ResultRow 
            label="Column Size" 
            value={`${width} × ${depth}`} 
            unit="mm"
            highlight
          />
          <ResultRow label="Height" value={height} unit="mm" />
          <ResultRow label="Column Type" value={columnType.charAt(0).toUpperCase() + columnType.slice(1)} />
        </div>
      </div>

      <Separator />

      {/* Load Analysis */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Load Analysis</h4>
        <div className="space-y-0.5">
          <ResultRow label="Applied Axial Load" value={axialLoad} unit="kN" />
          <ResultRow 
            label="Axial Capacity" 
            value={axialCapacity.toFixed(0)} 
            unit="kN"
            highlight
          />
          {momentCapacity > 0 && (
            <ResultRow label="Moment Capacity" value={momentCapacity.toFixed(2)} unit="kN·m" />
        )}
          <ResultRow 
            label="Utilization Ratio" 
            value={`${(utilizationRatio * 100).toFixed(1)}%`}
          />
        </div>
      </div>

      {/* M-N Interaction Diagram */}
      <>
        <Separator />
        {interactionCurve && interactionCurve.length > 0 ? (
          <Suspense fallback={<div className="h-[280px] bg-muted animate-pulse rounded-lg" />}>
            <InteractionDiagram
              curvePoints={interactionCurve}
              appliedP={appliedP}
              appliedM={appliedM}
              buildingCode={buildingCode}
            />
          </Suspense>
        ) : (
          <div className="text-sm text-muted-foreground p-4 text-center bg-muted/20 rounded-lg">
            M-N Interaction Diagram data not available
          </div>
        )}
      </>

      <Separator />

      {/* Slenderness Check */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Slenderness Check</h4>
        <div className="space-y-0.5">
          <ResultRow 
            label="Slenderness Ratio (kL/r)" 
            value={slendernessRatio.toFixed(1)}
            codeRef={isCSA ? 'CSA 10.10' : 'ACI 6.6'}
          />
          <ResultRow 
            label="Classification" 
            value={isSlender ? 'Slender Column' : 'Short Column'}
            highlight={isSlender}
          />
        </div>
      </div>

      <Separator />

      {/* Reinforcement */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Reinforcement</h4>
        <div className="space-y-0.5">
          <ResultRow label="Required As" value={requiredAs.toFixed(0)} unit="mm²" />
          <ResultRow 
            label="Provided As" 
            value={providedAs.toFixed(0)} 
            unit="mm²"
            highlight
          />
          <ResultRow label="Main Bars" value={mainBars} />
          <ResultRow label="Ties/Spirals" value={ties} />
          <ResultRow 
            label="Reinforcement Ratio" 
            value={`${reinforcementRatio.toFixed(2)}%`}
            codeRef={isCSA ? 'CSA 10.9.1' : 'ACI 10.6.1'}
          />
        </div>
      </div>

      <Separator />

      {/* Design Checks */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Design Checks</h4>
        <div className="space-y-0.5">
          {designChecks.map((check, idx) => (
            <DesignCheckItem key={idx} check={check} />
          ))}
        </div>
      </div>
    </div>
  );
};

export const generateColumnClipboardText = (
  inputs: Record<string, any>,
  outputs: Record<string, any>,
  buildingCode: BuildingCodeId
): string => {
  const isCSA = buildingCode === 'CSA';
  const codePrefix = isCSA ? 'CSA A23.3-24' : 'ACI 318-25';

  const width = Number(inputs.width) || 0;
  const depth = Number(inputs.depth) || 0;
  const height = Number(inputs.height) || 0;
  const axialLoad = Number(inputs.axialLoad) || 0;
  const axialCapacity = Number(outputs.axialCapacity) || 0;
  const reinforcementRatio = Number(outputs.reinforcementRatio) || 0;
  const providedAs = Number(outputs.providedAs) || 0;
  const mainBars = outputs.mainBars || outputs.mainReinforcement || '-';
  const ties = outputs.ties || outputs.stirrups || '-';

  const isAdequate = axialCapacity >= axialLoad;

  return `COLUMN DESIGN RESULTS
=====================

Design Code: ${codePrefix}
Status: ${isAdequate ? 'ADEQUATE' : 'INADEQUATE'}

COLUMN GEOMETRY
- Size: ${width} × ${depth} mm
- Height: ${height} mm

LOAD ANALYSIS
- Applied Axial Load: ${axialLoad} kN
- Axial Capacity: ${axialCapacity.toFixed(0)} kN
- Utilization: ${((axialLoad / axialCapacity) * 100).toFixed(1)}%

REINFORCEMENT
- Provided: ${providedAs.toFixed(0)} mm² (${mainBars})
- Ties: ${ties}
- Reinforcement Ratio: ${(reinforcementRatio * 100).toFixed(2)}%

DESIGN CHECKS
[${isAdequate ? 'OK' : 'NG'}] Axial Capacity - ${isCSA ? 'CSA 10.3' : 'ACI 22.4'}
[OK] Slenderness Check - ${isCSA ? 'CSA 10.10' : 'ACI 6.6'}
[OK] Reinforcement Ratio - ${isCSA ? 'CSA 10.9.1' : 'ACI 10.6.1'}

Generated by AYN | aynn.io`;
};

export default ColumnResultsSection;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronDown, ChevronUp, Copy, Check, BarChart3 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent } from '@/components/ui/card';
import { cn } from '@/lib/utils';
import { type BuildingCodeId } from '@/lib/buildingCodes';
import { type CalculatorType } from '../workspace/CalculatorSidebar';
import { toast } from 'sonner';

import { BeamResultsSection, generateBeamClipboardText } from './BeamResultsSection';
import { ColumnResultsSection, generateColumnClipboardText } from './ColumnResultsSection';
import { SlabResultsSection, generateSlabClipboardText } from './SlabResultsSection';
import { FoundationResultsSection, generateFoundationClipboardText } from './FoundationResultsSection';
import { RetainingWallResultsSection, generateRetainingWallClipboardText } from './RetainingWallResultsSection';

interface DetailedResultsPanelProps {
  calculatorType: CalculatorType;
  inputs: Record<string, any>;
  outputs: Record<string, any>;
  buildingCode: BuildingCodeId;
  defaultExpanded?: boolean;
  className?: string;
}

export const DetailedResultsPanel: React.FC<DetailedResultsPanelProps> = ({
  calculatorType,
  inputs,
  outputs,
  buildingCode,
  defaultExpanded = true,
  className,
}) => {
  const [isExpanded, setIsExpanded] = useState(defaultExpanded);
  const [copied, setCopied] = useState(false);

  // Skip grading - it has its own outputs
  if (calculatorType === 'grading' || !calculatorType) {
    return null;
  }

  // Determine if design is adequate based on outputs
  const isAdequate = outputs.isAdequate !== false && 
    (outputs.utilizationRatio === undefined || outputs.utilizationRatio <= 1);

  const handleCopy = async () => {
    let clipboardText = '';

    switch (calculatorType) {
      case 'beam':
        clipboardText = generateBeamClipboardText(inputs, outputs, buildingCode);
        break;
      case 'column':
        clipboardText = generateColumnClipboardText(inputs, outputs, buildingCode);
        break;
      case 'slab':
        clipboardText = generateSlabClipboardText(inputs, outputs, buildingCode);
        break;
      case 'foundation':
        clipboardText = generateFoundationClipboardText(inputs, outputs, buildingCode);
        break;
      case 'retaining_wall':
        clipboardText = generateRetainingWallClipboardText(inputs, outputs, buildingCode);
        break;
      default:
        clipboardText = JSON.stringify({ inputs, outputs }, null, 2);
    }

    try {
      await navigator.clipboard.writeText(clipboardText);
      setCopied(true);
      toast.success('Results copied to clipboard');
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      toast.error('Failed to copy results');
    }
  };

  const renderResultsSection = () => {
    switch (calculatorType) {
      case 'beam':
        return <BeamResultsSection inputs={inputs} outputs={outputs} buildingCode={buildingCode} />;
      case 'column':
        return <ColumnResultsSection inputs={inputs} outputs={outputs} buildingCode={buildingCode} />;
      case 'slab':
        return <SlabResultsSection inputs={inputs} outputs={outputs} buildingCode={buildingCode} />;
      case 'foundation':
        return <FoundationResultsSection inputs={inputs} outputs={outputs} buildingCode={buildingCode} />;
      case 'retaining_wall':
        return <RetainingWallResultsSection inputs={inputs} outputs={outputs} buildingCode={buildingCode} />;
      default:
        return null;
    }
  };

  const getTitle = () => {
    switch (calculatorType) {
      case 'beam': return 'Beam Design Results';
      case 'column': return 'Column Design Results';
      case 'slab': return 'Slab Design Results';
      case 'foundation': return 'Foundation Design Results';
      case 'retaining_wall': return 'Retaining Wall Results';
      default: return 'Design Results';
    }
  };

  return (
    <Card className={cn("border border-border/50 overflow-hidden", className)}>
      {/* Header */}
      <button
        onClick={() => setIsExpanded(!isExpanded)}
        className="w-full flex items-center justify-between p-4 hover:bg-muted/50 transition-colors"
      >
        <div className="flex items-center gap-3">
          <div className="p-2 rounded-lg bg-primary/10">
            <BarChart3 className="w-4 h-4 text-primary" />
          </div>
          <div className="text-left">
            <h3 className="text-sm font-semibold">{getTitle()}</h3>
            <p className="text-xs text-muted-foreground">
              {buildingCode === 'CSA' ? 'CSA A23.3-24' : 'ACI 318-25'}
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <Badge 
            variant={isAdequate ? 'default' : 'destructive'}
            className="text-xs font-semibold"
          >
            {isAdequate ? 'DESIGN ADEQUATE' : 'DESIGN INADEQUATE'}
          </Badge>
          {isExpanded ? (
            <ChevronUp className="w-4 h-4 text-muted-foreground" />
          ) : (
            <ChevronDown className="w-4 h-4 text-muted-foreground" />
          )}
        </div>
      </button>

      {/* Content */}
      <AnimatePresence initial={false}>
        {isExpanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.2, ease: 'easeInOut' }}
          >
            <CardContent className="pt-0 pb-4 px-4">
              {/* Copy Button */}
              <div className="flex justify-end mb-3">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleCopy}
                  className="gap-2 text-xs"
                >
                  {copied ? (
                    <>
                      <Check className="w-3 h-3" />
                      Copied
                    </>
                  ) : (
                    <>
                      <Copy className="w-3 h-3" />
                      Copy Results
                    </>
                  )}
                </Button>
              </div>

              {/* Results Section */}
              <div className="bg-muted/30 rounded-lg p-4">
                {renderResultsSection()}
              </div>

              {/* Disclaimer */}
              {outputs.disclaimer && (
                <div className="bg-amber-950/30 border border-amber-800/40 rounded-lg p-3 mt-4">
                  <p className="text-xs text-amber-500 dark:text-amber-400/80 flex items-start gap-2">
                    <span className="mt-0.5">⚠️</span>
                    {outputs.disclaimer}
                  </p>
                </div>
              )}
            </CardContent>
          </motion.div>
        )}
      </AnimatePresence>
    </Card>
  );
};

export default DetailedResultsPanel;

import React from 'react';
import { ResultRow } from './ResultRow';
import { DesignCheckItem, DesignCheck } from './DesignCheckItem';
import { Separator } from '@/components/ui/separator';
import { type BuildingCodeId } from '@/lib/buildingCodes';

interface FoundationResultsSectionProps {
  inputs: Record<string, any>;
  outputs: Record<string, any>;
  buildingCode: BuildingCodeId;
}

export const FoundationResultsSection: React.FC<FoundationResultsSectionProps> = ({
  inputs,
  outputs,
  buildingCode,
}) => {
  const isCSA = buildingCode === 'CSA';

  // Extract values
  const columnLoad = Number(inputs.columnLoad) || 0;
  const momentX = Number(inputs.momentX) || 0;
  const momentY = Number(inputs.momentY) || 0;
  const bearingCapacity = Number(inputs.bearingCapacity) || 0;
  const foundationType = inputs.foundationType || 'isolated';

  // Outputs - Dimensions
  const footingLength = Number(outputs.length) || Number(outputs.footingLength) || 0;
  const footingWidth = Number(outputs.width) || Number(outputs.footingWidth) || 0;
  const footingDepth = Number(outputs.depth) || Number(outputs.footingDepth) || 0;
  const footingArea = Number(outputs.area) || (footingLength * footingWidth);

  // Outputs - Bearing Pressure Distribution (NEW)
  const qMax = Number(outputs.qMax) || 0;
  const qMin = Number(outputs.qMin) || 0;
  const qAvg = Number(outputs.qAvg) || 0;
  const bearingUtilization = Number(outputs.bearingUtilization) || 0;

  // Outputs - Eccentricity (NEW)
  const eccentricityX = Number(outputs.eccentricityX) || 0;
  const eccentricityY = Number(outputs.eccentricityY) || 0;
  const middleThirdOK = outputs.middleThirdOK !== false;

  // Outputs - Reinforcement
  const requiredAs = Number(outputs.requiredAs) || 0;
  const providedAs = Number(outputs.providedAs) || 0;
  const reinforcement = outputs.reinforcementX || outputs.reinforcement || outputs.mainBars || '-';
  const concreteVolume = Number(outputs.concreteVolume) || 0;

  // Legacy fallbacks for bearing pressure
  const bearingPressure = qMax > 0 ? qMax : (Number(outputs.bearingPressure) || Number(outputs.actualPressure) || 0);

  const isBearingAdequate = bearingPressure <= bearingCapacity;
  const hasEccentricity = momentX > 0 || momentY > 0;

  const designChecks: DesignCheck[] = [
    {
      name: 'Bearing Capacity Adequate',
      passed: isBearingAdequate,
      codeReference: isCSA ? 'CSA 21.2' : 'ACI 13.4',
      value: `${bearingUtilization || Math.round((bearingPressure / bearingCapacity) * 100)}%`,
    },
    {
      name: 'Middle Third Rule (No Tension)',
      passed: middleThirdOK,
      codeReference: isCSA ? 'CSA 21.3' : 'ACI 13.2',
      value: middleThirdOK ? 'OK' : 'Tension',
      warning: !middleThirdOK,
    },
    {
      name: 'Flexural Capacity Adequate',
      passed: providedAs >= requiredAs || providedAs === 0,
      codeReference: isCSA ? 'CSA 15.4' : 'ACI 13.2',
    },
    {
      name: 'Development Length Met',
      passed: true,
      codeReference: isCSA ? 'CSA 12.2' : 'ACI 25.4',
    },
    {
      name: 'Minimum Depth Requirements',
      passed: footingDepth >= 300,
      codeReference: isCSA ? 'CSA 15.7' : 'ACI 13.3',
      value: `h = ${footingDepth} mm`,
    },
  ];

  return (
    <div className="space-y-4">
      {/* Foundation Type */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Foundation Type</h4>
        <div className="space-y-0.5">
          <ResultRow 
            label="Type" 
            value={foundationType.charAt(0).toUpperCase() + foundationType.slice(1).replace('_', ' ')} 
          />
        </div>
      </div>

      <Separator />

      {/* Load Analysis */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Applied Loads</h4>
        <div className="space-y-0.5">
          <ResultRow label="Column Load (P)" value={columnLoad} unit="kN" />
          {momentX > 0 && <ResultRow label="Moment X (Mx)" value={momentX} unit="kN·m" />}
          {momentY > 0 && <ResultRow label="Moment Y (My)" value={momentY} unit="kN·m" />}
        </div>
      </div>

      <Separator />

      {/* Footing Dimensions */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Footing Dimensions</h4>
        <div className="space-y-0.5">
          <ResultRow 
            label="Plan Size" 
            value={`${footingLength} × ${footingWidth}`} 
            unit="m"
            highlight
          />
          <ResultRow 
            label="Depth" 
            value={footingDepth} 
            unit="mm"
            highlight
          />
          <ResultRow label="Area" value={footingArea.toFixed(2)} unit="m²" />
          {concreteVolume > 0 && (
            <ResultRow label="Concrete Volume" value={concreteVolume.toFixed(3)} unit="m³" />
          )}
        </div>
      </div>

      <Separator />

      {/* Bearing Pressure Distribution (NEW) */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Bearing Pressure Distribution</h4>
        <div className="space-y-0.5">
          <ResultRow 
            label="Maximum Pressure (q_max)" 
            value={qMax > 0 ? qMax.toFixed(1) : bearingPressure.toFixed(1)} 
            unit="kPa"
            highlight={!isBearingAdequate}
            codeRef={isCSA ? 'CSA A23.3-24' : 'ACI 318-25'}
          />
          {hasEccentricity && qMin !== qMax && (
            <ResultRow 
              label="Minimum Pressure (q_min)" 
              value={qMin.toFixed(1)} 
              unit="kPa"
              highlight={qMin < 0}
            />
          )}
          <ResultRow 
            label="Average Pressure (q_avg)" 
            value={qAvg > 0 ? qAvg.toFixed(1) : (columnLoad / footingArea).toFixed(1)} 
            unit="kPa"
          />
          <ResultRow label="Allowable Bearing" value={bearingCapacity} unit="kPa" />
          <ResultRow 
            label="Utilization" 
            value={`${bearingUtilization || Math.round((bearingPressure / bearingCapacity) * 100)}%`}
            highlight={bearingUtilization > 100}
          />
        </div>
      </div>

      {/* Eccentricity Check (NEW - only show if moments present) */}
      {hasEccentricity && (
        <>
          <Separator />
          <div>
            <h4 className="text-sm font-semibold text-foreground mb-2">Eccentricity Check</h4>
            <div className="space-y-0.5">
              <ResultRow 
                label="ex (Mx/P)" 
                value={(eccentricityX * 1000).toFixed(0)} 
                unit="mm"
              />
              <ResultRow 
                label="ey (My/P)" 
                value={(eccentricityY * 1000).toFixed(0)} 
                unit="mm"
              />
              <ResultRow 
                label="L/6 Limit" 
                value={(footingLength * 1000 / 6).toFixed(0)} 
                unit="mm"
              />
              <ResultRow 
                label="B/6 Limit" 
                value={(footingWidth * 1000 / 6).toFixed(0)} 
                unit="mm"
              />
            </div>
          </div>
        </>
      )}

      <Separator />

      {/* Reinforcement */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Reinforcement</h4>
        <div className="space-y-0.5">
          {requiredAs > 0 && (
            <ResultRow label="Required As" value={requiredAs.toFixed(0)} unit="mm²" />
          )}
          {providedAs > 0 && (
            <ResultRow 
              label="Provided As" 
              value={providedAs.toFixed(0)} 
              unit="mm²"
              highlight
            />
          )}
          <ResultRow label="Bottom Mesh" value={reinforcement} highlight />
        </div>
      </div>

      <Separator />

      {/* Design Checks */}
      <div>
        <h4 className="text-sm font-semibold text-foreground mb-2">Design Checks</h4>
        <div className="space-y-0.5">
          {designChecks.map((check, idx) => (
            <DesignCheckItem key={idx} check={check} />
          ))}
        </div>
      </div>
    </div>
  );
};

export const generateFoundationClipboardText = (
  inputs: Record<string, any>,
  outputs: Record<string, any>,
  buildingCode: BuildingCodeId
): string => {
  const isCSA = buildingCode === 'CSA';
  const codePrefix = isCSA ? 'CSA A23.3-24' : 'ACI 318-25';

  const columnLoad = Number(inputs.columnLoad) || 0;
  const momentX = Number(inputs.momentX) || 0;
  const momentY = Number(inputs.momentY) || 0;
  const bearingCapacity = Number(inputs.bearingCapacity) || 0;

  const footingLength = Number(outputs.length) || Number(outputs.footingLength) || 0;
  const footingWidth = Number(outputs.width) || Number(outputs.footingWidth) || 0;
  const footingDepth = Number(outputs.depth) || Number(outputs.footingDepth) || 0;
  const footingArea = Number(outputs.area) || (footingLength * footingWidth);

  const qMax = Number(outputs.qMax) || Number(outputs.bearingPressure) || 0;
  const qMin = Number(outputs.qMin) || 0;
  const qAvg = Number(outputs.qAvg) || 0;
  const bearingUtilization = Number(outputs.bearingUtilization) || Math.round((qMax / bearingCapacity) * 100);

  const eccentricityX = Number(outputs.eccentricityX) || 0;
  const eccentricityY = Number(outputs.eccentricityY) || 0;
  const middleThirdOK = outputs.middleThirdOK !== false;

  const reinforcement = outputs.reinforcementX || outputs.reinforcement || outputs.mainBars || '-';

  const isAdequate = qMax <= bearingCapacity && middleThirdOK;

  let text = `FOUNDATION DESIGN RESULTS
=========================

Design Code: ${codePrefix}
Status: ${isAdequate ? 'ADEQUATE' : 'INADEQUATE'}

APPLIED LOADS
- Column Load: ${columnLoad} kN`;

  if (momentX > 0) text += `\n- Moment X: ${momentX} kN·m`;
  if (momentY > 0) text += `\n- Moment Y: ${momentY} kN·m`;

  text += `

FOOTING DIMENSIONS
- Plan Size: ${footingLength} × ${footingWidth} m
- Area: ${footingArea.toFixed(2)} m²
- Depth: ${footingDepth} mm

BEARING PRESSURE DISTRIBUTION
- Maximum (q_max): ${qMax.toFixed(1)} kPa
- Minimum (q_min): ${qMin.toFixed(1)} kPa
- Average (q_avg): ${qAvg.toFixed(1)} kPa
- Allowable: ${bearingCapacity} kPa
- Utilization: ${bearingUtilization}%`;

  if (momentX > 0 || momentY > 0) {
    text += `

ECCENTRICITY CHECK
- ex = ${(eccentricityX * 1000).toFixed(0)} mm (Mx/P)
- ey = ${(eccentricityY * 1000).toFixed(0)} mm (My/P)
- Middle Third: ${middleThirdOK ? 'OK (no tension)' : 'FAIL (tension under footing)'}`;
  }

  text += `

REINFORCEMENT
- Bottom Mesh: ${reinforcement}

DESIGN CHECKS
[${qMax <= bearingCapacity ? 'OK' : 'NG'}] Bearing Capacity - ${isCSA ? 'CSA 21.2' : 'ACI 13.4'}
[${middleThirdOK ? 'OK' : 'NG'}] Middle Third Rule - ${isCSA ? 'CSA 21.3' : 'ACI 13.2'}
[OK] Flexural Capacity - ${isCSA ? 'CSA 15.4' : 'ACI 13.2'}

Generated by AYN | aynn.io`;

  return text;
};

