    }

    const loadProfile = async () => {
      const { data } = await supabase
        .from('profiles')
        .select('contact_person, company_name, business_type, business_context, avatar_url')
        .eq('user_id', userId)
        .single();

      if (data) {
        const profileData = {
          contact_person: data.contact_person || '',
          company_name: data.company_name || '',
          business_type: data.business_type || '',
          business_context: (data as any).business_context || '',
          avatar_url: data.avatar_url || '',
        };
        setProfile(profileData);
        setOriginalProfile(profileData);
      }

      setLoading(false);
    };

    loadProfile();
  }, [userId]);

  // Track unsaved changes
  useEffect(() => {
    const hasChanges = JSON.stringify(profile) !== JSON.stringify(originalProfile);
    registerFormChange('account', hasChanges);
  }, [profile, originalProfile, registerFormChange]);

  // Function to refresh profile after avatar update
  const refreshProfile = async () => {
    const { data } = await supabase
      .from('profiles')
      .select('contact_person, company_name, business_type, avatar_url')
      .eq('user_id', userId)
      .single();

    if (data) {
      setProfile(prev => ({
        ...prev,
        contact_person: data.contact_person || '',
        company_name: data.company_name || '',
        business_type: data.business_type || '',
        avatar_url: data.avatar_url || '',
      }));
    }
  };

  const handleSave = async () => {
    if (!userId) return;

    setSaving(true);
    try {
      const { error } = await supabase
        .from('profiles')
        .update({
          contact_person: profile.contact_person,
          company_name: profile.company_name,
          business_type: profile.business_type,
          business_context: profile.business_context,
        } as any)
        .eq('user_id', userId);

      if (error) throw error;

      setOriginalProfile(profile);
      registerFormChange('account', false);

      toast({
        title: t('common.success'),
        description: t('settings.profileUpdated'),
      });
    } catch (error) {
      console.error('Error saving profile:', error);
      toast({
        title: "Couldn't Update Profile",
        description: error instanceof Error ? error.message : "Your changes weren't saved. Please try again.",
        variant: 'destructive',
      });
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  // Filter fields based on search
  const matchesSearch = (text: string) => {
    if (!searchTerm) return true;
    return text.toLowerCase().includes(searchTerm.toLowerCase());
  };

  const showContactPerson = matchesSearch(t('settings.contactPerson'));
  const showCompanyName = matchesSearch(t('settings.companyName'));
  const showEmail = matchesSearch(t('settings.email'));
  const showBusinessType = matchesSearch(t('settings.businessType'));
  const showBusinessContext = matchesSearch(t('settings.businessContext'));
  const showAvatar = matchesSearch(t('profile.changePhoto'));

  const showUsage = matchesSearch('Usage') || matchesSearch('Limit') || matchesSearch('Messages');

  const hasVisibleFields = showContactPerson || showCompanyName || showEmail || showBusinessType || showBusinessContext || showAvatar || showUsage;

    return (
    <div className="space-y-6">
      {/* Usage & Limits Card */}
      {showUsage && (
        <Card className="p-6 bg-card/50 backdrop-blur-xl border-border/50">
          <h2 className="text-xl font-semibold mb-4">Usage & Limits</h2>
          <UsageCard
            remaining={usage.remaining}
            totalLimit={usage.totalLimit}
            allowed={usage.allowed}
            resetsAt={usage.resetsAt}
            tier={usage.tier}
            isFree={usage.isFree}
            isUnlimited={usage.isUnlimited}
          />

          {/* Top Up — paid users only */}
          {isPaidUser && (
            <div className="mt-4 p-4 rounded-xl border border-border/50 bg-muted/30 flex items-center justify-between gap-4">
              <div>
                <p className="text-sm font-medium text-foreground">Need more messages?</p>
                <p className="text-xs text-muted-foreground">Get 500 extra messages for $10 — one-time purchase</p>
              </div>
              <Button
                variant="outline"
                size="sm"
                disabled
                className="shrink-0 gap-1.5"
              >
                <Plus className="w-3.5 h-3.5" />
                Top Up
                <Badge variant="secondary" className="ml-1 text-[10px] px-1.5 py-0">Coming Soon</Badge>
              </Button>
            </div>
          )}
        </Card>
      )}

      {!hasVisibleFields && searchTerm && (
        <Card className="p-6 bg-card/50 backdrop-blur-xl border-border/50">
          <p className="text-center text-muted-foreground">{t('settings.noResultsFound')}</p>
        </Card>
      )}
      {hasVisibleFields && (
        <Card className="p-6 bg-card/50 backdrop-blur-xl border-border/50">
          <h2 className="text-xl font-semibold mb-6">{t('settings.profileInformation')}</h2>

          <div className="space-y-6">
            {showAvatar && (
              <div className="flex items-center gap-4">
            <Avatar className="h-20 w-20 cursor-pointer" onClick={() => setShowAvatarUpload(true)}>
              <AvatarImage src={profile.avatar_url} />
              <AvatarFallback className="bg-background border border-border text-lg">
                {profile.contact_person?.[0]?.toUpperCase() || userEmail?.[0]?.toUpperCase()}
              </AvatarFallback>
            </Avatar>
                <Button variant="outline" onClick={() => setShowAvatarUpload(true)}>
                  {t('profile.changePhoto')}
                </Button>
              </div>
            )}

            {(showContactPerson || showCompanyName) && (
              <div className="grid gap-4 md:grid-cols-2">
                {showContactPerson && (
                  <div className="space-y-2">
                    <Label htmlFor="account-contact_person">{t('settings.contactPerson')}</Label>
                    <Input
                      id="account-contact_person"
                      name="account-contact_person"
                      value={profile.contact_person}
                      onChange={(e) => setProfile({ ...profile, contact_person: e.target.value })}
                      placeholder={t('settings.contactPersonPlaceholder')}
                    />
                  </div>
                )}

                {showCompanyName && (
                  <div className="space-y-2">
                    <Label htmlFor="account-company_name">{t('settings.companyName')}</Label>
                    <Input
                      id="account-company_name"
                      name="account-company_name"
                      value={profile.company_name}
                      onChange={(e) => setProfile({ ...profile, company_name: e.target.value })}
                      placeholder={t('settings.companyNamePlaceholder')}
                    />
                  </div>
                )}
              </div>
            )}

            {showEmail && (
              <div className="space-y-2">
                <Label htmlFor="account-email">{t('settings.email')}</Label>
                <Input
                  id="account-email"
                  name="account-email"
                  value={userEmail}
                  disabled
                  className="bg-muted cursor-not-allowed"
                />
              </div>
            )}

            {showBusinessType && (
              <div className="space-y-2">
                <Label htmlFor="account-business_type">{t('settings.businessType')}</Label>
                <Select
                  value={profile.business_type}
                  onValueChange={(value) => setProfile({ ...profile, business_type: value })}
                >
                  <SelectTrigger>
                    <SelectValue placeholder={t('settings.selectBusinessType')} />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="consulting">{t('settings.consulting')}</SelectItem>
                    <SelectItem value="ecommerce">{t('settings.ecommerce')}</SelectItem>
                    <SelectItem value="agency">{t('settings.agency')}</SelectItem>
                    <SelectItem value="saas">{t('settings.saas')}</SelectItem>
                    <SelectItem value="other">{t('settings.other')}</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            )}

            {showBusinessContext && (
              <div className="space-y-2">
                <Label htmlFor="account-business_context">{t('settings.businessContext')}</Label>
                <Textarea
                  id="account-business_context"
                  name="account-business_context"
                  value={profile.business_context}
                  onChange={(e) => setProfile({ ...profile, business_context: e.target.value })}
                  placeholder={t('settings.businessContextPlaceholder')}
                  className="min-h-[100px]"
                />
              </div>
            )}

            {hasVisibleFields && (
              <Button onClick={handleSave} disabled={saving} className="w-full sm:w-auto">
                {saving ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    {t('common.saving')}
                  </>
                ) : (
                  t('common.saveChanges')
                )}
              </Button>
            )}
          </div>
        </Card>
      )}

      <ProfileAvatarUpload
        open={showAvatarUpload}
        onOpenChange={setShowAvatarUpload}
        currentAvatarUrl={profile.avatar_url}
        onAvatarUpdated={() => {
          refreshProfile();
          setShowAvatarUpload(false);
        }}
        userId={userId}
        accessToken={accessToken}
      />

      <Card className="p-6 bg-card/50 backdrop-blur-xl border-border/50">
        <h2 className="text-xl font-semibold mb-6">{t('settings.security')}</h2>
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="space-y-0.5">
              <p className="font-medium">{t('settings.changePassword')}</p>
              <p className="text-sm text-muted-foreground">
                {t('settings.changePasswordDesc')}
              </p>
            </div>
            <Button
              variant="outline"
              className="gap-2"
              onClick={async () => {
                try {
                  setChangingPassword(true);
                  if (!userEmail) throw new Error('No email found');
                  localStorage.setItem('password_reset_email', userEmail.trim().toLowerCase());
                  const { error } = await supabase.auth.resetPasswordForEmail(userEmail, {
                    redirectTo: `${window.location.origin}/reset-password`,
                  });
                  if (error) throw error;
                  toast({
                    title: t('common.success'),
                    description: t('settings.passwordResetSent'),
                  });
                } catch (error) {
                  console.error('Error sending password reset:', error);
                  toast({
                    title: t('common.error'),
                    description: 'Failed to send password reset email',
                    variant: 'destructive',
                  });
                } finally {
                  setChangingPassword(false);
                }
              }}
              disabled={changingPassword}
            >
              {changingPassword ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  {t('common.sending')}
                </>
              ) : (
                <>
                  <Key className="h-4 w-4" />
                  {t('settings.changePassword')}
                </>
              )}
            </Button>
          </div>
        </div>
      </Card>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Badge } from '@/components/ui/badge';
import { 
  AlertDialog, 
  AlertDialogAction, 
  AlertDialogCancel, 
  AlertDialogContent, 
  AlertDialogDescription, 
  AlertDialogFooter, 
  AlertDialogHeader, 
  AlertDialogTitle, 
  AlertDialogTrigger 
} from '@/components/ui/alert-dialog';
import { 
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/integrations/supabase/client';
import { 
  Brain, 
  Trash2, 
  Eye, 
  Loader2, 
  User, 
  Settings2, 
  FolderOpen,
  Clock,
  AlertTriangle
} from 'lucide-react';

interface Memory {
  id: string;
  memory_type: string;
  memory_key: string;
  memory_data: Record<string, any> | null;
  created_at: string | null;
  expires_at: string | null;
  priority: number | null;
}

interface MemoryManagementProps {
  userId: string;
}

const memoryTypeIcons: Record<string, React.ReactNode> = {
  profile: <User className="w-4 h-4" />,
  preference: <Settings2 className="w-4 h-4" />,
  project: <FolderOpen className="w-4 h-4" />,
  conversation: <Clock className="w-4 h-4" />,
};

const memoryTypeColors: Record<string, string> = {
  profile: 'bg-blue-500/10 text-blue-500 border-blue-500/20',
  preference: 'bg-purple-500/10 text-purple-500 border-purple-500/20',
  project: 'bg-green-500/10 text-green-500 border-green-500/20',
  conversation: 'bg-orange-500/10 text-orange-500 border-orange-500/20',
};

export const MemoryManagement: React.FC<MemoryManagementProps> = ({ userId }) => {
  const { toast } = useToast();
  const [memories, setMemories] = useState<Memory[]>([]);
  const [loading, setLoading] = useState(false);
  const [isViewerOpen, setIsViewerOpen] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [clearingAll, setClearingAll] = useState(false);

  const fetchMemories = useCallback(async () => {
    if (!userId) return;

    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('user_memory')
        .select('*')
        .eq('user_id', userId)
        .order('priority', { ascending: true })
        .order('created_at', { ascending: false });

      if (error) throw error;
      setMemories((data || []).map(d => ({
        ...d,
        memory_data: typeof d.memory_data === 'object' && d.memory_data !== null ? d.memory_data as Record<string, any> : {}
      })));
    } catch (error) {
      console.error('Error fetching memories:', error);
      toast({
        title: 'Error',
        description: 'Failed to load memories',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  }, [userId, toast]);

  useEffect(() => {
    if (isViewerOpen) {
      fetchMemories();
    }
  }, [isViewerOpen, userId, fetchMemories]);

  const handleDeleteMemory = async (memoryId: string) => {
    setDeletingId(memoryId);
    try {
      const { error } = await supabase
        .from('user_memory')
        .delete()
        .eq('id', memoryId)
        .eq('user_id', userId);

      if (error) throw error;

      setMemories(prev => prev.filter(m => m.id !== memoryId));
      toast({
        title: 'Memory Deleted',
        description: 'AYN will no longer remember this.',
      });
    } catch (error) {
      console.error('Error deleting memory:', error);
      toast({
        title: 'Error',
        description: 'Failed to delete memory',
        variant: 'destructive',
      });
    } finally {
      setDeletingId(null);
    }
  };

  const handleClearAllMemories = async () => {
    setClearingAll(true);
    try {
      const { error } = await supabase
        .from('user_memory')
        .delete()
        .eq('user_id', userId);

      if (error) throw error;

      setMemories([]);
      toast({
        title: 'All Memories Cleared',
        description: 'AYN has forgotten everything about you.',
      });
      setIsViewerOpen(false);
    } catch (error) {
      console.error('Error clearing memories:', error);
      toast({
        title: 'Error',
        description: 'Failed to clear memories',
        variant: 'destructive',
      });
    } finally {
      setClearingAll(false);
    }
  };

  const groupedMemories = memories.reduce((acc, memory) => {
    const type = memory.memory_type;
    if (!acc[type]) acc[type] = [];
    acc[type].push(memory);
    return acc;
  }, {} as Record<string, Memory[]>);

  // Format memory data for display in a human-readable way
  const formatMemoryDisplay = (memory: Memory): string => {
    if (!memory.memory_data) return 'No data';

    const data = memory.memory_data;

    // Simple value field
    if (data.value && typeof data.value === 'string') return data.value;

    // Project memory with title
    if (data.title) {
      let summary = String(data.title);

      // Add key specs if available
      if (data.keySpecs && typeof data.keySpecs === 'object') {
        const specs = data.keySpecs as Record<string, unknown>;
        const parts: string[] = [];

        if (specs.siteArea) parts.push(String(specs.siteArea));
        if (specs.totalSpaces) parts.push(`${specs.totalSpaces} spaces`);
        if (specs.efficiency) parts.push(`${specs.efficiency} efficiency`);
        if (specs.evSpaces) parts.push(`${specs.evSpaces} EV`);

        if (parts.length > 0) {
          summary += ` (${parts.slice(0, 3).join(', ')})`;
        }
      }

      return summary;
    }

    // Engineering calculation with type
    if (data.type && typeof data.type === 'string') {
      const type = data.type.charAt(0).toUpperCase() + data.type.slice(1);
      if (data.savedAt) {
        return `${type} design saved`;
      }
      return `${type} data`;
    }

    // Fallback: show first few meaningful fields
    const keys = Object.keys(data).filter(k => 
      !['id', 'created_at', 'updated_at', 'user_id'].includes(k)
    ).slice(0, 2);

    if (keys.length === 0) return 'Stored data';

    return keys.map(k => {
      const val = data[k];
      const strVal = typeof val === 'object' ? JSON.stringify(val).substring(0, 20) : String(val).substring(0, 30);
      return `${k.replace(/_/g, ' ')}: ${strVal}`;
    }).join(', ');
  };

  return (
    <Card className="p-6 bg-card/50 backdrop-blur-xl border-border/50">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 rounded-xl bg-gradient-to-br from-primary/20 to-accent/20">
          <Brain className="w-5 h-5 text-primary" />
        </div>
        <div>
          <h2 className="text-xl font-semibold">AYN Memory</h2>
          <p className="text-sm text-muted-foreground">
            Control what AYN remembers about you
          </p>
        </div>
      </div>

      <div className="space-y-4">
        {/* View Memories Button */}
        <div className="flex items-center justify-between">
          <div className="space-y-0.5">
            <Label className="text-sm font-medium">View My Memories</Label>
            <p className="text-sm text-muted-foreground">
              See what AYN remembers about you
            </p>
          </div>
          <Button 
            variant="outline" 
            onClick={() => setIsViewerOpen(true)}
            className="gap-2"
          >
            <Eye className="w-4 h-4" />
            View ({memories.length || '...'})
          </Button>
        </div>

        {/* Clear All Memories */}
        <div className="flex items-center justify-between pt-4 border-t border-border">
          <div className="space-y-0.5">
            <Label className="text-sm font-medium text-destructive">Clear All Memories</Label>
            <p className="text-sm text-muted-foreground">
              Make AYN forget everything about you
            </p>
          </div>
          <AlertDialog>
            <AlertDialogTrigger asChild>
              <Button variant="destructive" className="gap-2">
                <Trash2 className="w-4 h-4" />
                Clear All
              </Button>
            </AlertDialogTrigger>
            <AlertDialogContent>
              <AlertDialogHeader>
                <AlertDialogTitle className="flex items-center gap-2">
                  <AlertTriangle className="w-5 h-5 text-destructive" />
                  Clear All Memories?
                </AlertDialogTitle>
                <AlertDialogDescription>
                  This will permanently delete all memories AYN has about you, including 
                  your name, preferences, and project history. This cannot be undone.
                </AlertDialogDescription>
              </AlertDialogHeader>
              <AlertDialogFooter>
                <AlertDialogCancel>Cancel</AlertDialogCancel>
                <AlertDialogAction
                  onClick={handleClearAllMemories}
                  className="bg-destructive text-destructive-foreground"
                  disabled={clearingAll}
                >
                  {clearingAll ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Clearing...
                    </>
                  ) : (
                    'Clear All Memories'
                  )}
                </AlertDialogAction>
              </AlertDialogFooter>
            </AlertDialogContent>
          </AlertDialog>
        </div>
      </div>

      {/* Memory Viewer Dialog */}
      <Dialog open={isViewerOpen} onOpenChange={setIsViewerOpen}>
        <DialogContent className="max-w-2xl max-h-[80vh]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Brain className="w-5 h-5 text-primary" />
              What AYN Remembers
            </DialogTitle>
          </DialogHeader>

          {loading ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
            </div>
          ) : memories.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              <Brain className="w-12 h-12 mx-auto mb-4 opacity-30" />
              <p>AYN hasn't learned anything about you yet.</p>
              <p className="text-sm mt-1">Start chatting and AYN will remember helpful details!</p>
            </div>
          ) : (
            <ScrollArea className="h-[50vh] pr-4">
              <div className="space-y-6">
                {Object.entries(groupedMemories).map(([type, typeMemories]) => (
                  <div key={type}>
                    <div className="flex items-center gap-2 mb-3">
                      {memoryTypeIcons[type] || <Brain className="w-4 h-4" />}
                      <h3 className="font-medium capitalize">{type}</h3>
                      <Badge variant="secondary" className="text-xs">
                        {typeMemories.length}
                      </Badge>
                    </div>
                    <div className="space-y-2">
                      <AnimatePresence>
                        {typeMemories.map((memory) => (
                          <motion.div
                            key={memory.id}
                            initial={{ opacity: 0, y: -10 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, x: -20 }}
                            className={`p-3 rounded-lg border ${memoryTypeColors[type] || 'bg-muted/30 border-border'}`}
                          >
                            <div className="flex items-start justify-between gap-3">
                              <div className="flex-1 min-w-0">
                                <p className="font-medium text-sm capitalize">
                                  {memory.memory_key.replace(/_/g, ' ')}
                                </p>
                                <p className="text-sm text-muted-foreground mt-1 break-words">
                                  {formatMemoryDisplay(memory)}
                                </p>
                                <p className="text-xs text-muted-foreground mt-2">
                                  Learned {memory.created_at ? new Date(memory.created_at).toLocaleDateString() : 'Unknown'}
                                </p>
                              </div>
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-8 w-8 shrink-0 text-muted-foreground hover:text-destructive"
                                onClick={() => handleDeleteMemory(memory.id)}
                                disabled={deletingId === memory.id}
                              >
                                {deletingId === memory.id ? (
                                  <Loader2 className="w-4 h-4 animate-spin" />
                                ) : (
                                  <Trash2 className="w-4 h-4" />
                                )}
                              </Button>
                            </div>
                          </motion.div>
                        ))}
                      </AnimatePresence>
                    </div>
                  </div>
                ))}
              </div>
            </ScrollArea>
          )}
        </DialogContent>
      </Dialog>
    </Card>
  );
};

export default MemoryManagement;

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Brain, RefreshCw } from 'lucide-react';

interface Props {
  children: ReactNode;
  fallback?: ReactNode;
}

interface State {
  hasError: boolean;
  error?: Error;
}

export class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false
  };

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('ErrorBoundary caught an error:', error, errorInfo);

    // Non-blocking error report to Supabase
    this.reportError(error, errorInfo).catch(() => {});

    // Auto-reload on dynamic import failures (stale chunk errors)
    const message = error?.message || '';
    const shouldReload =
      message.includes('Failed to fetch dynamically imported module') ||
      message.includes('Component is not a function');

    // Prevent infinite refresh loops
    if (shouldReload) {
      const key = message.includes('Component is not a function')
        ? 'ayn_auto_reload_component_not_function'
        : 'ayn_auto_reload_stale_chunk';

      try {
        if (!sessionStorage.getItem(key)) {
          sessionStorage.setItem(key, '1');
          window.location.reload();
        }
      } catch {
        // If sessionStorage is unavailable, still attempt a single reload.
        window.location.reload();
      }
    }
  }

  private async reportError(error: Error, errorInfo: ErrorInfo) {
    try {
      const { supabase } = await import('@/integrations/supabase/client');
      const { data: { session } } = await supabase.auth.getSession();

      await (supabase as any).from('error_logs').insert({
        error_message: (error.message || 'Unknown error').slice(0, 1000),
        error_stack: error.stack?.slice(0, 5000) || null,
        component_stack: errorInfo.componentStack?.slice(0, 5000) || null,
        url: window.location.href,
        user_id: session?.user?.id || null,
        user_agent: navigator.userAgent,
      });
    } catch {
      // Silent failure — error reporting should never break the app
    }
  }

  public render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback;
      }

      const isDev = import.meta.env.DEV;
      const message = this.state.error?.message || '';
      const isAutoReloadError =
        message.includes('Failed to fetch dynamically imported module') ||
        message.includes('Component is not a function');

      return (
        <Card className="border-primary/20 bg-gradient-to-br from-primary/5 to-primary/10">
          <CardHeader>
            <CardTitle className="flex items-center gap-3 text-foreground">
              <div className="p-2 rounded-full bg-primary/10">
                <Brain className="w-5 h-5 text-primary" />
              </div>
              Oops! AYN hit a snag
            </CardTitle>
            <CardDescription className="text-muted-foreground">
              Something unexpected happened, but don't worry - we've got this. Let's get you back on track.
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {isDev && this.state.error && (
                <div className="text-xs text-muted-foreground bg-muted/50 p-3 rounded font-mono">
                  {this.state.error.message}
                </div>
              )}
              <Button 
                onClick={() => {
                  if (isAutoReloadError) {
                    window.location.reload();
                    return;
                  }
                  this.setState({ hasError: false, error: undefined });
                }}
                variant="default"
                size="sm"
                className="gap-2"
              >
                <RefreshCw className="w-4 h-4" />
                {isAutoReloadError ? 'Reload Page' : "Let's Try Again"}
              </Button>
            </div>
          </CardContent>
        </Card>
      );
    }

    return this.props.children;
  }
}

import { useState, useEffect, useCallback, useMemo } from 'react';
import { toast } from 'sonner';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeHighlight from 'rehype-highlight';
import 'highlight.js/styles/github-dark.min.css';
import { cn } from '@/lib/utils';
import { sanitizeUserInput, isValidUserInput } from '@/lib/security';
import { Copy, Check, AlertCircle, Loader2, Download } from 'lucide-react';
import {
  Dialog,
  DialogContent,
} from '@/components/ui/dialog';
import { persistDalleImage } from '@/hooks/useImagePersistence';
import { isDocumentStorageUrl, isSupabaseStorageUrl, openDocumentUrl } from '@/lib/documentUrlUtils';

interface MessageFormatterProps {
  content: string;
  className?: string;
}

// Detect if content is predominantly Arabic/RTL text
const hasArabicText = (text: string): boolean => {
  // Strip markdown syntax, URLs, code blocks for cleaner detection
  const cleaned = text
    .replace(/```[\s\S]*?```/g, '')
    .replace(/`[^`]+`/g, '')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .replace(/https?:\/\/\S+/g, '')
    .replace(/[^a-zA-Z\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF\uFB50-\uFDFF\uFE70-\uFEFF]/g, '');

  const arabicChars = (cleaned.match(/[\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF\uFB50-\uFDFF\uFE70-\uFEFF]/g) || []).length;
  const latinChars = (cleaned.match(/[a-zA-Z]/g) || []).length;

  // Only RTL if Arabic characters are the majority (>60%)
  const total = arabicChars + latinChars;
  return total > 0 && (arabicChars / total) > 0.6;
};

// Remove outer code fence wrapping if entire content is a single code block
const unwrapCodeFences = (text: string): string => {
  if (!text) return '';

  const trimmed = text.trim();

  // Check if entire content is wrapped in a single code block
  // Pattern: ```optionalLanguage\ncontent\n```
  const codeBlockMatch = trimmed.match(/^```[\w]*\n?([\s\S]*?)\n?```$/);

  if (codeBlockMatch) {
    // Return the content inside the code fences
    return codeBlockMatch[1].trim();
  }

  return text;
};

// Detect JSON responses with image URLs and convert to markdown image syntax
// Also strips raw LLM action/tool-call JSON that leaked through
const detectImageJsonResponse = (text: string): string => {
  if (!text) return text;

  const trimmed = text.trim();

  // Check if content looks like JSON with image URL or raw action payload
  if (trimmed.startsWith('{') && trimmed.endsWith('}')) {
    try {
      const parsed = JSON.parse(trimmed);

      // Strip raw LLM action/tool-call JSON (e.g. { action: "dalle.text2im", action_input: "..." })
      if (parsed.action && parsed.action_input) {
        // Extract the prompt from the action_input for a friendly message
        let prompt = '';
        try {
          const actionData = typeof parsed.action_input === 'string' 
            ? JSON.parse(parsed.action_input) 
            : parsed.action_input;
          prompt = actionData?.prompt || '';
        } catch { /* ignore */ }
        const thought = parsed.thought || '';
        const friendlyMsg = prompt 
          ? `🎨 generating image: *${prompt.substring(0, 120)}${prompt.length > 120 ? '...' : ''}*`
          : (thought || 'processing your request...');
        return friendlyMsg;
      }

      // Check for common image response patterns (from n8n, DALL-E, etc.)
      if (parsed.url && typeof parsed.url === 'string') {
        const url = parsed.url;
        const isImageUrl = url.includes('.png') || 
                          url.includes('.jpg') || 
                          url.includes('.jpeg') || 
                          url.includes('.gif') || 
                          url.includes('.webp') ||
                          url.includes('image') || 
                          url.includes('blob.core.windows.net') ||
                          url.includes('oaidalleapiprodscus');

        if (isImageUrl) {
          const caption = parsed.revised_prompt || parsed.description || parsed.prompt || 'Generated Image';
          return `![${caption}](${url})\n\n**${caption}**`;
        }
      }
    } catch {
      // Not valid JSON, return original
    }
  }

  // Also handle raw JSON embedded within other text
  const actionJsonMatch = trimmed.match(/\{\s*"action"\s*:\s*"[^"]*"\s*,\s*"action_input"\s*:/);
  if (actionJsonMatch) {
    // Strip the raw JSON and keep only non-JSON text around it
    const cleaned = trimmed.replace(/\{[^{}]*"action"\s*:\s*"[^"]*"[^{}]*(?:\{[^{}]*\}[^{}]*)?\}/g, '').trim();
    return cleaned || 'processing your request...';
  }

  return text;
};

// Decode HTML entities safely without using innerHTML (prevents XSS)
const decodeHtmlEntities = (text: string): string => {
  if (!text) return '';

  // Map of common HTML entities to their decoded values
  const htmlEntities: Record<string, string> = {
    '&quot;': '"',
    '&#34;': '"',
    '&#x22;': '"',
    '&apos;': "'",
    '&#39;': "'",
    '&#x27;': "'",
    '&lt;': '<',
    '&#60;': '<',
    '&#x3C;': '<',
    '&gt;': '>',
    '&#62;': '>',
    '&#x3E;': '>',
    '&amp;': '&',
    '&#38;': '&',
    '&#x26;': '&',
    '&#x2F;': '/',
    '&#47;': '/',
    '&nbsp;': ' ',
    '&#160;': ' ',
    '&#xa0;': ' ',
    '&ndash;': '–',
    '&#8211;': '–',
    '&mdash;': '—',
    '&#8212;': '—',
    '&lsquo;': '\u2018',
    '&rsquo;': '\u2019',
    '&ldquo;': '\u201C',
    '&rdquo;': '\u201D',
    '&hellip;': '…',
    '&copy;': '©',
    '&reg;': '®',
    '&trade;': '™',
  };

  let decoded = text;

  // Replace all known named entities
  for (const [entity, char] of Object.entries(htmlEntities)) {
    decoded = decoded.split(entity).join(char);
  }

  // Handle remaining numeric entities (decimal: &#123; or hex: &#x7B;)
  decoded = decoded.replace(/&#(\d+);/g, (_, dec) => 
    String.fromCharCode(parseInt(dec, 10))
  );
  decoded = decoded.replace(/&#x([0-9a-fA-F]+);/g, (_, hex) => 
    String.fromCharCode(parseInt(hex, 16))
  );

  return decoded;
};

export function MessageFormatter({ content, className }: MessageFormatterProps) {
  const [lightboxImage, setLightboxImage] = useState<{ src: string; alt: string } | null>(null);
  const [copiedCodeId, setCopiedCodeId] = useState<string | null>(null);
  const [persistedUrls, setPersistedUrls] = useState<Map<string, string>>(new Map());
  const [savingImages, setSavingImages] = useState<Set<string>>(new Set());
  const [failedImages, setFailedImages] = useState<Set<string>>(new Set());

  const normalizeImageUrl = useCallback((url: string) => {
    return (url || '').trim().replace(/^['"]+|['"]+$/g, '');
  }, []);

  // Auto-persist DALL-E images when content changes
  useEffect(() => {
    const dalleUrlRegex = /https:\/\/oaidalleapiprodscus\.blob\.core\.windows\.net[^\s)]+/g;
    const matches = content.match(dalleUrlRegex);

    if (matches) {
      matches.forEach(async (rawUrl) => {
        const url = normalizeImageUrl(rawUrl);
        if (!url) return;
        if (persistedUrls.has(url) || savingImages.has(url)) return;

        setSavingImages(prev => new Set(prev).add(url));
        try {
          const permanentUrl = await persistDalleImage(url);
          if (permanentUrl !== url) {
            setPersistedUrls(prev => new Map(prev).set(url, permanentUrl));
          }
        } catch {
          setFailedImages(prev => new Set(prev).add(url));
        } finally {
          setSavingImages(prev => {
            const next = new Set(prev);
            next.delete(url);
            return next;
          });
        }
      });
    }
  }, [content, persistedUrls, savingImages, normalizeImageUrl]);

  // Helper to get the best URL for an image
  const getImageUrl = useCallback((originalUrl: string) => {
    const clean = normalizeImageUrl(originalUrl);
    return persistedUrls.get(clean) || clean;
  }, [persistedUrls, normalizeImageUrl]);

  // Step 1: Detect and convert JSON image responses to markdown
  const imageProcessedContent = detectImageJsonResponse(content);

  // Step 2: Unwrap outer code fences (if entire content is wrapped)
  const unwrappedContent = unwrapCodeFences(imageProcessedContent);

  // Step 3: Decode HTML entities
  const decodedContent = decodeHtmlEntities(unwrappedContent);

  // Step 4: Strip inline document download links (users use the Download button instead)
  const strippedContent = decodedContent
    // Remove lines like: 📄 [Click here to download...](url) or 📊 [Download ...](url)
    .replace(/^[\s]*[📄📊📥]\s*\[[^\]]*\]\((?:https?:\/\/[^\s)]+|data:[^\s)]+)\)\s*$/gm, '')
    // Remove lines like: [Download filename.xlsx](url) or [Click here to download](url)
    .replace(/^[\s]*\[(?:[Dd]ownload[^\]]*|[Cc]lick here[^\]]*|[Cc]liquez ici[^\]]*|اضغط[^\]]*|تحميل[^\]]*)\]\((?:https?:\/\/[^\s)]+|data:[^\s)]+)\)\s*$/gm, '')
    // Clean up resulting empty lines
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  // Step 5: Sanitize content to prevent XSS attacks
  const sanitizedContent = isValidUserInput(strippedContent) ? strippedContent : sanitizeUserInput(strippedContent);

  const copyCodeToClipboard = async (code: string) => {
    try {
      await navigator.clipboard.writeText(code);
      setCopiedCodeId(code);
      setTimeout(() => setCopiedCodeId(null), 2000);
    } catch (err) {
      console.error('Failed to copy code:', err);
    }
  };

  // Preprocess to convert inline tables, numbered/bullet lists to proper newlines
  const preprocessContent = (text: string): string => {
    let processed = text;

    // Normalize curly/smart quotes to straight quotes for markdown compatibility
    processed = processed
      .replace(/[\u2018\u2019]/g, "'")  // Single curly quotes → straight
      .replace(/[\u201C\u201D]/g, '"'); // Double curly quotes → straight

    // Check if content contains a markdown table (has pipes and separator row)
    const isTable = processed.includes('|') && /\|[\s-:]+\|/.test(processed);

    // For tables: just normalize excessive newlines, don't modify structure
    if (isTable) {
      processed = processed.replace(/\n{3,}/g, '\n\n');
      return processed;
    }

    // Only apply list conversion for NON-table content
    // 1. Convert inline numbered lists like "1. item 2. item 3. item"
    if (processed.match(/\d+\.\s[^0-9]+\d+\.\s/)) {
      processed = processed.replace(/(\s)(\d+)\.\s/g, '\n$2. ').trim();
    }

    // 2. Convert inline bullet lists like "text: - **Item** - **Item**"
    if (processed.match(/[^-\n]\s+-\s+(\*\*|[A-Z])/)) {
      processed = processed.replace(/(\S)\s+-\s+(\*\*|[A-Z])/g, '$1\n- $2');
    }

    // 3. Convert inline bullets with em-dash "text – item – item"
    if (processed.match(/[^\n]\s+[–—]\s+\*\*/)) {
      processed = processed.replace(/(\S)\s+[–—]\s+(\*\*)/g, '$1\n- $2');
    }

    return processed;
  };

  const processedContent = preprocessContent(sanitizedContent);

  // Detect RTL for Arabic content
  const isRTL = useMemo(() => hasArabicText(processedContent), [processedContent]);

  return (
    <>
       <div 
        className={cn("space-y-4 leading-relaxed break-words max-w-none", className)}
        dir={isRTL ? 'rtl' : 'ltr'}
        style={{ 
          fontFamily: isRTL ? "'Noto Sans Arabic', 'Segoe UI', system-ui, sans-serif" : undefined,
          textAlign: isRTL ? 'right' : undefined,
        }}
      >
        <ReactMarkdown
          remarkPlugins={[remarkGfm]}
          rehypePlugins={[rehypeHighlight]}
          components={{
            // Bold text
            strong: ({ children }) => (
              <strong className="font-semibold text-foreground">{children}</strong>
            ),
            // Italic text
            em: ({ children }) => (
              <em className="italic text-muted-foreground">{children}</em>
            ),
            // Strikethrough (GFM)
            del: ({ children }) => (
              <del className="line-through text-muted-foreground">{children}</del>
            ),
            // Unordered lists with styled bullets
            ul: ({ children }) => (
              <ul className="space-y-2 my-3 first:mt-0 last:mb-0 ps-1 list-none">{children}</ul>
            ),
            // Ordered lists with styled markers
            ol: ({ children }) => (
              <ol className="space-y-2 my-3 first:mt-0 last:mb-0 ps-5 list-decimal list-outside marker:text-primary/60 marker:font-medium">{children}</ol>
            ),
            // List items with custom bullet styling
            li: ({ children }) => (
              <li className="relative ps-5 leading-relaxed pb-0.5 break-words [overflow-wrap:anywhere] [&>p]:inline [&>p]:m-0 before:content-['•'] before:absolute before:start-0 before:text-primary/60 before:font-bold before:text-base [ol>&]:before:content-none [ol>&]:ps-0">{children}</li>
            ),
            // Paragraphs
            p: ({ children }) => (
              <p className="leading-[1.75] mb-3 last:mb-0 text-current break-words">{children}</p>
            ),
            // Code blocks with language label and copy button
            code: ({ children, className: codeClassName }) => {
              const isBlock = codeClassName?.includes('language-');
              const codeString = String(children).replace(/\n$/, '');
              const language = codeClassName?.replace('language-', '') || '';

              if (isBlock) {
                return (
                  <div className="relative group my-4 first:mt-0 last:mb-0 max-w-full overflow-hidden rounded-xl border border-border">
                    {/* Language label + copy button header */}
                    <div className="flex items-center justify-between px-4 py-2 bg-muted/80 border-b border-border">
                      <span className="text-xs font-mono text-muted-foreground uppercase tracking-wider">
                        {language || 'code'}
                      </span>
                      <button
                        onClick={() => copyCodeToClipboard(codeString)}
                        className={cn(
                          "flex items-center gap-1.5 px-2 py-1 rounded-md text-xs",
                          "text-muted-foreground hover:text-foreground hover:bg-muted",
                          "transition-colors"
                        )}
                        title="Copy code"
                      >
                        {copiedCodeId === codeString ? (
                          <>
                            <Check size={13} className="text-green-500" />
                            <span className="text-green-500">Copied</span>
                          </>
                        ) : (
                          <>
                            <Copy size={13} />
                            <span>Copy</span>
                          </>
                        )}
                      </button>
                    </div>
                    <pre className="bg-muted/40 p-4 overflow-x-auto max-w-full w-full">
                      <code className="text-[13px] font-mono text-foreground/90 whitespace-pre leading-relaxed">
                        {children}
                      </code>
                    </pre>
                  </div>
                );
              }
              return (
                <code className="bg-muted/70 text-foreground px-1.5 py-0.5 rounded-md text-[13px] font-mono border border-border/50">
                  {children}
                </code>
              );
            },
            // Pre blocks - let code component handle rendering
            pre: ({ children }) => <>{children}</>,
            // Headers
            h1: ({ children }) => (
              <h1 className="text-xl font-bold mt-6 mb-3 first:mt-0 text-foreground tracking-tight">{children}</h1>
            ),
            h2: ({ children }) => (
              <h2 className="text-lg font-semibold mt-6 mb-2.5 first:mt-0 text-foreground tracking-tight">{children}</h2>
            ),
            h3: ({ children }) => (
              <h3 className="text-base font-semibold mt-5 mb-2 first:mt-0 text-foreground">{children}</h3>
            ),
            h4: ({ children }) => (
              <h4 className="text-sm font-semibold mt-4 mb-1.5 first:mt-0 text-foreground">{children}</h4>
            ),
            // Blockquotes
            blockquote: ({ children }) => (
              <blockquote className="border-l-[3px] border-primary/40 bg-muted/30 ps-4 py-2.5 my-4 first:mt-0 last:mb-0 rounded-e-lg text-muted-foreground [&>p]:mb-1 [&>p:last-child]:mb-0">
                {children}
              </blockquote>
            ),
            // Tables
            table: ({ children }) => (
              <div className="my-4 first:mt-0 last:mb-0 rounded-xl border border-border overflow-hidden">
                <div className="overflow-x-auto">
                  <table className="min-w-full border-collapse text-sm">
                    {children}
                  </table>
                </div>
              </div>
            ),
            thead: ({ children }) => (
              <thead className="bg-muted/60">{children}</thead>
            ),
            tbody: ({ children }) => (
              <tbody className="divide-y divide-border/60">{children}</tbody>
            ),
            tr: ({ children }) => (
              <tr className="even:bg-muted/20 hover:bg-muted/40 transition-colors">{children}</tr>
            ),
            th: ({ children }) => (
              <th className="px-4 py-2.5 text-left font-semibold text-xs uppercase tracking-wider text-foreground whitespace-nowrap border-b border-border">
                {children}
              </th>
            ),
            td: ({ children }) => (
              <td className="px-4 py-2.5 text-sm text-foreground/80 break-words">
                {children}
              </td>
            ),
            // Horizontal rule
            hr: () => (
              <hr className="my-5 border-border" />
            ),
            // Links - route document storage URLs through proxy for reliable downloads
            a: ({ children, href }) => {
              const isDataURL = href?.startsWith('data:');
              const isDocUrl = isDocumentStorageUrl(href || '');
              const isSupabaseUrl = isSupabaseStorageUrl(href || '');
              const isSandboxUrl = href?.startsWith('sandbox:') || href?.includes('/mnt/data/');
              const isDownloadable = isDataURL || isDocUrl || isSupabaseUrl;

              const handleClick = (e: React.MouseEvent) => {
                e.preventDefault();
                e.stopPropagation();
                console.log('[MessageFormatter] Link clicked:', href?.substring(0, 80));
                // Intercept hallucinated sandbox URLs
                if (isSandboxUrl) {
                  toast.error('File not available. Try asking again to generate the document.');
                  return;
                }
                if (isDownloadable && href) {
                  const urlFilename = href.split('/').pop()?.split('?')[0] || 'download';
                  console.log('[MessageFormatter] Downloading:', urlFilename);
                  openDocumentUrl(href, urlFilename).catch(err => {
                    console.error('[MessageFormatter] Download failed:', err);
                    toast.error('Download failed. Please try the Download button below.');
                  });
                  return;
                }
                // Regular external link - open in new tab
                if (href) {
                  window.open(href, '_blank', 'noopener,noreferrer');
                }
              };

              // Use <span> instead of <button> to avoid invalid nesting inside <p>
              return (
                <span
                  role="link"
                  tabIndex={0}
                  onClick={handleClick}
                  onKeyDown={(e) => e.key === 'Enter' && handleClick(e as any)}
                  className="inline text-primary underline underline-offset-2 hover:text-primary/80 transition-colors cursor-pointer"
                >
                  {children}
                </span>
              );
            },
            // Images with click-to-zoom and persistence
            img: ({ src, alt }) => {
              const rawSrc = src || '';
              const cleanSrc = normalizeImageUrl(rawSrc);
              const displaySrc = getImageUrl(cleanSrc);
              const isDalleUrl = cleanSrc.includes('oaidalleapiprodscus.blob.core.windows.net');
              const isSaving = savingImages.has(cleanSrc);
              const hasFailed = failedImages.has(cleanSrc);
              const isSupabase = isSupabaseStorageUrl(cleanSrc);

              const handleImageError = async (e: React.SyntheticEvent<HTMLImageElement>) => {
                const imgEl = e.currentTarget;
                // Avoid infinite loop: only retry once via blob
                if (imgEl.dataset.blobRetried) return;
                imgEl.dataset.blobRetried = 'true';

                try {
                  const response = await fetch(cleanSrc);
                  if (!response.ok) throw new Error('fetch failed');
                  const blob = await response.blob();
                  const blobUrl = URL.createObjectURL(blob);
                  imgEl.src = blobUrl;
                } catch {
                  if (isDalleUrl && !hasFailed) {
                    setFailedImages(prev => new Set(prev).add(cleanSrc));
                  }
                }
              };

              return (
                <div className="relative my-2">
                  <img 
                    src={displaySrc} 
                    alt={alt || ''} 
                    loading="lazy"
                    className="max-w-full h-auto rounded-lg cursor-zoom-in hover:opacity-90 transition-opacity shadow-sm"
                    onClick={() => setLightboxImage({ src: displaySrc, alt: alt || '' })}
                    onError={handleImageError}
                  />
                  {/* Saving indicator */}
                  {isSaving && (
                    <div className="absolute top-2 right-2 flex items-center gap-1 px-2 py-1 rounded-full bg-foreground/70 text-background text-xs">
                      <Loader2 size={12} className="animate-spin" />
                      <span>Saving...</span>
                    </div>
                  )}
                  {/* Failed/Expired indicator */}
                  {hasFailed && displaySrc === cleanSrc && (
                    <div className="absolute inset-0 flex items-center justify-center bg-muted rounded-lg">
                      <div className="text-center p-4">
                        <AlertCircle className="w-8 h-8 text-amber-500 mx-auto mb-2" />
                        <p className="text-sm text-muted-foreground">Image has expired</p>
                        <p className="text-xs text-muted-foreground mt-1">Please regenerate the image</p>
                      </div>
                    </div>
                  )}
                  {/* Download button for supabase images */}
                  {isSupabase && (
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        const filename = cleanSrc.split('/').pop()?.split('?')[0] || 'image.png';
                        openDocumentUrl(cleanSrc, filename);
                      }}
                      className="absolute bottom-2 right-2 flex items-center gap-1 px-2 py-1 rounded-md bg-foreground/70 text-background text-xs hover:bg-foreground/90 transition-colors"
                    >
                      <Download size={12} />
                      <span>Download</span>
                    </button>
                  )}
                </div>
              );
            },
          }}
        >
          {processedContent}
        </ReactMarkdown>
      </div>

      {/* Image Lightbox Dialog */}
      <Dialog open={!!lightboxImage} onOpenChange={() => setLightboxImage(null)}>
        <DialogContent className="max-w-[90vw] max-h-[90vh] p-2 bg-black/95 border-none">
          {lightboxImage && (
            <img
              src={lightboxImage.src}
              alt={lightboxImage.alt}
              className="w-full h-full object-contain max-h-[85vh]"
            />
          )}
        </DialogContent>
      </Dialog>
    </>
  );
}

import { Helmet } from 'react-helmet-async';

interface SEOProps {
  title: string;
  description: string;
  canonical?: string;
  type?: 'website' | 'article' | 'product';
  image?: string;
  noIndex?: boolean;
  jsonLd?: object;
  keywords?: string;
  language?: 'en' | 'ar' | 'fr';
}

const SITE_URL = 'https://aynn.io';
const DEFAULT_IMAGE = 'https://aynn.io/og-image.jpg';

export const SEO = ({
  title,
  description,
  canonical,
  type = 'website',
  image = DEFAULT_IMAGE,
  noIndex = false,
  jsonLd,
  keywords,
  language = 'en',
}: SEOProps) => {
  const fullTitle = title.includes('AYN') ? title : `${title} | AYN`;
  const canonicalUrl = canonical ? `${SITE_URL}${canonical}` : undefined;
  const ogLocale = language === 'ar' ? 'ar_SA' : language === 'fr' ? 'fr_FR' : 'en_US';

  return (
    <Helmet>
      {/* Basic Meta Tags */}
      <title>{fullTitle}</title>
      <meta name="description" content={description} />
      {keywords && <meta name="keywords" content={keywords} />}
      {canonicalUrl && <link rel="canonical" href={canonicalUrl} />}
      {noIndex && <meta name="robots" content="noindex, nofollow" />}

      {/* Open Graph */}
      <meta property="og:title" content={fullTitle} />
      <meta property="og:description" content={description} />
      <meta property="og:type" content={type} />
      <meta property="og:image" content={image} />
      {canonicalUrl && <meta property="og:url" content={canonicalUrl} />}
      <meta property="og:site_name" content="AYN" />
      <meta property="og:locale" content={ogLocale} />
      <meta property="og:locale:alternate" content="en_US" />
      <meta property="og:locale:alternate" content="ar_SA" />
      <meta property="og:locale:alternate" content="fr_FR" />

      {/* Twitter Card */}
      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={fullTitle} />
      <meta name="twitter:description" content={description} />
      <meta name="twitter:image" content={image} />
      <meta name="twitter:site" content="@ayn_ai" />

      {/* JSON-LD Structured Data */}
      {jsonLd && (
        <script type="application/ld+json">
          {JSON.stringify(jsonLd)}
        </script>
      )}
    </Helmet>
  );
};

