// Keywords that trigger excitement/surprise reaction
const EXCITING_KEYWORDS = [
  'amazing', 'incredible', 'perfect', 'excellent', 'brilliant', 'fantastic',
  'wow', 'awesome', 'great', 'success', 'achievement', 'breakthrough',
  'important', 'urgent', 'critical', 'milestone', 'winner', 'congratulations',
  'exciting', 'love', 'best', 'outstanding', 'exceptional', 'remarkable',
  'رائع', 'ممتاز', 'مذهل', 'عظيم', 'مبروك', 'نجاح', 'إنجاز'
];

// Activity level for dynamic particle behavior
export type ActivityLevel = 'idle' | 'low' | 'medium' | 'high';

interface AYNEmotionContextType {
  emotion: AYNEmotion;
  emotionSource: EmotionSource;
  emotionConfig: EmotionConfig;
  setEmotion: (emotion: AYNEmotion) => void;
  setEmotionWithSource: (emotion: AYNEmotion, source: EmotionSource) => void;
  isAbsorbing: boolean;
  triggerAbsorption: () => void;
  isBlinking: boolean;
  triggerBlink: () => void;
  isResponding: boolean;
  setIsResponding: (responding: boolean) => void;
  // New smart life states
  isUserTyping: boolean;
  setIsUserTyping: (typing: boolean) => void;
  isAttentive: boolean;
  setIsAttentive: (attentive: boolean) => void;
  triggerAttentionBlink: () => void;
  lastActivityTime: number;
  updateActivity: () => void;
  // Surprise/excitement reaction
  isSurprised: boolean;
  triggerSurprise: () => void;
  detectExcitement: (text: string) => boolean;
  // Pulse effect for new messages
  isPulsing: boolean;
  triggerPulse: () => void;
  // Wink interaction
  isWinking: boolean;
  triggerWink: () => void;
  // Empathy responses to user emotions
  triggerEmpathyBlink: () => void;
  triggerEmpathyPulse: () => void;
  // Dynamic activity level for particles
  activityLevel: ActivityLevel;
  bumpActivity: () => void;
}

const AYNEmotionContext = createContext<AYNEmotionContextType | undefined>(undefined);

export const AYNEmotionProvider = ({ children }: { children: ReactNode }) => {
  const [emotion, setEmotionState] = useState<AYNEmotion>('calm');
  const [emotionSource, setEmotionSource] = useState<EmotionSource>('default');
  const [isAbsorbing, setIsAbsorbing] = useState(false);
  const [isBlinking, setIsBlinking] = useState(false);
  const [isResponding, setIsResponding] = useState(false);
  const [isUserTyping, setIsUserTyping] = useState(false);
  const [isAttentive, setIsAttentive] = useState(false);
  const [lastActivityTime, setLastActivityTime] = useState(Date.now());
  const [isSurprised, setIsSurprised] = useState(false);
  const [isPulsing, setIsPulsing] = useState(false);
  const [isWinking, setIsWinking] = useState(false);
  const [activityLevel, setActivityLevel] = useState<ActivityLevel>('idle');
  const activityCountRef = useRef(0);
  const activityDecayRef = useRef<NodeJS.Timeout | null>(null);
  const blinkTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const surpriseTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const pulseTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const winkTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Cleanup all timeout refs on unmount to prevent memory leaks
  useEffect(() => {
    return () => {
      if (activityDecayRef.current) clearTimeout(activityDecayRef.current);
      if (blinkTimeoutRef.current) clearTimeout(blinkTimeoutRef.current);
      if (surpriseTimeoutRef.current) clearTimeout(surpriseTimeoutRef.current);
      if (pulseTimeoutRef.current) clearTimeout(pulseTimeoutRef.current);
      if (winkTimeoutRef.current) clearTimeout(winkTimeoutRef.current);
    };
  }, []);

  // Bump activity when messages sent/received or typing
  const bumpActivity = useCallback(() => {
    activityCountRef.current = Math.min(activityCountRef.current + 1, 10);

    // Map activity count to level
    if (activityCountRef.current >= 7) {
      setActivityLevel('high');
    } else if (activityCountRef.current >= 4) {
      setActivityLevel('medium');
    } else if (activityCountRef.current >= 1) {
      setActivityLevel('low');
    }

    // Clear existing decay timer
    if (activityDecayRef.current) {
      clearTimeout(activityDecayRef.current);
    }

    // Start decay - activity decreases over time
    activityDecayRef.current = setTimeout(function decayActivity() {
      activityCountRef.current = Math.max(0, activityCountRef.current - 1);

      if (activityCountRef.current >= 7) {
        setActivityLevel('high');
      } else if (activityCountRef.current >= 4) {
        setActivityLevel('medium');
      } else if (activityCountRef.current >= 1) {
        setActivityLevel('low');
      } else {
        setActivityLevel('idle');
      }

      if (activityCountRef.current > 0) {
        activityDecayRef.current = setTimeout(decayActivity, 3000);
      }
    }, 5000);
  }, []);

  const setEmotionWithSource = useCallback((newEmotion: AYNEmotion, source: EmotionSource) => {
    // ONLY set emotion state - haptic is handled EXCLUSIVELY by useEmotionOrchestrator
    // This prevents duplicate haptic triggers
    setEmotionState(newEmotion);
    setEmotionSource(source);
  }, []);

  const setEmotion = useCallback((newEmotion: AYNEmotion) => {
    // Default to 'response' source for backward compatibility
    setEmotionWithSource(newEmotion, 'response');
  }, [setEmotionWithSource]);

  const triggerAbsorption = useCallback(() => {
    setIsAbsorbing(true);
    hapticFeedback('light'); // Subtle feedback when message absorbed
    setTimeout(() => setIsAbsorbing(false), 300);
  }, []);

  const triggerBlink = useCallback(() => {
    setIsBlinking(true);
    // 180ms gives eye time to fully close (150ms) + brief hold before opening
    setTimeout(() => setIsBlinking(false), 180);
  }, []);

  // Double-blink for attention (when user starts typing)
  const triggerAttentionBlink = useCallback(() => {
    // Clear any existing blink timeout
    if (blinkTimeoutRef.current) {
      clearTimeout(blinkTimeoutRef.current);
    }

    // First blink
    setIsBlinking(true);
    setTimeout(() => {
      setIsBlinking(false);
      // Second blink after short pause
      blinkTimeoutRef.current = setTimeout(() => {
        setIsBlinking(true);
        setTimeout(() => setIsBlinking(false), 100);
      }, 150);
    }, 100);
  }, []);

  const updateActivity = useCallback(() => {
    setLastActivityTime(Date.now());
  }, []);

  // Trigger brief surprise/excitement enlargement
  const triggerSurprise = useCallback(() => {
    if (surpriseTimeoutRef.current) {
      clearTimeout(surpriseTimeoutRef.current);
    }
    setIsSurprised(true);
    hapticFeedback('excited'); // Two quick bursts for excitement
    surpriseTimeoutRef.current = setTimeout(() => {
      setIsSurprised(false);
    }, 600);
  }, []);

  // Detect exciting keywords in text
  const detectExcitement = useCallback((text: string): boolean => {
    const lowerText = text.toLowerCase();
    const hasExcitingKeyword = EXCITING_KEYWORDS.some(keyword => 
      lowerText.includes(keyword.toLowerCase())
    );
    if (hasExcitingKeyword) {
      triggerSurprise();
    }
    return hasExcitingKeyword;
  }, [triggerSurprise]);

  // Trigger pulse effect for new message receive
  const triggerPulse = useCallback(() => {
    if (pulseTimeoutRef.current) {
      clearTimeout(pulseTimeoutRef.current);
    }
    setIsPulsing(true);
    hapticFeedback('pulse'); // Subtle pulse for new message
    pulseTimeoutRef.current = setTimeout(() => {
      setIsPulsing(false);
    }, 400);
  }, []);

  // Empathetic response triggers - AYN responds to USER emotions
  const triggerEmpathyBlink = useCallback(() => {
    // Slow, understanding double-blink for when user is sad/anxious
    triggerBlink();
    setTimeout(() => triggerBlink(), 400);
  }, [triggerBlink]);

  const triggerEmpathyPulse = useCallback(() => {
    // Gentle pulse showing "I understand your feelings"
    hapticFeedback('empathy');
    triggerPulse();
  }, [triggerPulse]);

  // Trigger wink (asymmetric blink)
  const triggerWink = useCallback(() => {
    if (winkTimeoutRef.current) {
      clearTimeout(winkTimeoutRef.current);
    }
    setIsWinking(true);
    winkTimeoutRef.current = setTimeout(() => {
      setIsWinking(false);
    }, 250);
  }, []);

  // Memoize emotionConfig to prevent unnecessary re-renders
  const emotionConfig = useMemo(() => EMOTION_CONFIGS[emotion], [emotion]);

  return (
    <AYNEmotionContext.Provider
      value={{
        emotion,
        emotionSource,
        emotionConfig,
        setEmotion,
        setEmotionWithSource,
        isAbsorbing,
        triggerAbsorption,
        isBlinking,
        triggerBlink,
        isResponding,
        setIsResponding,
        isUserTyping,
        setIsUserTyping,
        isAttentive,
        setIsAttentive,
        triggerAttentionBlink,
        lastActivityTime,
        updateActivity,
        isSurprised,
        triggerSurprise,
        detectExcitement,
        isPulsing,
        triggerPulse,
        isWinking,
        triggerWink,
        triggerEmpathyBlink,
        triggerEmpathyPulse,
        activityLevel,
        bumpActivity,
      }}
    >
      {children}
    </AYNEmotionContext.Provider>
  );
};

export const useAYNEmotion = () => {
  const context = useContext(AYNEmotionContext);
  if (!context) {
    throw new Error('useAYNEmotion must be used within an AYNEmotionProvider');
  }
  return context;
};

import React, { createContext, useContext, useCallback, useMemo, useState, ReactNode } from 'react';
import { useActionTracker, TrackedAction } from '@/hooks/useActionTracker';
import { type BuildingCodeId, type NBCCVersion, AVAILABLE_CODES, DEFAULT_BUILDING_CODE, getBuildingCodeConfig } from '@/lib/buildingCodes';
import { type GradingRegion } from '@/lib/gradingStandards';

interface CalculatorState {
  inputs: Record<string, any>;
  outputs: Record<string, any> | null;
  lastCalculatedAt: Date | null;
}

interface EngineeringSessionContextValue {
  // Current state
  currentCalculator: string | null;
  currentInputs: Record<string, any>;
  currentOutputs: Record<string, any> | null;

  // Building code
  buildingCode: BuildingCodeId;
  setBuildingCode: (code: BuildingCodeId) => void;
  nbccVersion: NBCCVersion;
  setNbccVersion: (version: NBCCVersion) => void;

  // Grading region
  gradingRegion: GradingRegion;
  setGradingRegion: (region: GradingRegion) => void;

  // All calculator states
  calculatorStates: Record<string, CalculatorState>;

  // Action history
  recentActions: TrackedAction[];

  // Session info
  sessionSummary: {
    sessionDuration: number;
    totalActions: number;
    actionCounts: Record<string, number>;
    calculatorsUsed: string[];
    calculationsRun: number;
    currentCalculator: string | null;
  };

  // Tracking functions
  trackCalculatorSwitch: (calculator: string) => void;
  trackInputChange: (field: string, value: any) => void;
  trackMultipleInputs: (inputs: Record<string, any>) => void;
  trackCalculation: (outputs: Record<string, any>) => void;
  trackExport: (format: 'pdf' | 'dxf') => void;
  trackSave: (designName: string) => void;
  trackAIInteraction: (message: string, actionsExecuted?: string[]) => void;
  trackReset: () => void;

  // Get context for AI
  getAIContext: () => AIContext;
}

export interface AIContext {
  currentCalculator: string | null;
  currentInputs: Record<string, any>;
  currentOutputs: Record<string, any> | null;
  allCalculatorStates: Record<string, CalculatorState>;
  buildingCode: {
    id: BuildingCodeId;
    name: string;
    fullName: string;
    version: string;
    loadCombinations: Array<{ id: string; formula: string; purpose: string }>;
    resistanceFactors: {
      flexure: number;
      shear: number;
      compressionTied: number;
      compressionSpiral: number;
    };
    codeReferences: { [key: string]: string };
  };
  recentActions: {
    type: string;
    timestamp: string;
    details: Record<string, any>;
    calculator?: string;
  }[];
  sessionInfo: {
    sessionDuration: number;
    calculatorsUsed: string[];
    calculationsRun: number;
  };
}

const EngineeringSessionContext = createContext<EngineeringSessionContextValue | null>(null);

interface EngineeringSessionProviderProps {
  children: ReactNode;
}

export const EngineeringSessionProvider: React.FC<EngineeringSessionProviderProps> = ({ children }) => {
  const actionTracker = useActionTracker();
  const [buildingCode, setBuildingCode] = useState<BuildingCodeId>(DEFAULT_BUILDING_CODE);
  const [nbccVersion, setNbccVersion] = useState<NBCCVersion>('2020');
  const [gradingRegion, setGradingRegion] = useState<GradingRegion>('USA');

  const getCurrentState = useCallback((): CalculatorState | null => {
    return actionTracker.getCurrentCalculatorState();
  }, [actionTracker]);

  const getAIContext = useCallback((): AIContext => {
    const currentState = getCurrentState();
    const summary = actionTracker.getSessionSummary();
    const recentActions = actionTracker.getRecentActions(20);
    const codeConfig = getBuildingCodeConfig(buildingCode);

    return {
      currentCalculator: actionTracker.currentCalculator,
      currentInputs: currentState?.inputs || {},
      currentOutputs: currentState?.outputs || null,
      allCalculatorStates: actionTracker.calculatorStates,
      buildingCode: {
        id: buildingCode,
        name: codeConfig.name,
        fullName: codeConfig.fullName,
        version: codeConfig.version,
        loadCombinations: codeConfig.loadCombinations,
        resistanceFactors: codeConfig.resistanceFactors,
        codeReferences: codeConfig.codeReferences as unknown as { [key: string]: string },
      },
      recentActions: recentActions.map(action => ({
        type: action.type,
        timestamp: action.timestamp.toISOString(),
        details: action.details,
        calculator: action.calculator,
      })),
      sessionInfo: {
        sessionDuration: summary.sessionDuration,
        calculatorsUsed: summary.calculatorsUsed,
        calculationsRun: summary.calculationsRun,
      },
    };
  }, [actionTracker, getCurrentState, buildingCode]);

  const value = useMemo<EngineeringSessionContextValue>(() => {
    const currentState = getCurrentState();

    return {
      // Current state
      currentCalculator: actionTracker.currentCalculator,
      currentInputs: currentState?.inputs || {},
      currentOutputs: currentState?.outputs || null,

      // Building code
      buildingCode,
      setBuildingCode,
      nbccVersion,
      setNbccVersion,

      // Grading region
      gradingRegion,
      setGradingRegion,

      // All calculator states
      calculatorStates: actionTracker.calculatorStates,

      // Action history
      recentActions: actionTracker.getRecentActions(20),

      // Session info
      sessionSummary: actionTracker.getSessionSummary(),

      // Tracking functions
      trackCalculatorSwitch: actionTracker.trackCalculatorSwitch,
      trackInputChange: actionTracker.trackInputChange,
      trackMultipleInputs: actionTracker.trackMultipleInputs,
      trackCalculation: actionTracker.trackCalculation,
      trackExport: actionTracker.trackExport,
      trackSave: actionTracker.trackSave,
      trackAIInteraction: actionTracker.trackAIInteraction,
      trackReset: actionTracker.trackReset,

      // AI context
      getAIContext,
    };
  }, [actionTracker, getCurrentState, getAIContext, buildingCode, nbccVersion, gradingRegion]);

  return (
    <EngineeringSessionContext.Provider value={value}>
      {children}
    </EngineeringSessionContext.Provider>
  );
};

export const useEngineeringSession = (): EngineeringSessionContextValue => {
  const context = useContext(EngineeringSessionContext);
  if (!context) {
    throw new Error('useEngineeringSession must be used within EngineeringSessionProvider');
  }
  return context;
};

// Optional hook that returns null if outside provider (for components that may be used both inside and outside)
export const useEngineeringSessionOptional = (): EngineeringSessionContextValue | null => {
  return useContext(EngineeringSessionContext);
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { translations } from '@/i18n';

export type Language = 'en' | 'ar' | 'fr';
export type Direction = 'ltr' | 'rtl';

interface LanguageContextType {
  language: Language;
  direction: Direction;
  setLanguage: (lang: Language) => void;
  t: (key: string) => string;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

interface LanguageProviderProps {
  children: React.ReactNode;
}

export const LanguageProvider: React.FC<LanguageProviderProps> = ({ children }) => {
  const [language, setLanguageState] = useState<Language>('en');
  const direction: Direction = language === 'ar' ? 'rtl' : 'ltr';

  useEffect(() => {
    // Load saved language from localStorage
    const savedLang = localStorage.getItem('ayn-language') as Language;
    if (savedLang && (savedLang === 'en' || savedLang === 'ar' || savedLang === 'fr')) {
      setLanguageState(savedLang);
    }
  }, []);

  useEffect(() => {
    // Update document direction and language for public pages (Landing, Services, Pricing)
    // Dashboard overrides this with its own dir="ltr" container
    document.documentElement.lang = language;
    // Direction is applied per-page via dir={direction}, not globally,
    // to prevent dashboard portals (modals, toasts, dropdowns) from breaking
  }, [language, direction]);

  const setLanguage = (lang: Language) => {
    setLanguageState(lang);
    localStorage.setItem('ayn-language', lang);
  };

  const t = (key: string): string => {
    return translations[language]?.[key] || key;
  };

  return (
    <LanguageContext.Provider value={{ language, direction, setLanguage, t }}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (context === undefined) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useCallback } from 'react';

interface SettingsContextType {
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  hasUnsavedChanges: boolean;
  setHasUnsavedChanges: (hasChanges: boolean) => void;
  registerFormChange: (formId: string, hasChanges: boolean) => void;
}

const SettingsContext = createContext<SettingsContextType | undefined>(undefined);

export const SettingsProvider = ({ children }: { children: React.ReactNode }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [formStates, setFormStates] = useState<Record<string, boolean>>({});

  const registerFormChange = useCallback((formId: string, hasChanges: boolean) => {
    setFormStates(prev => ({ ...prev, [formId]: hasChanges }));
  }, []);

  const hasUnsavedChanges = Object.values(formStates).some(state => state);

  return (
    <SettingsContext.Provider
      value={{
        searchTerm,
        setSearchTerm,
        hasUnsavedChanges,
        setHasUnsavedChanges: (hasChanges: boolean) => {
          if (!hasChanges) {
            setFormStates({});
          }
        },
        registerFormChange,
      }}
    >
      {children}
    </SettingsContext.Provider>
  );
};

export const useSettingsContext = () => {
  const context = useContext(SettingsContext);
  if (!context) {
    throw new Error('useSettingsContext must be used within SettingsProvider');
  }
  return context;
};

