    it('should return null and show toast on error', async () => {
      const file = new File(['content'], 'test.pdf', { type: 'application/pdf' });

      mockSupabase._mocks.auth.getSession.mockResolvedValueOnce({
        data: { session: { expires_at: Math.floor(Date.now() / 1000) + 3600 } },
        error: null,
      });

      mockSupabase._mocks.invoke.mockResolvedValueOnce({
        data: null,
        error: { message: 'Upload failed' },
      });

      const { result } = renderHook(() => useFileUpload('test-user-id'));

      let attachment;
      await act(async () => {
        attachment = await result.current.uploadFile(file);
      });

      expect(attachment).toBeNull();
      expect(mockToast).toHaveBeenCalledWith(
        expect.objectContaining({
          variant: 'destructive',
        })
      );
    });

    it('should set isUploading state during upload', async () => {
      const file = new File(['content'], 'test.pdf', { type: 'application/pdf' });

      mockSupabase._mocks.auth.getSession.mockResolvedValueOnce({
        data: { session: { expires_at: Math.floor(Date.now() / 1000) + 3600 } },
        error: null,
      });

      mockSupabase._mocks.invoke.mockImplementationOnce(
        () => new Promise(resolve => 
          setTimeout(() => resolve({ data: { url: 'https://example.com/file.pdf' }, error: null }), 100)
        )
      );

      const { result } = renderHook(() => useFileUpload('test-user-id'));

      act(() => {
        result.current.uploadFile(file);
      });

      await waitFor(() => {
        expect(result.current.isUploading).toBe(true);
      });

      await waitFor(() => {
        expect(result.current.isUploading).toBe(false);
      }, 200);
    });
  });

  describe('drag and drop', () => {
    it('should set isDragOver on drag enter', () => {
      const { result } = renderHook(() => useFileUpload('test-user-id'));

      const event = new Event('dragenter') as any;
      event.preventDefault = vi.fn();
      event.stopPropagation = vi.fn();

      act(() => {
        result.current.handleDragEnter(event);
      });

      expect(result.current.isDragOver).toBe(true);
    });

    it('should clear isDragOver on drag leave', () => {
      const { result } = renderHook(() => useFileUpload('test-user-id'));

      const enterEvent = new Event('dragenter') as any;
      enterEvent.preventDefault = vi.fn();
      enterEvent.stopPropagation = vi.fn();

      act(() => {
        result.current.handleDragEnter(enterEvent);
      });

      const leaveEvent = new Event('dragleave') as any;
      leaveEvent.preventDefault = vi.fn();
      leaveEvent.stopPropagation = vi.fn();

      act(() => {
        result.current.handleDragLeave(leaveEvent);
      });

      expect(result.current.isDragOver).toBe(false);
    });

    it('should handle file drop correctly', () => {
      const { result } = renderHook(() => useFileUpload('test-user-id'));

      const file = new File(['content'], 'test.pdf', { type: 'application/pdf' });
      const dropEvent = {
        preventDefault: vi.fn(),
        stopPropagation: vi.fn(),
        dataTransfer: {
          files: [file],
        },
      } as any;

      act(() => {
        result.current.handleDrop(dropEvent);
      });

      expect(result.current.selectedFile).toBe(file);
      expect(result.current.isDragOver).toBe(false);
    });

    it('should reject multiple file drops', () => {
      const { result } = renderHook(() => useFileUpload('test-user-id'));

      const file1 = new File(['content1'], 'test1.pdf', { type: 'application/pdf' });
      const file2 = new File(['content2'], 'test2.pdf', { type: 'application/pdf' });
      const dropEvent = {
        preventDefault: vi.fn(),
        stopPropagation: vi.fn(),
        dataTransfer: {
          files: [file1, file2],
        },
      } as any;

      act(() => {
        result.current.handleDrop(dropEvent);
      });

      expect(mockToast).toHaveBeenCalledWith(
        expect.objectContaining({
          variant: 'destructive',
        })
      );
      expect(result.current.selectedFile).toBeNull();
    });
  });

  describe('file management', () => {
    it('should remove file when removeFile is called', () => {
      const { result } = renderHook(() => useFileUpload('test-user-id'));
      const file = new File(['content'], 'test.pdf', { type: 'application/pdf' });

      act(() => {
        result.current.handleFileSelect(file);
      });

      expect(result.current.selectedFile).toBe(file);

      act(() => {
        result.current.removeFile();
      });

      expect(result.current.selectedFile).toBeNull();
    });
  });
});

import { useState, useCallback, useRef } from 'react';

export interface TrackedAction {
  id: string;
  type: 
    | 'switch_calculator' 
    | 'set_input' 
    | 'set_multiple_inputs' 
    | 'calculate' 
    | 'view_results'
    | 'export_pdf' 
    | 'export_dxf' 
    | 'save_design' 
    | 'view_history' 
    | 'reset_form'
    | 'compare_designs'
    | 'ai_interaction'
    | 'load_calculation';
  timestamp: Date;
  details: Record<string, any>;
  calculator?: string;
}

export interface ActionTrackerState {
  actions: TrackedAction[];
  sessionStart: Date;
  currentCalculator: string | null;
  calculatorStates: Record<string, {
    inputs: Record<string, any>;
    outputs: Record<string, any> | null;
    lastCalculatedAt: Date | null;
  }>;
}

const generateActionId = () => `action_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

export const useActionTracker = () => {
  const [state, setState] = useState<ActionTrackerState>({
    actions: [],
    sessionStart: new Date(),
    currentCalculator: null,
    calculatorStates: {},
  });

  const maxActions = useRef(50); // Keep last 50 actions

  const trackAction = useCallback((
    type: TrackedAction['type'],
    details: Record<string, any> = {},
    calculator?: string
  ) => {
    const action: TrackedAction = {
      id: generateActionId(),
      type,
      timestamp: new Date(),
      details,
      calculator: calculator || state.currentCalculator || undefined,
    };

    setState(prev => ({
      ...prev,
      actions: [...prev.actions.slice(-maxActions.current + 1), action],
    }));

    return action;
  }, [state.currentCalculator]);

  const trackCalculatorSwitch = useCallback((calculator: string) => {
    setState(prev => ({
      ...prev,
      currentCalculator: calculator,
      calculatorStates: {
        ...prev.calculatorStates,
        [calculator]: prev.calculatorStates[calculator] || {
          inputs: {},
          outputs: null,
          lastCalculatedAt: null,
        },
      },
    }));
    trackAction('switch_calculator', { calculator }, calculator);
  }, [trackAction]);

  const trackInputChange = useCallback((field: string, value: any, calculator?: string) => {
    const calc = calculator || state.currentCalculator;
    if (!calc) return;

    setState(prev => ({
      ...prev,
      calculatorStates: {
        ...prev.calculatorStates,
        [calc]: {
          ...prev.calculatorStates[calc],
          inputs: {
            ...(prev.calculatorStates[calc]?.inputs || {}),
            [field]: value,
          },
        },
      },
    }));
    trackAction('set_input', { field, value }, calc);
  }, [state.currentCalculator, trackAction]);

  const trackMultipleInputs = useCallback((inputs: Record<string, any>, calculator?: string) => {
    const calc = calculator || state.currentCalculator;
    if (!calc) return;

    setState(prev => ({
      ...prev,
      calculatorStates: {
        ...prev.calculatorStates,
        [calc]: {
          ...prev.calculatorStates[calc],
          inputs: {
            ...(prev.calculatorStates[calc]?.inputs || {}),
            ...inputs,
          },
        },
      },
    }));
    trackAction('set_multiple_inputs', { inputs, fieldCount: Object.keys(inputs).length }, calc);
  }, [state.currentCalculator, trackAction]);

  const trackCalculation = useCallback((outputs: Record<string, any>, calculator?: string) => {
    const calc = calculator || state.currentCalculator;
    if (!calc) return;

    setState(prev => ({
      ...prev,
      calculatorStates: {
        ...prev.calculatorStates,
        [calc]: {
          ...prev.calculatorStates[calc],
          outputs,
          lastCalculatedAt: new Date(),
        },
      },
    }));
    trackAction('calculate', { outputKeys: Object.keys(outputs) }, calc);
  }, [state.currentCalculator, trackAction]);

  const trackExport = useCallback((format: 'pdf' | 'dxf') => {
    trackAction(format === 'pdf' ? 'export_pdf' : 'export_dxf', { format });
  }, [trackAction]);

  const trackSave = useCallback((designName: string) => {
    trackAction('save_design', { name: designName });
  }, [trackAction]);

  const trackAIInteraction = useCallback((message: string, actionsExecuted?: string[]) => {
    trackAction('ai_interaction', { 
      messagePreview: message.slice(0, 100),
      actionsExecuted: actionsExecuted || [],
    });
  }, [trackAction]);

  const trackReset = useCallback(() => {
    const calc = state.currentCalculator;
    if (!calc) return;

    setState(prev => ({
      ...prev,
      calculatorStates: {
        ...prev.calculatorStates,
        [calc]: {
          inputs: {},
          outputs: null,
          lastCalculatedAt: null,
        },
      },
    }));
    trackAction('reset_form', {});
  }, [state.currentCalculator, trackAction]);

  const getRecentActions = useCallback((count: number = 20) => {
    return state.actions.slice(-count);
  }, [state.actions]);

  const getAllCalculatorStates = useCallback(() => {
    return state.calculatorStates;
  }, [state.calculatorStates]);

  const getCurrentCalculatorState = useCallback(() => {
    if (!state.currentCalculator) return null;
    return state.calculatorStates[state.currentCalculator] || null;
  }, [state.currentCalculator, state.calculatorStates]);

  const getSessionSummary = useCallback(() => {
    const actionCounts = state.actions.reduce((acc, action) => {
      acc[action.type] = (acc[action.type] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    const calculatorsUsed = Object.keys(state.calculatorStates);
    const calculationsRun = state.actions.filter(a => a.type === 'calculate').length;

    return {
      sessionDuration: Math.floor((Date.now() - state.sessionStart.getTime()) / 1000),
      totalActions: state.actions.length,
      actionCounts,
      calculatorsUsed,
      calculationsRun,
      currentCalculator: state.currentCalculator,
    };
  }, [state]);

  return {
    // State
    actions: state.actions,
    currentCalculator: state.currentCalculator,
    calculatorStates: state.calculatorStates,

    // Tracking functions
    trackAction,
    trackCalculatorSwitch,
    trackInputChange,
    trackMultipleInputs,
    trackCalculation,
    trackExport,
    trackSave,
    trackAIInteraction,
    trackReset,

    // Query functions
    getRecentActions,
    getAllCalculatorStates,
    getCurrentCalculatorState,
    getSessionSummary,
  };
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { User, Session } from '@supabase/supabase-js';
import { useToast } from '@/hooks/use-toast';
import { trackDeviceLogin } from '@/hooks/useDeviceTracking';
import type { UserProfile, UseAuthReturn } from '@/types/dashboard.types';

import { supabaseApi } from '@/lib/supabaseApi';

export const useAuth = (user: User, session: Session): UseAuthReturn => {
  const [hasAccess, setHasAccess] = useState(false);
  const [hasAcceptedTerms, setHasAcceptedTerms] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [isDuty, setIsDuty] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [currentMonthUsage, setCurrentMonthUsage] = useState(0);
  const [monthlyLimit, setMonthlyLimit] = useState<number | null>(null);
  const [usageResetDate, setUsageResetDate] = useState<string | null>(null);
  const { toast } = useToast();

  const hasTrackedDevice = useRef(false);

  // Check access — any authenticated user with a subscription row has access.
  // Falls back to access_grants for backward compatibility.
  const checkAccess = useCallback(async () => {
    try {
      // Primary: check user_subscriptions — all registered users have a row here
      const subData = await supabaseApi.get<any[]>(
        `user_subscriptions?user_id=eq.${user.id}&select=subscription_tier,status`,
        session.access_token
      );

      if (subData && subData.length > 0) {
        // Any user with a subscription row has access — free, paid, or unlimited
        setHasAccess(true);
        return;
      }

      // Fallback: legacy access_grants table
      const data = await supabaseApi.get<any[]>(
        `access_grants?user_id=eq.${user.id}&select=is_active,expires_at,current_month_usage,monthly_limit,usage_reset_date`,
        session.access_token
      );

      if (!data || data.length === 0) {
        // No row in either table but user is authenticated — still give access
        setHasAccess(true);
        return;
      }

      const record = data[0];
      const isActive = record.is_active && (!record.expires_at || new Date(record.expires_at) > new Date());
      setHasAccess(isActive);
      setCurrentMonthUsage(record.current_month_usage ?? 0);
      setMonthlyLimit(record.monthly_limit ?? null);
      setUsageResetDate(record.usage_reset_date ?? null);
    } catch {
      // On any error, give access — better to show card than hide it
      setHasAccess(true);
    }
  }, [user.id, session.access_token]);

  // Check if user is admin or duty - uses direct fetch
  const checkAdminRole = useCallback(async () => {
    try {
      const data = await supabaseApi.get<any[]>(
        `user_roles?user_id=eq.${user.id}&select=role`,
        session.access_token
      );

      const role = data?.[0]?.role;
      setIsAdmin(role === 'admin');
      setIsDuty(role === 'duty');
    } catch {
      // Silent failure - non-admin by default
    }
  }, [user.id, session.access_token]);

  // Load user profile - uses direct fetch
  const loadUserProfile = useCallback(async () => {
    try {
      const data = await supabaseApi.get<any[]>(
        `profiles?user_id=eq.${user.id}&select=user_id,contact_person,company_name,business_type,avatar_url`,
        session.access_token
      );

      if (data && data.length > 0) {
        setUserProfile(data[0] as UserProfile);
      }
    } catch {
      // Silent failure - no profile
    }
  }, [user.id, session.access_token]);

  // Accept terms and conditions
  const acceptTerms = useCallback(async (consent: { privacy: boolean; terms: boolean; aiDisclaimer: boolean }) => {
    try {
      const now = new Date().toISOString();

      const updated = await supabaseApi.fetch<any[]>(
        `user_settings?user_id=eq.${user.id}`,
        session.access_token,
        {
          method: 'PATCH',
          body: { has_accepted_terms: true, updated_at: now },
          headers: { 'Prefer': 'return=representation' }
        }
      );

      if (!updated || updated.length === 0) {
        await supabaseApi.post(
          'user_settings',
          session.access_token,
          { user_id: user.id, has_accepted_terms: true, updated_at: now }
        );
      }

      await supabaseApi.post(
        'terms_consent_log',
        session.access_token,
        {
          user_id: user.id,
          terms_version: '2026-03-14',
          privacy_accepted: consent.privacy,
          terms_accepted: consent.terms,
          ai_disclaimer_accepted: consent.aiDisclaimer,
          user_agent: navigator.userAgent
        }
      );

      setHasAcceptedTerms(true);
      localStorage.setItem(`terms_accepted_${user.id}`, 'true');

      toast({
        title: 'Welcome to AYN',
        description: 'Your AI companion is ready to assist you.'
      });
    } catch (error) {
      if (import.meta.env.DEV) {
        console.error('Failed to save terms acceptance:', error);
      }
      toast({
        title: 'Error',
        description: 'Could not save your acceptance. Please try again.',
        variant: 'destructive',
      });
    }
  }, [user.id, session.access_token, toast]);

  // Load all auth data on mount
  useEffect(() => {
    if (!user?.id || !session?.access_token) {
      setIsAuthLoading(false);
      return;
    }

    let isMounted = true;
    let hasRun = false;

    const runQueries = async () => {
      if (hasRun) return;
      hasRun = true;

      try {
        const results = await Promise.all([
          // Primary access check: user_subscriptions
          supabaseApi.getWithRetry<any[]>(`user_subscriptions?user_id=eq.${user.id}&select=subscription_tier,status`, session.access_token),
          supabaseApi.getWithRetry<any[]>(`user_roles?user_id=eq.${user.id}&select=role`, session.access_token),
          supabaseApi.getWithRetry<any[]>(`profiles?user_id=eq.${user.id}&select=user_id,contact_person,company_name,business_type,avatar_url`, session.access_token),
          supabaseApi.getWithRetry<any[]>(`user_settings?user_id=eq.${user.id}&select=has_accepted_terms`, session.access_token)
        ]);

        if (!isMounted) return;

        const [subData, roleData, profileData, settingsData] = results;

        // Access: any authenticated user with a subscription row has access
        if (subData && subData.length > 0) {
          setHasAccess(true);
        } else {
          // Fallback to access_grants for legacy users
          try {
            const accessData = await supabaseApi.get<any[]>(
              `access_grants?user_id=eq.${user.id}&select=is_active,expires_at,current_month_usage,monthly_limit,usage_reset_date`,
              session.access_token
            );
            if (accessData && accessData.length > 0) {
              const record = accessData[0];
              const isActive = record.is_active &&
                (!record.expires_at || new Date(record.expires_at) > new Date());
              setHasAccess(isActive);
              setCurrentMonthUsage(record.current_month_usage ?? 0);
              setMonthlyLimit(record.monthly_limit ?? null);
              setUsageResetDate(record.usage_reset_date ?? null);
            } else {
              // Authenticated but no rows anywhere — give access
              setHasAccess(true);
            }
          } catch {
            setHasAccess(true);
          }
        }

        // Admin/duty role
        if (roleData) {
          const role = roleData?.[0]?.role;
          setIsAdmin(role === 'admin');
          setIsDuty(role === 'duty');
        }

        // Profile
        if (profileData && profileData.length > 0) {
          setUserProfile(profileData[0] as UserProfile);
        }

        // Terms
        if (settingsData) {
          const dbTermsAccepted = settingsData?.[0]?.has_accepted_terms ?? false;
          setHasAcceptedTerms(dbTermsAccepted);
          if (dbTermsAccepted) {
            localStorage.setItem(`terms_accepted_${user.id}`, 'true');
          } else {
            localStorage.removeItem(`terms_accepted_${user.id}`);
          }
        } else {
          const localTermsAccepted = localStorage.getItem(`terms_accepted_${user.id}`) === 'true';
          setHasAcceptedTerms(localTermsAccepted);
        }

      } catch (error) {
        if (import.meta.env.DEV) {
          console.error('Auth queries batch failed:', error);
        }
      } finally {
        if (isMounted) {
          setIsAuthLoading(false);
        }
      }
    };

    runQueries();

    if (!hasTrackedDevice.current) {
      hasTrackedDevice.current = true;
      setTimeout(() => trackDeviceLogin(user.id, session.access_token), 0);
    }

    return () => {
      isMounted = false;
    };
  }, [user?.id, session?.access_token]);

  return {
    hasAccess,
    hasAcceptedTerms,
    isAdmin,
    isDuty,
    hasDutyAccess: isAdmin || isDuty,
    isAuthLoading,
    userProfile,
    currentMonthUsage,
    monthlyLimit,
    usageResetDate,
    checkAccess,
    checkAdminRole,
    loadUserProfile,
    acceptTerms
  };
};

import { useState, useRef, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { API_ENDPOINTS } from '@/constants/apiEndpoints';
import type { ChartAnalysisResult, ChartAnalyzerStep } from '@/types/chartAnalyzer.types';

export function useChartAnalyzer() {
  const [step, setStep] = useState<ChartAnalyzerStep>('idle');
  const [result, setResult] = useState<ChartAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const analyzeChart = useCallback(async (file: File) => {
    setError(null);
    setResult(null);

    // Preview
    const preview = URL.createObjectURL(file);
    setPreviewUrl(preview);

    try {
      setStep('uploading');
      const base64 = await fileToBase64(file);

      setStep('analyzing');
      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.access_token) throw new Error('Please log in to use Chart Analyzer');

      const res = await supabase.functions.invoke(API_ENDPOINTS.ANALYZE_TRADING_CHART, {
        body: { imageBase64: base64, sessionId: null },
      });

      if (res.error) {
        // supabase.functions.invoke may put the parsed body in res.data even on error
        const bodyError = res.data?.error;
        // Also try to parse from the error context
        let contextError: string | undefined;
        try {
          const ctx = (res.error as any)?.context;
          if (ctx instanceof Response) {
            const body = await ctx.json();
            contextError = body?.error;
          }
        } catch {}
        throw new Error(bodyError || contextError || res.error.message || 'Analysis failed');
      }

      setResult(res.data as ChartAnalysisResult);
      setStep('done');
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Analysis failed';
      setError(msg);
      setStep('error');
    }
  }, []);

  const reset = useCallback(() => {
    setStep('idle');
    setResult(null);
    setError(null);
    if (previewUrl) URL.revokeObjectURL(previewUrl);
    setPreviewUrl(null);
  }, [previewUrl]);

  return { step, result, error, previewUrl, fileInputRef, analyzeChart, reset };
}

import { useState, useCallback, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import type { ChartHistoryItem, ChartHistoryFilter, ChartAnalysisResult } from '@/types/chartAnalyzer.types';

const PAGE_SIZE = 10;

function mapRowToHistoryItem(row: any): ChartHistoryItem {
  const prediction = (row.prediction_details || {}) as any;
  const technical = (row.technical_analysis || {}) as any;
  const news = (row.news_data || []) as any[];

  const result: ChartAnalysisResult = {
    ticker: row.ticker || 'N/A',
    assetType: row.asset_type || 'stock',
    timeframe: row.timeframe || 'unknown',
    technical: {
      trend: technical.trend || 'unknown',
      patterns: technical.patterns || [],
      support: technical.support || [],
      resistance: technical.resistance || [],
      indicators: technical.indicators || {},
      keyObservations: technical.keyObservations || '',
    },
    news: news.map((n: any) => ({
      title: n.title || '',
      url: n.url || '#',
      description: n.description || '',
      sentiment: n.sentiment || 0,
      impact: n.impact || 'low',
    })),
    prediction: {
      signal: row.prediction_signal || 'NEUTRAL',
      confidence: row.confidence || 0,
      timeframe: row.timeframe || 'unknown',
      assetType: row.asset_type || 'stock',
      reasoning: prediction.reasoning || '',
      entry_zone: prediction.entry_zone || 'N/A',
      stop_loss: prediction.stop_loss || 'N/A',
      take_profit: prediction.take_profit || 'N/A',
      risk_reward: prediction.risk_reward || 'N/A',
      overallSentiment: row.sentiment_score || 0,
    },
    imageUrl: row.image_url || '',
    analysisId: row.id,
    disclaimer: 'This is AI-generated analysis for educational purposes only. Not financial advice.',
  };

  return {
    ...result,
    id: row.id,
    created_at: row.created_at,
  };
}

export function useChartHistory() {
  const [items, setItems] = useState<ChartHistoryItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const [filter, setFilter] = useState<ChartHistoryFilter>({});
  const [selectedItem, setSelectedItem] = useState<ChartHistoryItem | null>(null);

  const fetchHistory = useCallback(async (offset = 0, append = false) => {
    setLoading(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.user) return;

      let query = supabase
        .from('chart_analyses')
        .select('*')
        .eq('user_id', session.user.id)
        .order('created_at', { ascending: false })
        .range(offset, offset + PAGE_SIZE - 1);

      if (filter.ticker) {
        query = query.ilike('ticker', `%${filter.ticker}%`);
      }
      if (filter.assetType) {
        query = query.eq('asset_type', filter.assetType);
      }
      if (filter.signal) {
        query = query.eq('prediction_signal', filter.signal);
      }

      const { data, error } = await query;
      if (error) throw error;

      const mapped = (data || []).map(mapRowToHistoryItem);
      setHasMore(mapped.length === PAGE_SIZE);

      if (append) {
        setItems(prev => [...prev, ...mapped]);
      } else {
        setItems(mapped);
      }
    } catch (err) {
      console.error('Failed to fetch chart history:', err);
    } finally {
      setLoading(false);
    }
  }, [filter]);

  const loadMore = useCallback(() => {
    if (!loading && hasMore) {
      fetchHistory(items.length, true);
    }
  }, [fetchHistory, items.length, loading, hasMore]);

  const deleteItem = useCallback(async (id: string) => {
    try {
      const { error } = await supabase.from('chart_analyses').delete().eq('id', id);
      if (error) throw error;
      setItems(prev => prev.filter(item => item.id !== id));
      if (selectedItem?.id === id) setSelectedItem(null);
    } catch (err) {
      console.error('Failed to delete analysis:', err);
    }
  }, [selectedItem]);

  useEffect(() => {
    fetchHistory(0, false);
  }, [fetchHistory]);

  return {
    items,
    loading,
    hasMore,
    filter,
    setFilter,
    loadMore,
    deleteItem,
    selectedItem,
    setSelectedItem,
    refresh: () => fetchHistory(0, false),
  };
}

import { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { getHandlingMessage, RATE_LIMIT_MESSAGE } from '@/lib/errorMessages';

export interface AIAction {
  tool: string;
  args: Record<string, any>;
  id: string;
  status: 'pending' | 'executing' | 'done' | 'error';
  result?: any;
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
  actions?: AIAction[];
  id?: string; // Database ID for persistence
}

interface UseEngineeringAIAgentProps {
  calculatorType: string | null;
  currentInputs: Record<string, any>;
  currentOutputs: Record<string, any> | null;
  onSetInput: (field: string, value: any) => void;
  onSetMultipleInputs: (inputs: Record<string, any>) => void;
  onCalculate: () => void;
  onSwitchCalculator: (type: string) => void;
  onReset: () => void;
  onShowHistory: () => void;
  onSaveDesign?: (name: string, notes?: string) => Promise<void>;
  onExportFile?: (format: 'dxf' | 'pdf') => void;
  onCompareDesigns?: (alternativeInputs: Record<string, any>) => void;
  sessionId?: string; // Optional: link to main chat session
}

// Get or create engineering session ID
const getEngineeringSessionId = (): string => {
  const key = 'engineering_session_id';
  let sessionId = sessionStorage.getItem(key);
  if (!sessionId) {
    sessionId = crypto.randomUUID();
    sessionStorage.setItem(key, sessionId);
  }
  return sessionId;
};

export const useEngineeringAIAgent = ({
  calculatorType,
  currentInputs,
  currentOutputs,
  onSetInput,
  onSetMultipleInputs,
  onCalculate,
  onSwitchCalculator,
  onReset,
  onShowHistory,
  onSaveDesign,
  onExportFile,
  onCompareDesigns,
  sessionId: externalSessionId,
}: UseEngineeringAIAgentProps) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [currentAction, setCurrentAction] = useState<string | null>(null);
  const [userId, setUserId] = useState<string | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const messageSequenceRef = useRef(0);

  // Use external session ID or generate one for engineering
  const engineeringSessionId = useMemo(() => {
    return externalSessionId || getEngineeringSessionId();
  }, [externalSessionId]);

  // Get current user
  useEffect(() => {
    const getUser = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      setUserId(user?.id || null);
    };
    getUser();
  }, []);

  // Load previous engineering messages from database
  useEffect(() => {
    const loadPreviousMessages = async () => {
      if (!userId) return;

      try {
        const { data, error } = await supabase
          .from('messages')
          .select('*')
          .eq('session_id', engineeringSessionId)
          .eq('mode_used', 'engineering')
          .order('created_at', { ascending: true });

        if (error) {
          if (import.meta.env.DEV) {
            console.error('Error loading engineering messages:', error);
          }
          return;
        }

        if (data && data.length > 0) {
          setMessages(data.map(m => ({
            id: m.id,
            role: m.sender === 'user' ? 'user' : 'assistant' as const,
            content: m.content,
            timestamp: new Date(m.created_at),
          })));
        }
      } catch (err) {
        if (import.meta.env.DEV) {
          console.error('Failed to load engineering messages:', err);
        }
      }
    };

    loadPreviousMessages();
  }, [userId, engineeringSessionId]);

  // Save message to database
  const saveMessageToDb = useCallback(async (
    content: string, 
    sender: 'user' | 'ayn'
  ): Promise<string | null> => {
    if (!userId) return null;

    try {
      const { data, error } = await supabase
        .from('messages')
        .insert({
          user_id: userId,
          content,
          sender,
          session_id: engineeringSessionId,
          mode_used: 'engineering'
        })
        .select('id')
        .single();

      if (error) {
        if (import.meta.env.DEV) {
          console.error('Error saving message:', error);
        }
        return null;
      }

      return data?.id || null;
    } catch (err) {
      if (import.meta.env.DEV) {
        console.error('Failed to save message:', err);
      }
      return null;
    }
  }, [userId, engineeringSessionId]);

  // Execute a single AI action
  const executeAction = useCallback(async (action: AIAction): Promise<any> => {
    setCurrentAction(`Executing: ${action.tool}`);

    try {
      switch (action.tool) {
        case 'set_input':
          onSetInput(action.args.field, action.args.value);
          return { success: true, field: action.args.field, value: action.args.value };

        case 'set_multiple_inputs':
          onSetMultipleInputs(action.args.inputs);
          return { success: true, inputs: action.args.inputs };

        case 'calculate':
          onCalculate();
          return { success: true, message: 'Calculation triggered' };

        case 'switch_calculator':
          onSwitchCalculator(action.args.calculator);
          return { success: true, calculator: action.args.calculator };

        case 'save_design':
          if (onSaveDesign) {
            await onSaveDesign(action.args.name, action.args.notes);
            toast.success(`Design saved as "${action.args.name}"`);
            return { success: true, name: action.args.name };
          }
          return { success: false, message: 'Save not available' };

        case 'export_file':
          if (onExportFile) {
            onExportFile(action.args.format);
            return { success: true, format: action.args.format };
          }
          return { success: false, message: 'Export not available' };

        case 'compare_designs':
          if (onCompareDesigns) {
            onCompareDesigns(action.args.alternative_inputs);
            return { success: true };
          }
          return { success: false, message: 'Compare not available' };

        case 'reset_form':
          onReset();
          return { success: true, message: 'Form reset' };

        case 'show_history':
          onShowHistory();
          return { success: true, message: 'History opened' };

        default:
          if (import.meta.env.DEV) {
            console.warn('Unknown action:', action.tool);
          }
          return { success: false, message: `Unknown action: ${action.tool}` };
      }
    } catch (err) {
      if (import.meta.env.DEV) {
        console.error('Action execution error:', err);
      }
      return { success: false, error: err instanceof Error ? err.message : 'Unknown error' };
    }
  }, [onSetInput, onSetMultipleInputs, onCalculate, onSwitchCalculator, onReset, onShowHistory, onSaveDesign, onExportFile, onCompareDesigns]);

  // Execute all actions from AI response
  const executeActions = useCallback(async (actions: AIAction[]): Promise<AIAction[]> => {
    const results: AIAction[] = [];

    for (const action of actions) {
      const executingAction: AIAction = { ...action, status: 'executing' };

      const result = await executeAction(action);

      const completedAction: AIAction = {
        ...action,
        status: result.success ? 'done' : 'error',
        result
      };
      results.push(completedAction);

      // Small delay between actions for UI feedback
      await new Promise(resolve => setTimeout(resolve, 100));
    }

    setCurrentAction(null);
    return results;
  }, [executeAction]);

  // Send a message to the AI agent
  const sendMessage = useCallback(async (question: string) => {
    if (!question.trim() || isLoading) return;

    // Cancel any ongoing request
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    abortControllerRef.current = new AbortController();

    // Increment sequence for guaranteed ordering
    const userSequence = ++messageSequenceRef.current;

    const userMessage: ChatMessage = {
      role: 'user',
      content: question.trim(),
      timestamp: new Date(),
      id: `user-${userSequence}`,
    };

    // Add user message FIRST
    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    // Small delay to ensure React commits user message to DOM before AI response
    await new Promise(resolve => setTimeout(resolve, 50));

    // Save user message to database (non-blocking)
    saveMessageToDb(question.trim(), 'user');

    try {
      // Get session context if available
      const sessionContext = (window as any).__engineeringSessionContext?.();

      const { data, error } = await supabase.functions.invoke('engineering-ai-agent', {
        body: {
          calculatorType,
          currentInputs,
          currentOutputs,
          question: question.trim(),
          messages: messages.slice(-10).map(m => ({ role: m.role, content: m.content })),
          allCalculatorStates: sessionContext?.allCalculatorStates || {},
          recentActions: sessionContext?.recentActions || [],
          sessionInfo: sessionContext?.sessionInfo || {},
        },
      });

      if (error) throw error;

      // Execute any actions from the AI
      let executedActions: AIAction[] = [];
      if (data.actions && data.actions.length > 0) {
        executedActions = await executeActions(data.actions);
      }

      const assistantContent = data.answer || 'Done! I executed the requested actions.';
      const aiSequence = ++messageSequenceRef.current;
      const assistantMessage: ChatMessage = {
        role: 'assistant',
        content: assistantContent,
        timestamp: new Date(),
        id: `assistant-${aiSequence}`,
        actions: executedActions,
      };

      setMessages(prev => [...prev, assistantMessage]);

      // Save assistant message to database (non-blocking)
      saveMessageToDb(assistantContent, 'ayn');

    } catch (err) {
      if (import.meta.env.DEV) {
        console.error('AI agent error:', err);
      }

      // Use friendly handling message that maintains personality
      const errorContent = err instanceof Error && err.message.includes('rate limit')
        ? RATE_LIMIT_MESSAGE
        : getHandlingMessage();

      const errorMessage: ChatMessage = {
        role: 'assistant',
        content: errorContent,
        timestamp: new Date(),
      };

      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
      setCurrentAction(null);
    }
  }, [calculatorType, currentInputs, currentOutputs, messages, isLoading, executeActions, saveMessageToDb]);

  // Quick command shortcuts
  const executeQuickCommand = useCallback((command: string) => {
    switch (command) {
      case '/calc':
      case '/calculate':
        onCalculate();
        toast.success('Calculation triggered');
        break;
      case '/reset':
        onReset();
        toast.success('Form reset');
        break;
      case '/history':
        onShowHistory();
        break;
      case '/save':
        sendMessage('Save this design');
        break;
      case '/export':
        sendMessage('Export this design as PDF');
        break;
      default:
        return false;
    }
    return true;
  }, [onCalculate, onReset, onShowHistory, sendMessage]);

  // Clear conversation
  const clearConversation = useCallback(() => {
    setMessages([]);
    setCurrentAction(null);
  }, []);

  // Start new engineering session (clears memory)
  const startNewSession = useCallback(() => {
    sessionStorage.removeItem('engineering_session_id');
    setMessages([]);
    setCurrentAction(null);
  }, []);

  return {
    messages,
    isLoading,
    currentAction,
    sendMessage,
    executeQuickCommand,
    clearConversation,
    startNewSession,
    engineeringSessionId,
  };
};

import { useState, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import type { Json } from '@/integrations/supabase/types';
import type { BuildingCodeId } from '@/lib/buildingCodes';

export interface CalculationHistoryItem {
  id: string;
  calculation_type: string;
  inputs: Record<string, any>;
  outputs: Record<string, any>;
  ai_analysis: Record<string, any> | null;
  building_code?: BuildingCodeId;
  created_at: string;
}

export interface EngineeringActivityItem {
  id: string;
  activity_type: string;
  summary: string;
  details: Record<string, any>;
  created_at: string;
}

export const useEngineeringHistory = (userId: string | undefined) => {
  const [calculationHistory, setCalculationHistory] = useState<CalculationHistoryItem[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Fetch calculation history
  const fetchHistory = useCallback(async () => {
    if (!userId) return;

    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('calculation_history')
        .select('*')
        .eq('user_id', userId)
        .order('created_at', { ascending: false })
        .limit(50);

      if (error) throw error;

      setCalculationHistory((data || []).map(item => ({
        ...item,
        inputs: item.inputs as Record<string, any>,
        outputs: item.outputs as Record<string, any>,
        ai_analysis: item.ai_analysis as Record<string, any> | null,
      })));
    } catch (err) {
      if (import.meta.env.DEV) {
        console.error('Error fetching calculation history:', err);
      }
    } finally {
      setIsLoading(false);
    }
  }, [userId]);

  // Log engineering activity (for AYN context)
  const logActivity = useCallback(async (
    activityType: string,
    summary: string,
    details: Record<string, any>
  ) => {
    if (!userId) return;

    try {
      await supabase
        .from('engineering_activity')
        .insert({
          user_id: userId,
          activity_type: activityType,
          summary,
          details: details as Json,
        });
    } catch (err) {
      if (import.meta.env.DEV) {
        console.error('Error logging engineering activity:', err);
      }
    }
  }, [userId]);

  // Save a calculation to history
  const saveCalculation = useCallback(async (
    calculationType: string,
    inputs: Record<string, any>,
    outputs: Record<string, any>,
    aiAnalysis?: Record<string, any>,
    buildingCode?: BuildingCodeId
  ) => {
    if (!userId) return null;

    try {
      // Include building code in inputs for storage
      const enrichedInputs = buildingCode 
        ? { ...inputs, buildingCode } 
        : inputs;

      const { data, error } = await supabase
        .from('calculation_history')
        .insert({
          user_id: userId,
          calculation_type: calculationType,
          inputs: enrichedInputs as Json,
          outputs: outputs as Json,
          ai_analysis: aiAnalysis as Json || null,
        })
        .select()
        .single();

      if (error) throw error;

      // Also log to engineering_activity for AYN context
      await logActivity(
        `${calculationType}_calculation`,
        generateActivitySummary(calculationType, enrichedInputs, outputs),
        { inputs: enrichedInputs, outputs, aiAnalysis, buildingCode }
      );

      return data;
    } catch (err) {
      if (import.meta.env.DEV) {
        console.error('Error saving calculation:', err);
      }
      return null;
    }
  }, [userId, logActivity]);

  // Delete a calculation from history
  const deleteCalculation = useCallback(async (calculationId: string) => {
    if (!userId) return false;

    try {
      const { error } = await supabase
        .from('calculation_history')
        .delete()
        .eq('id', calculationId)
        .eq('user_id', userId);

      if (error) throw error;

      setCalculationHistory(prev => prev.filter(c => c.id !== calculationId));
      return true;
    } catch (err) {
      if (import.meta.env.DEV) {
        console.error('Error deleting calculation:', err);
      }
      return false;
    }
  }, [userId]);

  return {
    calculationHistory,
    isLoading,
    fetchHistory,
    saveCalculation,
    logActivity,
    deleteCalculation,
  };
};

// Helper to generate human-readable summaries
function generateActivitySummary(
  type: string,
  inputs: Record<string, any>,
  outputs: Record<string, any>
): string {
  switch (type) {
    case 'beam':
      return `Beam design: ${inputs.span}m span, ${inputs.deadLoad}+${inputs.liveLoad} kN/m load → ${outputs.beamWidth}x${outputs.totalDepth}mm, ${outputs.mainReinforcementCount}Ø${outputs.mainReinforcementSize} bars`;

    case 'foundation':
      return `Foundation design: ${inputs.columnLoad}kN load → ${outputs.length}x${outputs.width}m, ${outputs.depth}mm depth, ${outputs.concreteVolume?.toFixed(2) || '?'}m³ concrete`;

    case 'column':
      return `Column design: ${inputs.axialLoad}kN, ${inputs.columnWidth}x${inputs.columnDepth}mm → Steel ratio ${((outputs.requiredSteelArea / (inputs.columnWidth * inputs.columnDepth)) * 100).toFixed(2)}%`;

    case 'grading':
      return `Grading design: Cut ${outputs.totalCutVolume?.toLocaleString() || '?'}m³, Fill ${outputs.totalFillVolume?.toLocaleString() || '?'}m³, Net ${outputs.netVolume?.toLocaleString() || '?'}m³`;

    default:
      return `${type} calculation completed`;
  }
}

import { useEffect } from 'react';
import { useDebugStore } from '@/stores/debugStore';

export const useLayoutShiftObserver = () => {
  const isDebugMode = useDebugStore((s) => s.isDebugMode);
  const addLayoutShift = useDebugStore((s) => s.addLayoutShift);

  useEffect(() => {
    if (!isDebugMode || !('PerformanceObserver' in window)) return;

    if (import.meta.env.DEV) {
      console.log('[Layout Shift Observer] Started monitoring');
    }

    const observer = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        // Only log shifts not caused by user input
        if (entry.entryType === 'layout-shift' && !(entry as any).hadRecentInput) {
          addLayoutShift(entry);
        }
      }
    });

    try {
      observer.observe({ type: 'layout-shift', buffered: true });
    } catch (e) {
      if (import.meta.env.DEV) {
        console.warn('[Layout Shift Observer] Not supported in this browser');
      }
    }

    return () => {
      observer.disconnect();
      if (import.meta.env.DEV) {
        console.log('[Layout Shift Observer] Stopped monitoring');
      }
    };
  }, [isDebugMode, addLayoutShift]);
};

