/**
 * Validate a single input value against its rule
 */
export function validateInput(
  value: number | string,
  rule: ValidationRule
): ValidationResult {
  const numValue = typeof value === 'string' ? parseFloat(value) : value;

  // Check if it's a valid number
  if (isNaN(numValue)) {
    return {
      isValid: false,
      error: `${rule.label} must be a valid number`,
    };
  }

  // Check minimum
  if (rule.min !== undefined && numValue < rule.min) {
    return {
      isValid: false,
      error: `${rule.label} must be at least ${rule.min} ${rule.unit}`,
    };
  }

  // Check maximum
  if (rule.max !== undefined && numValue > rule.max) {
    return {
      isValid: false,
      error: `${rule.label} cannot exceed ${rule.max} ${rule.unit}`,
    };
  }

  return { isValid: true };
}

// Alias for backwards compatibility
export const validateField = (value: number, rule: ValidationRule): string | null => {
  const result = validateInput(value, rule);
  return result.isValid ? null : (result.error || 'Invalid value');
};

// Check if errors object has any errors
export const hasErrors = (errors: Record<string, string>): boolean => {
  return Object.keys(errors).length > 0;
};

/**
 * Validate all inputs against their rules
 */
export function validateAllInputs(
  inputs: Record<string, number | string>,
  rules: Record<string, ValidationRule>
): Record<string, string> {
  const errors: Record<string, string> = {};

  for (const [field, rule] of Object.entries(rules)) {
    const value = inputs[field];
    if (value !== undefined && value !== '') {
      const result = validateInput(value, rule);
      if (!result.isValid && result.error) {
        errors[field] = result.error;
      }
    }
  }

  return errors;
}

/**
 * Check if all required fields have values
 */
export function hasRequiredFields(
  inputs: Record<string, any>,
  requiredFields: string[]
): boolean {
  return requiredFields.every(field => {
    const value = inputs[field];
    return value !== undefined && value !== '' && !isNaN(Number(value));
  });
}

import { SUPABASE_URL } from '@/config';

/**
 * Reports Core Web Vitals (TTFB, DCL, Load) to the report-vitals edge function.
 * Only runs in production for 10% of sessions. Non-blocking — failures are silently ignored.
 */
export function initPerformanceMonitoring() {
  if (import.meta.env.DEV) return;
  if (Math.random() > 0.1) return; // 10% sampling

  window.addEventListener('load', () => {
    setTimeout(() => {
      try {
        const nav = performance.getEntriesByType('navigation')[0] as PerformanceNavigationTiming;
        if (!nav) return;
        const metrics = {
          ttfb: Math.round(nav.responseStart - nav.requestStart),
          dcl: Math.round(nav.domContentLoadedEventEnd - nav.startTime),
          load: Math.round(nav.loadEventEnd - nav.startTime),
          url: window.location.pathname,
          connection: (navigator as any).connection?.effectiveType || 'unknown',
        };
        navigator.sendBeacon?.(
          `${SUPABASE_URL}/functions/v1/report-vitals`,
          JSON.stringify(metrics)
        );
      } catch { /* silent */ }
    }, 3000);
  });
}

